-- Reports 2001-2500 of 3671

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('72e2e52e-1fbb-5ae7-9dfa-d76ab4412f24','910e41ce-16bd-50ce-9200-d586b318f60b','2025-11-20 14:14:16','ZARAGOZA B - CD Alfaro (11/10/2025)','Extremo zurdo bajito. Cierta capacidad de desborde, pero poco destacable.','RP',NULL),
  ('1324389b-4d03-5b05-9631-276c3e2a406a','7db83ad2-ff8e-59f5-82c8-a44f5a1eebee','2025-11-20 14:16:52','ZARAGOZA B - CD Alfaro (11/10/2025)','Centrocampista zurdo de primera/segunda altura, para actuar como mediocentro, pivote, o interior cerca de la base. Perfil físico interesante: estatura cercana a 1''85 m y complexión delgada pero fuerte. Buen nivel técnico y mucho criterio con balón para distribuir, casi siempre hacia delante y encontrando soluciones para progresar. También se suelta a menudo y o bien conduce hasta el último tercio o incluso tira algún desmarque profundo en pasillos interiores. En defensa, va bien por arriba y tiene cierta capacidad de duelo y de corte. 

Mayor para la categoría, pero me ha parecido un jugador de un nivel muy alto.','RP','Seguir'),
  ('8a8f953d-3e50-56c5-96b9-9388f3fcb453','30633296-1284-531e-8095-6e6b16ada6cf','2025-11-20 14:21:55','ZARAGOZA B - CD Alfaro (11/10/2025)','Centrocampista diestro de segunda altura, en el partido actuando primero como interior y después como mediapunta. Por condiciones técnicas y nivel de participación, capacidad para intervenir en las tres alturas del centro del campo. Perfil físico medio en cuanto a estatura y complexión física. Técnicamente sobresaliente, tiene un manejo del balón muy bueno para controlar, conducir y pasar con ambas piernas. Es ágil y tiene mucha habilidad para escapar de presiones. Buen gestor de balón y agresivo en metros finales. En defensa es voluntarioso, aunque no destaca en duelos.','RP','Firmar'),
  ('94d284fe-f6d3-55e7-9b91-1075255185b3','444ab917-8d4b-5445-8230-8a063ee925d4','2025-11-20 14:26:43','ZARAGOZA B - CD Alfaro (11/10/2025)','Atacante diestro de perfil físico medio en cuanto a estatura y complexión física. En el partido ha empezado en banda izquierda y luego ha pasado a la punta, desde donde ha marcado el gol de la victoria de cabeza. Pocas intervenciones, pero parece un jugador ágil y con capacidad técnica.','RP','Seguir'),
  ('99526c8c-0324-58c6-ad10-203e59e70d76','826dc7e0-790c-5e16-81c5-948449bf4b89','2025-11-20 14:52:16',NULL,'Central zurdo de buen perfil físico: es alto, fuerte, velocidad ok sin destacar. Va bien al corte, proactivo para salir de zona, buen defensor de área. Noto que le falta punto más de agresividad para resolver duelos y mayor velocidad para defender profundidad. Con balón tiene rendimiento positivo, jugando hacia adelante y buscando superar líneas de presión.

En mi opinión es central que puede jugar en Segunda en próximas temporadas, sin potencial alto. Creo que es el de menos nivel de los tres centrales.','NB',NULL),
  ('6f750b4d-b1f5-57f5-bff7-8f8a6ae0fcc0','2a821b63-8ef8-5f21-b151-3da6f42d2ef2','2025-11-20 14:54:43',NULL,'Juega de central por dentro, en línea de 3. Muy agresivo para afrontar duelos individuales, fuerte yendo al choque, sólido en acciones defensivas. Juega hacia adelante y es capaz de progresar con balón. Buen perfil físico: fuerte, rápido, ágil.','NB','Seguir'),
  ('bbcf6fee-e7e2-5430-8c70-109f5ccd80ef','5531714e-e08a-5fee-b654-d2ad7bb557c5','2025-11-20 14:56:20',NULL,'Central diestro en línea de tres. Estatura media, bien de velocidad y agilidad, fuerte aunque no sea tan corpulento. Intenso para afrontar duelos, ganador, bien en conceptos defensivos en general. Con balón no destaca, juega hacia adelante aunque sin ser un gran valor en salida, ni por visión de juego ni por pie. Compite bien y es jugador que puede evolucionar. Sin tener nada especial es jugador para subir de nivel/categoría.','NB','Seguir'),
  ('ed306ef5-2a6d-5836-a03a-a2ac5cb8817c','dc38c4a7-384a-50c4-ae81-6fb90d124ca3','2025-11-20 15:48:55','vs Alcorcón','Juega de central zurdo. Buen prototipo físico: ágil, rápido, liviano, de buena estatura. Tiene buena salida de balón, es capaz de progresar en conducción, tiene pase largo. Sólido en acciones defensivas.','NB','Seguir'),
  ('d35940b3-9033-5cce-a905-d1343a0fc95a','ade84026-987a-5a7d-b157-e7251677b07e','2025-11-20 15:51:02','vs Alcorcón','Extremo zurdo por izquierda. Me genera buena impresión por perfil físico, cercano al 1.90, con buen punto de velocidad y agilidad.','NB','Seguir'),
  ('cf083ebc-2163-568b-aa21-bc2adb565662','0ee6ba40-3488-5286-b376-725a4d47a02a','2025-11-20 15:53:53','vs Alcorcón','Delantero centro que entra desde banquillo. Pocos minutos, gran impresión. Físicamente es muy poderoso, tiene zancada larga para conducir, capaz de progresar y generar ocasiones por su cuenta.','NB','Firmar'),
  ('bcc51f2b-3ce7-5745-8e57-25b90a165401','a150c228-67d1-5766-afef-ce5ab1321f5c','2025-11-20 15:54:14','MÁLAGA B - Estepona (12/10/2025)','Lateral derecho de perfil físico medio. No destaca ni en ataque ni en defensa, nivel bajo para mi gusto.','RP',NULL),
  ('ef99c354-8f31-560c-a06d-eb15493c932e','8164f100-c6eb-5782-b8c6-d796c09fb97a','2025-11-20 15:55:25','MÁLAGA B - Estepona (12/10/2025)','Central zurdo con un perfil físico poco interesante para la posición: estatura quizás algo inferior a 1''85 m y complexión normal. No es top defensivamente ni con balón.','RP',NULL),
  ('e492b3c8-6100-5414-bcc0-792567fa6e3c','fd9fb683-b8b9-5478-9891-03edfd80495f','2025-11-20 15:56:27','MÁLAGA B - Estepona (12/10/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior. Físicamente lo veo pesado y no ha dejado ninguna acción destacable.','RP',NULL),
  ('f07c95eb-5400-5d52-8640-ca708e14d916','6aa86854-660e-542d-9a65-ede102b14f90','2025-11-20 15:57:27','MÁLAGA B - Estepona (12/10/2025)','Delantero centro de perfil físico medio: estatura alrededor de 1''80 m y complexión más o menos fuerte. En el partido ha dejado alguna acción con balón y algún movimiento interesante, pero poca cosa.','RP',NULL),
  ('aa30d2ae-a50e-5c91-a6df-4375066ede24','58730643-bf25-5834-b55e-e66cba176c82','2025-11-20 15:58:55','MÁLAGA B - Estepona (12/10/2025)','Centrocampista diestro de primera/segunda altura, aunque con buena llegada a último tercio. Perfil físico medio alto: estatura algo por encima de 1''80 m, complexión atlética y con piernas largas. En el partido ha dejado algunos toques de mucha calidad, pero el equipo es un desastre. Quiero verle alguna vez más para confirmar sensaciones.','RP','Seguir'),
  ('dd2d8aa1-cd0c-5615-80b9-a5020dcf181f','e8da4787-898f-5a5e-af69-71bd11735d56','2025-11-20 16:08:29','MÁLAGA B - Estepona (12/10/2025)','Extremo diestro con un perfil físico medio-bajo en cuanto a estatura y complexión. Parece tener cierta capacidad de desborde, pero no le veo un cambio de ritmo diferencial y en el partido apenas ha generado.','RP',NULL),
  ('870827e5-46de-51da-a8c5-88de70ebc5d5','f14f7895-6ce7-5349-b885-a502e47da05a','2025-11-20 17:21:46','vs Montecarlo','Segundo punta / #10 de estatura cercana al 1.87 m (espigado, con zancada, buen perfil físico en general). No tiene gran impacto en juego, pero es futbolista que por tipología y algunos detalles me hace creer que puede explotar.','NB','Seguir'),
  ('e2b5d0c7-6fba-5391-bd2d-386e0b310e5c','df72df0c-efb7-588f-8ec7-80c42f06ba36','2025-11-20 17:24:46','vs Montecarlo','Mediocentro de buen perfil físico, manejo de balón, capacidad para superar rivales en 1v1 y conducción','NB','Seguir'),
  ('7027dbf8-0706-51d9-9488-d210c37b6be5','98e20e08-0a75-5df1-9d66-2679a6a6a4dd','2025-11-21 11:44:53','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Lateral izquierdo de perfil físico medio en cuanto a estatura y complexión. Buen nivel técnico y presencia en campo rival. Sin ser muy dominador desde lo físico a través de desdoblamientos ni desmarques, siempre mejora la jugada y tiene una buena capacidad de centro al área. En el partido da dos asistencias así. Defensivamente tiene un buen nivel en el 1vs1 por activación y velocidad de reacción ante los movimientos del rival.','RP','Seguir'),
  ('7cbc5060-4733-592a-9a51-9891d9a1aee7','07db410c-c4db-5120-9f0d-11e24b5d75a3','2025-11-21 11:47:22','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Central zurdo con un perfil físico interesante: estatura cercana a 1''85 m y complexión delgada pero fuerte. Técnicamente es sobresaliente y tiene una gran jerarquía tanto en ataque como en defensa. Está mejorando la falta de tensión competitiva que mostraba en cadetes, seguramente por exceso de suficiencia. Central con potencial de élite.','RP','Firmar'),
  ('b7810f0b-593e-507e-ba19-06be8a812a4b','43479982-bcdd-5184-b814-a84af3ab5dba','2025-11-21 11:48:59','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Central diestro con un buen perfil físico: estatura alrededor de 1''85 m y complexión fuerte, aunque algo pesado en carrera y movimientos. Defensivamente es muy contundente y resuelve bien casi todas las acciones por lectura, fortaleza física y técnica defensiva. Con balón no aporta demasiadas ventajas, pero es muy seguro.','RP','Firmar'),
  ('a13b41ba-0308-5a66-8ce4-8b382122c266','7e5d8183-de1a-511c-8b26-373099ba4f01','2025-11-21 11:52:57','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Lateral derecho de perfil físico medio en cuanto a estatura y complexión. Tiene un buen nivel técnico y bastante presencia en campo rival. No es destacable en nada, pero está muy cómodo con balón tanto por fuera como en pasillos interiores.','RP','Seguir'),
  ('e62c1f8b-c1b4-557b-a727-97e29b9a0b1e','95e2b1a4-5d87-5f00-918e-e23a6581a6f5','2025-11-21 11:55:06','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Centrocampista diestro de primera altura, para actuar como mediocentro o en doble pivote. Perfil físico medio-bajo en cuanto a estatura y complexión. Técnicamente muy bueno y con mucho criterio para la circulación. Tiene una buena capacidad para retener el balón, escapar de presiones incluso de espaldas y hacer progresar al equipo a través de la conducción y, sobre todo, el pase.','RP','Seguir'),
  ('91a1a567-290c-513f-99c8-399d7854ab42','3df0004d-59bb-56ce-83ca-50e0000c7c6b','2025-11-21 11:58:10','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Centrocmapista diestro de segunda altura, para actuar como interior o en doble pivote. Perfil físico medio-bajo en cuanto a estatura y complexión. Buen nivel técnico para retener el balón, escapar de marcas y conducir. Juega bien de espaldas y suele hacer avanzar al equipo. Buen criterio y visión de juego, jugador de un alto nivel de participación.','RP','Seguir'),
  ('f48520a7-17d0-5021-8a41-ff1e47765e32','05af3b9b-95ef-5a30-b7e7-a90d4228e817','2025-11-21 12:00:43','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Centrocampista zurdo de segunda/tercera altura, aunque con capacidad técnica y física para intervenir en las tres alturas. Perfil físico sensacional: estatura cercana a 1''85 m y complexión fuerte. También es explosivo y tiene una zancada muy poderosa. Nivel técnico altísimo para controles, giros, conducción y pase. Muy agresivo con balón y con personalidad para buscar siempre generar ventaja. También tiene buena capacidad de llegada y de finalización en los últimos metros.','RP','Firmar'),
  ('21932c50-598f-5c99-a7db-1bb22f9f3520','08f9ed00-d179-5da4-93c6-a334a0527252','2025-11-21 12:04:01','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Extremo diestro de perfil físico similar a Luismi, aunque menos fuerte y algo más ágil. Técnicamente es muy bueno y también tiene mucha habilidad para mantener el balón pegado al pie y desbordar con facilidad. Muestra una buena llegada al área y peligro en los últimos metros a través del centro, el disparo y el remate dentro del área.','RP','Seguir'),
  ('0de77a8f-1421-5846-ba77-ec7a67b7f6a4','8c36adcd-71f9-5a46-a5e2-c1692bf029d6','2025-11-21 12:07:21','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Delantero centro con un perfil físico alto: estatura cercana a 1''85 m y complexión muy fuerte, aunque tampoco es lento en carrera. Buen nivel técnico y bastante criterio a la hora de participar en el juego del equipo. En lo que más destaca es en el remate, tanto con los pies como de cabeza. Es un delantero capaz de marcar la diferencia con pocas intervenciones.','RP','Firmar'),
  ('1db175d6-87f7-55ef-a69f-df204419378b','a486798c-0dee-58b8-8d58-35c5f5818ec7','2025-11-21 12:12:38','Dinamarca sub-17 - ESPAÑA SUB-17 (14/10/2025)','Extremo zurdo con un perfil físico excepcional: estatura alrededor de 1''85 m, complexión fuerte y muy potente en carrera, tanto en primeros metros como en distancias más largas. Jugador más técnico que habilidoso, tiene muy buenos toques y desborda con acciones sencillas: fintas, cambios de dirección, salidas explosivas, etc. Muy buena capacidad de llegada y de producción ofensiva en cuanto a goles y asistencias.','RP','Firmar'),
  ('755bc683-81f1-51d4-95df-77b63dfae48f','dc54a879-903a-5749-880c-7f0bb4b4a835','2025-11-21 12:33:39','vs Real Madrid','Central diestro de planta espectacular, con estatura cercana al 1.90 m, estructura física potente, musculado, con buen punto de velocidad y agilidad para su tamaño, aunque es cierto que da sensación de que en primeros metros le puede costar. En defensa es agresivo para anticipar, salir de zona y buscar duelos individuales. Fuerte por abajo y por arriba. Con balón, sin tener gran técnica, destaca por jugar hacia adelante. Sale en conducción muy potente y filtra por dentro.','NB','Firmar'),
  ('7bdea6d6-0aa4-5258-9729-9be5f46d3002','27cad8ba-b61e-5866-97f7-b046c0bea039','2025-11-21 12:35:57','vs Alcobendas','Central diestro de buena planta: espigado, delgado, con zancada, sin ser tan rápido. Bien jugando hacia adelante y en juego aéreo.','NB',NULL),
  ('41422cc7-b7d7-54cb-8cc3-ae04cc4d93ce','9c574cc8-96cf-5e6e-bf51-042c110fcc05','2025-11-21 12:36:57','vs Alcobendas','#8 de físico normal, sin destacar. Calidad para asociarse, manejar balón, superar presión y rivales en corto. Destaca por llegada a último tercio, con gran golpeo para remates y pases/centros. En defensa ok, sin destacar.','NB','Seguir'),
  ('dcd74b3b-df81-5450-b656-cc5e8e92004e','5d42d513-07a9-5ac0-9232-e5b73a4c9b93','2025-11-21 12:41:14','vs Alcobendas','Me parece perfil top, por físico, condiciones técnicas y llegada a área. Similar a Sancet en características.','NB','Firmar'),
  ('2cc5a150-51aa-5144-ac1a-7e05b74f536c','3b76ec9b-0609-5acc-bdd5-416fb7feb213','2025-11-21 12:42:01','vs Alcobendas','Me fijé especialmente en él, no hace un buen partido. Más allá de eso, tiene una debilidad importante en su juego. No sabe utilizar la derecha. Y eso le limita a la hora de tomar decisiones y generar impacto, ya que se vuelve previsible y pierde recursos en corto.','NB',NULL),
  ('2d9a6841-08b7-5dd3-acd1-7616bbb1aa64','c7b6cb1a-a02f-5b69-b4f8-f3138fea7b27','2025-11-21 13:50:45','ALBACETE JUV. A - Valencia Juv. A (18/10/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando en doble pivote, pero estilo de juego de interior. Perfil físico medio en cuanto a estatura y complexión. Muy buen nivel técnico, retiene muy bien el balón y es capaz de encontrar soluciones para mejorar jugadas o incluso generar acciones de peligro.','RP','Seguir'),
  ('5e35580d-f29f-54a1-8e3b-0f2fd856ff1c','b49fc57f-0d10-539c-97e7-bd7b54db4857','2025-11-21 13:54:13','vs Canet','Juega de  #10. Centrocampista zurdo, de físico medio, no impresiona por cualidades a primera vista (estatura media, delgado) ni por tener gran intensidad/ritmo. Con balón bien, maneja los dos perfiles, tiene recursos individuales y visión de juego. Sin balón le falta bastante. Trotón, poco trabajador en transiciones, no es agresivo al duelo. No genera impacto real en su equipo en este partido.','NB',NULL),
  ('1d07b59d-61ac-5d7a-956a-e7c257647746','b535341c-628b-5ed1-9e0a-77d23f28b446','2025-11-21 13:55:48','ALBACETE JUV. A - Valencia Juv. A (18/10/2025)','Carrilero diestro con un perfil físico medio-bajo en cuanto a estatura y complexión. En el partido solo ha jugado la primera parte y estaba en la banda contraria a la cámara, por lo que no puedo evaluarlo bien. Aún así, parece un jugador bastante dinámico, con recorrido y capacidad de desborde en campo rival. Está siendo titular con el Albacete en DH','RP','Seguir'),
  ('4a339578-c1f3-5cf0-b4fa-91fe4948945e','90d126f2-d836-5130-b807-aa109a00510a','2025-11-21 13:59:02','ALCABETE JUV. A - Valencia Juv. A (18/10/2025)','Central diestro con un perfil físico interesante: estatura alrededor de 1''85 m y complexión fuerte. Ha salido en la segunda parte y ha ganado todo por arriba.','RP','Seguir'),
  ('08c4c14d-1b9e-5709-b39c-36d31f8aaa3b','23cae36e-21fb-56d3-8906-1353b1f18b36','2025-11-21 14:02:38','ALBACETE JUV. A - Valencia Juv. A (18/10/2025)','Carrilero izquierdo de estatura medio-baja, pero dinámico, rápido y con bastante recorrido. No va mal a duelos y con balón tiene ideas interesantes y una técnica suficiente.','RP','Seguir'),
  ('ce7e7211-567d-569e-8e81-45546dbf01f6','613f4a1c-c3ed-5183-b0d2-eee00e3b618a','2025-11-21 14:04:30','Albacete Juv. A - VALENCIA JUV. A (18/10/2025)','Lateral izquierdo de perfil físico medio. Ha tenido un partido correcto con y sin balón, pero no he visto nada extraordinario.','RP',NULL),
  ('c2727899-49e0-50bd-8b79-ef309d890f01','aeb8cbbd-3d9c-5a3f-ace7-0cc1a7163b2a','2025-11-21 14:05:32','Albacete Juv. A - VALENCIA JUV. A (18/10/2025)','Central diestro con un perfil físico muy interesante: estatura algo superior a 1''85 m y complexión muy fuerte, aunque algo lento en movimientos y en carrera. Tiene una muy buena lectura y técnica defensivas y es muy contundente. Va muy fuerte al choque y gana casi siempre. Con balón es correcto.','RP','Seguir'),
  ('0d47b079-a673-596a-b73c-5efe313401e0','b8b8aa80-d41b-58e1-939d-33d8eeeed79d','2025-11-21 14:08:12','Albacete Juv. A - VALENCIA JUV. A (18/10/2025)','Centrocampista diestro de segunda/tercera altura. Perfil físico medio, aunque resiste muy bien los duelos y tiene una gran capacidad para proteger el balón con su cuerpo. Técnicamente sobresaliente y muy creativo, es un jugador diferente.','RP','Firmar'),
  ('b50613c5-2c22-5c59-9382-45a7322909d9','42f2be60-fc28-5cec-913e-2cd9e297a337','2025-11-21 14:11:07','Albacete Juv. A - VALENCIA JUV. A (18/10/2025)','Lateral derecho de perfil físico medio. Ha estado correcto, pero no destaco nada.','RP',NULL),
  ('f507c2ee-c3f5-5a75-96af-9646032e2d78','fc6cee27-b26e-5ee7-8272-8146ffb74520','2025-11-21 15:45:23','vs Majadahonda','Medio #6-#8 de buen perfil físico (aún por hacer, da sensación de que puede ganar centímetros y mayor musculatura, es ágil, veloz, con recorrido). Diestro, de buen nivel técnico, vertical para recuperar y salir hacia adelante en conducción. Intenso en duelos, con técnica para ganar balones.','NB','Firmar'),
  ('a3774e0a-8c11-5a53-9b19-f5d2985dce31','1c4dc383-b594-5dab-98ef-97d420b7956c','2025-11-21 15:47:30',NULL,'El mejor central izquierdo de su generación a nivel nacional.','NB','Firmar'),
  ('f81b45af-97a0-5305-a8a7-696e03ced6fa','de72106d-f624-52ef-b0e4-dcab76c61597','2025-11-21 15:48:30','vs Majadahonda','defectos defensivos claros, acompañado de un perfil físico que no es positivo. Le puede costar.','NB',NULL),
  ('64bbcf0b-3f02-5116-9a86-6c7057298501','f470b43e-3c30-5f26-917c-3d16d433dd7b','2025-11-21 15:49:14','vs Majadahonda','Extremo de físico promedio, estatura media-baja, no es poderoso. Bastante rápido, con aceleración en primeros metros. Perfil ok sin ser tan diferencial.','NB',NULL),
  ('bfb0f9c4-ecac-5aa1-8965-d6ea67246334','3ed055bd-40c6-5fc3-9329-bfdc32ace474','2025-11-22 12:36:26','vs Patacona','#6 de 1.73 m aprox, tren inferior potente, ágil, con energía y recorrido. Técnica muy buena para dirigir juego asociativo de su equipo, progresar con balón y llegar a último tercio. Toma decisiones positivas, siempre escanea antes de recibir. En defensa tiene intensidad y es trabajador, le falta más físico para imponerse más. Es buen jugador, me deja dudas si seguirá creciendo físicamente.','NB','Seguir'),
  ('0e767b00-bd36-58ed-906e-45ba105824ea','03cd8462-8e11-596f-a980-1fa19a52bf05','2025-11-22 12:39:46','vs Patacona','Central diestro que saca mucha ventaja física con respecto al resto. Juega con una superioridad extrema, conduciendo hacia adelante sin problemas y ganando duelos defensivos. Se nota que es un chico al que le cuesta todo lo analítico, mala toma de decisiones, no parece inteligente. Tiene toda la pinta de que no va a crecer más.','NB',NULL),
  ('c6945df2-51ff-5e3e-b07b-881304ade69f','6511a91b-5ae8-5e82-a0cd-963819a1e1a3','2025-11-22 12:42:44','vs Patacona','Extremo de estatura normal, bastante fuerte y rápido. Perfil similar al de Mauro Roca, pero de menos nivel al menos por ahora. No es extremo de 1v1 y gran desequilibrio, pero es cierto que llega bien al área. Influye directamente en los dos primeros goles.','NB',NULL),
  ('e7dd7afd-3366-573e-80eb-bf5e545a8a93','b3bf7333-6b04-52ef-8cfb-b06a60cacb98','2025-11-22 12:46:06','vs Patacona','Delantero centro de buen perfil físico, pero al que no se le ve impacto en juego','NB',NULL),
  ('16a2cf1b-f2c3-5528-8dea-be5792f2a98b','42ce8165-964a-57fe-b98b-5ab2dee32919','2025-11-22 12:47:24','vs Patacona','Delantero con buen perfil físico: fuerte, rápido, de estatura media. Dudas sobre evolución física. Es capaz de generar ocasiones por su cuenta. Tiene capacidad para influir en área. Mala toma de decisiones en general.','NB',NULL),
  ('341db480-0add-59b0-929d-55b27a753c66','82267212-1aeb-5bc2-bb1b-d2d7e1946aba','2025-11-22 12:50:43','vs Patacona','Delantero centro de perfil físico muy bueno, aún descoordinado y con problemas técnicos. Está jugando poco.','NB',NULL),
  ('2f6e0a30-c2b8-5155-a52c-91c04396b5cb','828d903c-17b3-5251-bc44-07d3510beece','2025-11-22 12:59:21','vs Villarreal','#6 de buen perfil físico, agresivo, con carácter e intensidad. Buen recuperador, dinámico en sus acciones, juega hacia adelante. Le falta algo de pie. En mi opinión el de mayor potencial de su equipo, quiero verlo más.','NB','Seguir'),
  ('61b0bafd-218f-5d18-ae0a-2aeb341049e9','6ca7a462-18c5-5a5c-8405-5822a9d14e46','2025-11-23 01:18:57','vs Damm','Central de condiciones físicas top: fuerte, alto, veloz. Con gran capacidad en salida de balón, sólido en duelos individuales.','NB','Firmar'),
  ('58e35b65-2f44-58b7-b821-d99145229506','91847783-fb65-52ba-9b70-7a6ca9c7f7dd','2025-11-23 01:20:09','vs Damm','Extremo bajo, poco poderoso, muy rápido, explosivo. Buen 1v1 y golpeo de derecha.','NB',NULL),
  ('4303ea73-584d-5ed1-801d-938a63dd809d','111a84a3-31d2-5b37-8fce-f8d0b4862b76','2025-11-23 01:21:19','vs Barca','Perfil similar a Aleix Enríquez. Jugador de banda, pero que se mueve mucho por dentro. Tiene algo más de 1v1, destaca por golpeo y capacidad de finalización. Perfil físico bueno.','NB','Seguir'),
  ('48781f77-2544-589c-a56f-df8f9eaf92ad','010de466-02ef-59bc-a285-6fef9a903600','2025-11-23 01:22:09','vs Barca','Poco impacto en juego. No me termina de convencer, lo veo poco veloz y le faltan recursos para generar por sí solo','NB',NULL),
  ('c4d3b438-cf03-54f3-b4be-6fff638374e0','6abc2a1b-06a0-5fa5-a57f-c69fe67ba43c','2025-11-23 01:23:37','vs Barca','Extremo de buen perfil físico para posición. Sin ser extremo puro, ya que se mueve bastante por dentro. Buena capacidad para asociarse, crear ocasiones y finalizar.','NB','Seguir'),
  ('205a6a90-380c-5e15-880b-47b2726a2abd','d72e16e1-129d-5742-a277-d87fdf68f785','2025-11-23 01:31:37','vs Hercules','Lateral - extremo zurdo de estatura baja, muy veloz y explosivo. Genera peligro atacando espacio y en carrera, tiene recursos en 1v1 y es capaz de sacar centros. Intenso y agresivo en su juego.','NB','Seguir'),
  ('1a6abb28-b04f-59ac-bfa4-73ff85d73407','b77bcce3-529d-5afc-8a33-c4791eaaef2c','2025-11-23 01:37:23','vs Hércules','Perfil de mediocentro interesante. Alto, espigado, vertical en acciones, con llegada desde segunda línea, nivel técnico OK, trabajador.','NB','Seguir'),
  ('f71e5200-adb6-5283-875d-b0b6a51fa7e8','5dcfea8b-88b0-5536-8d28-4fd59a4182c2','2025-11-23 01:38:58','vs Hércules','Extremo de buen perfil físico, con punto interesante de velocidad y aceleración. Desequilibrio en 1v1, gana metros en conducción, genera ocasiones, tiene buen golpeo para centros/remates. Toma de decisiones mejorable.','NB','Seguir'),
  ('de8f7a36-275c-5125-9eee-b19e07b99f93','dc503b30-fe10-54fe-852c-8d76dd467bc9','2025-11-23 01:40:14','vs Hércules','En persona el perfil físico me impresiona, centrocampista con estructura perfecta para posición. De resto, lo que vengo compartiendo en análisis anteriores. Sigue sin ser lo influyente que debería pero aún así es jugador interesante.','NB','Seguir'),
  ('4973bad6-daf7-515f-9768-5d8b47317dd9','24cc58e2-9e21-5755-9152-8ba8d6ed097d','2025-11-23 01:41:28','vs Hércules','#6 de buena estatura, dudas sobre ritmos altos. Fuerte en juego aéreo, bastante intenso, con buen toque sin ser demasiado vertical.','NB',NULL),
  ('4ad3afae-0763-5796-866d-73035bda3645','32691a09-e321-555b-80bc-7edc74d72cc6','2025-11-23 01:42:38','vs Hércules','Estatura media, tren inferior potente, jugador dinámico y con llegada desde segunda línea. Vertical para buscar el tiro y terminar jugada. En defensa es discreto. No lo veo nivel primer equipo','NB',NULL),
  ('1d6fd4c1-70f9-58e6-8acb-3049adada463','5657266f-2165-5e33-8a21-e23e27f660bd','2025-11-23 01:45:53','vs Betis B','Extremo muy habilidoso, con gran capacidad para superar en 1v1, con recursos para el regate y también asociarse. Va al espacio con peligro. Es trabajador y tiene retroceso. Carácter competitivo. Físico normal en cuanto a estatura y corpulencia. Muy rápido y explosivo. Jugador de otra categoría.','NB','Firmar'),
  ('00e30541-4526-5e4b-be52-7bd9823036cd','e61b292f-aab5-58e4-8fbf-8c5f6188f2be','2025-11-24 20:02:57','vs Extremadura','Delantero centro de físico fuerte, alto, buen punto de velocidad. Juega bien fuera del área, de espaldas y yendo al espacio. Tiene impacto en el juego desde su entrada.','NB','Seguir'),
  ('44d6a7a2-2f71-591e-aede-ddfc66cbd1d8','c058cc00-b874-53d4-a2c0-2a7e250d78af','2025-11-25 11:08:37','VILLARREAL B - Nástic (21/11/2025)','Extremo diestro, en el partido actuando en banda izquierda. Perfil físico bajo en cuanto a estatura y complexión, pero con una gran aceleración y tren inferior fuerte. 

En el partido no ha tenido una gran participación, pero ha generado las ocasiones más claras del equipo, enviando dos balones al palo y desbordando en tres o cuatro ocasiones con mucho peligro.','RP','Seguir'),
  ('ecde23de-cca9-5c2d-a228-43a7740f170d','50ea397f-ff3c-51d5-9765-325f1dc23c47','2025-11-25 11:10:59','VILLARREAL B - Nástic (21/11/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en un doble pivote. Perfil físico medio alto: estatura alrededor de 1''80 m y complexión delgada pero fuerte. No es especialmente dominante ni con balón ni sin él, pero es muy seguro y va muy bien en duelos y en acción defensiva.','RP','Seguir'),
  ('2402c2d1-1071-583c-b4c5-6c1f6b081912','385bd0c6-e2db-5f3e-a000-8d5ba4d12bec','2025-11-25 11:13:26','CASTELLÓN B - Torrent (22/11/2025)','Jugador de banda, diestro. En el Castellón juega de carrilero, pero es extremo. Estatura alrededor de 1''80 m, físico fuerte. No he podido evaluarle en carrera de media y larga distancia, pero tiene una arrancada potente. Buena técnica y cierta habilidad para desbordar.

En su última temporada en DH marcó 8 goles, así que puede tener cierta capacidad de producir.','RP','Seguir'),
  ('e835bd89-b6ca-5e5f-b3c1-8ae088dc4ba7','9a83f5d5-d688-51c5-9fdd-7c5dd8a3809d','2025-11-25 11:15:45','CASTELLÓN B - Torrent (21/11/2025)','Mediapunta/segundo punta diestro. Buena capacidad técnica, aunque no le veo muy acertado. Estatura alrededor de 1''80 m y físico delgado pero fuerte. No me gusta mucho el perfil táctico, estilo mediapunta, pero tiene calidad, no está mal físicamente y está jugando bastante en 2ª RFEF siendo 2006.','RP','Seguir'),
  ('3c6eac66-f302-53e3-831e-2d18c3dbd6f4','2fca2493-701f-5ef3-b2ed-345e292d79d0','2025-11-25 11:19:01','VALENCIA JUV. A - UCAM Juv. A (23/11/2025)','Centrocampista diestro de primera altura, para actuar como mediocentro o en doble pivote. Muy seguro con balón e intenso en defensa. Estatura algo inferior a 1''80 m, complexión fuerte. Ha entrado bien al partido, pero luego ha ido perdiendo peso y ha tenido un error grave en salida que casi acaba en gol.','RP','Seguir'),
  ('0b513864-8a1c-586e-a08f-96c717d5b968','83d173c8-72d4-5ad5-8289-11851d5260a1','2025-11-25 11:23:17','VALENCIA JUV. A - UCAM Juv. A (23/11/2025)','Extremo con un perfil físico muy interesante: estatura superior a 1''85 m y aspecto fuerte. Ha entrado en la segunda parte y no ha tenido demasiadas intervenciones, pero se ha mostrado muy agresivo con balón. Tiene una arrancada potente.','RP','Seguir'),
  ('0e9fd401-e520-5948-adda-f0c78181974e','f4a1efb6-8451-57d5-9a20-160cb83e50de','2025-11-25 17:09:09','VALENCIA JUV. A - UCAM Juv. A (23/11/2025)','Delantero centro zurdo con un perfil físico interesante; estatura superior a 1''85 m y complexión fuerte. No es lento en carrera, va muy bien a duelos y combina bastante bien. Ha marcado dos golazos impresionantes y se va del partido con tres goles y una asistencia.','RP','Seguir'),
  ('7debb792-587c-5d0d-893f-a9b6e70ea3b5','b9488bec-4680-5aa6-a07f-1ac9b9d99a9d','2025-11-25 17:11:04','Valencia Juv. A - UCAM JUV. A (23/11/2025)','Extremo zurdo. Estatura alrededor de 1''85 m. Ha marcado un golazo después de jugada individual sentando a varios defensas. Técnicamente bastante bien.','RP','Seguir'),
  ('c5b9df01-24cd-5db9-ba11-d0c514240f43','a72b2955-4951-5b8e-b98b-ad4cdc363db4','2025-11-25 17:14:29','Valencia Juv. A - UCAM JUV. A (23/11/2025)','Delantero centro diestro con un perfil físico interesante: estatura algo inferior a 1''85 m y complexión fuerte, aunque quizás algo pesado. Bien en duelos. Ha fallado una ocasión clara.','RP','Seguir'),
  ('164bd20d-9d5c-5ca0-be20-fd92cc0842fa','eda4b624-4ff5-5fc5-8f84-aa02598cb7cd','2025-11-25 23:40:52','vs Rayo','Mediapunta de buen nivel técnico, móvil, dinámico. Tiene visión de juego, buen pase largo, capacidad para jugar hacia adelante.','NB','Firmar'),
  ('f4cf8aca-5a16-5e50-a415-3e3c5db6b287','b35d4619-ef72-58f9-a637-21bd5b5144ab','2025-11-25 23:57:02','vs Lleida','Delantero centro de gran perfil físico, que genera ventajas con su juego fuera del área. De espaldas, asociándose con sus compañeros, jugando con criterio, mostrando visión de juego. En el área le faltó presencia, poco preciso en remates en este partido.','NB','Firmar'),
  ('bf30c702-c4c4-5e40-9ec5-0ccca8212741','c6aeac05-d89c-51fe-b2a1-b54b54f617b5','2025-11-26 00:06:56','vs Lleida','Repito opinión. Es extremo con buena llegada a área, con capacidad para generar ocasiones y finalizarlas, tanto con remates como con pases. Le falta mayor poderío físico.','NB','Seguir'),
  ('4d600a83-5f52-5521-b743-ca01055b3030','aed14ae1-71d6-5ed8-873e-fef6fcf34f90','2025-11-26 00:13:52','vs Lleida','Condiciones físicas sobresalientes. Pese a problemas de finalización de jugadas y defectos técnicos, jugador que genera peligro con facilidad gracias a su físico. Peligroso yendo al espacio, atacando profundidad, en conducción.','NB','Firmar'),
  ('23c8e5f5-44d8-5577-9248-20b4989128c9','c631ebd9-737e-5c24-9bd9-65e2c345afbe','2025-11-26 00:36:24','vs Valencia B','Lateral izquierdo de estatura media, delgado, veloz. Le cuesta en defensa, y en ataque no genera ventajas significativas.','NB',NULL),
  ('cff35d4a-34c7-543b-b703-1e78aff942e2','7efde4c5-4801-5f69-bd74-ab6e68ec08d9','2025-11-26 12:07:55','vs Trival Valderas','central zurdo, buen biotipo, largo, delgado, utiliza derecha para controles, con balón juega hacia adelante sin complicarse, asociaciones cortas, se incorpora a ataque y mete buen pase al área, gol ABP, gana x arriba, bien midiendo en situaciones de 2v1 para cortar pase. Dudas sobre velocidad hacia atrás, no es sensación de ser top en esto. Gana juego aéreo. 

Tras verlo vs Real Madrid confirmo que no es rápido, lo que deja dudas sobre potencial.','NB','Seguir'),
  ('9587793c-1f8c-5517-844a-2e729228fc60','a0cccc26-4830-5eb2-be98-69a760e037ea','2025-11-26 12:11:25','vs Trival Valderas','#6: buena tipología física, dinámico, juega hacia adelante, dinámico, capaz de conducir, perfil adaptable a 8. Físico ok sin ser sobresaliente.','NB',NULL),
  ('3aa3c163-9219-5442-acf0-43e5f8031ae9','aa714cee-e6b8-569f-b4c5-cef59b2f373a','2025-11-26 12:12:36','vs Trival Valderas','#27: Delantero de estatura media-baja, físico normal. Se mueve bien por dentro, dinámico entre líneas. Rápido, aguerrido, con criterio para asociarse. Le falta poderío para ser 9.','NB',NULL),
  ('7d488cdc-3eb3-5c8e-9b91-f2fd36d7ef85','6079f3c2-3d1e-5ef5-aed8-d8291d9d6fb0','2025-11-26 12:15:21','vs Trival Valderas','Entra de lateral izquierdo, impacto limitado en juego. Es bajo y poco poderoso, su perfil físico no le permite sacar ventajas más allá de velocidad y aceleración.','NB',NULL),
  ('594e2c0e-461a-547e-84c5-81dfca810a1f','4aa8ae32-a458-54e2-9c3c-d9dad9f67319','2025-11-26 12:18:29','vs Trival Valderas','Entra en banda para minutos finales. Jugador dinámico, que va hacia adelante en conducción y es capaz de sacar centro de gol y algún pase más hacia atrás. Estatura media, musculatura por hacer aunque bastante fuerte para soportar choques, rápido en carrera. Se le ven condiciones para ser 8 de ida y vuelta.','NB','Seguir'),
  ('4e474709-1973-5016-8580-07618a34bbfb','8990848a-32d3-5b66-ba89-f75dad3b517b','2025-11-26 13:56:27','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Lateral diestro con un perfil físico medio. Partido de lateral correcto, con algunas buenas acciones pero sin destacar. Está jugando todo con el Espanyol en DH.','RP','Seguir'),
  ('4baf86a4-8331-5982-9d66-f5a19dc4bdc5','4f9c2b27-9205-588f-9bc6-c9a90ab30478','2025-11-26 13:59:20','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Lateral izquierdo con un perfil físico medio en cuanto a estatura y corpulencia, pero bastante explosivo en carrera y potente en el duelo. Mucho recorrido y buena llegada a último tercio, con acciones de carrera y centro muy interesantes. Con balón tiene una buena técnica para participar en la construcción del juego y escapar de presiones.','RP','Seguir'),
  ('eced218d-479c-5e42-8ec1-2ee5443a8c96','4f527eea-f439-50b7-b063-c73481eabfa8','2025-11-26 14:04:34','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Extremo diestro perfil mediapunta en banda. Perfil físico medio-bajo en cuanto a estatura y complexión. Mucha calidad técnica y personalidad con balón. Está siendo titular en DH con el Espanyol.','RP','Seguir'),
  ('6c2fe2d5-efd6-5334-8588-cc4344766a1d','f6a01600-ab90-590b-893b-202f68f66dea','2025-11-26 14:07:14','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Extremo zurdo de perfil físico medio-bajo en cuanto a estatura y complexión. Muy ligero y no he visto nada muy destacable con balón.','RP',NULL),
  ('2bfb9d20-769b-5e20-b947-280ff48618b1','7e90fc8b-6a7a-5eb7-a735-daf74c24faff','2025-11-26 14:10:33','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Central zurdo con una estatura alrededor de 1''85 m y complexión delgada pero fuerte. Es muy contundente en el duelo, especialmente cuando defiende hacia delante, y extraordinariamente dominante en el juego aéreo. Con balón le he visto correcto. No he podido evaluarle la velocidad en carrera, pero no parece lento.','RP','Firmar'),
  ('fa33dc4c-c4d9-585a-bac9-671b0569ca2d','e9602a91-2142-5d52-b3c5-f8cfc86e447e','2025-11-26 14:13:08','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Delantero centro diestro con un perfil físico interesante: estatura quizás algo inferior a 1''85 m y fuerte para los duelos. Me ha gustado cómo usa el cuerpo en los choques y alguna acción con balón interesante.','RP','Seguir'),
  ('bc83b83a-91be-54a2-b217-2ebdc6787a31','118cb409-5a72-5f19-b2ff-fa05a1a08b01','2025-11-26 14:15:54','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura algo superior a 1''85 m y complexión delgada pero fuerte. Tiene cierto criterio con balón. Algo lento de movimientos.','RP',NULL),
  ('ef158b42-ffac-5a71-9fc6-926353a7c028','6fd8206d-f0de-50f1-8903-8781655edcca','2025-11-26 14:17:08','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Delantero centro de perfil físico medio. Bastante peleón, pero en el partido no he visto ninguna acción destacable.','RP',NULL),
  ('dbfb9bc2-bb3a-5b4d-a23a-44c95e0c3e57','207a6567-8924-5c6f-a004-ad30813735ab','2025-11-26 14:19:04','Racing Zaragoza Juv. A - ESPANYOL JUV. A (18/10/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura alrededor de 1''80 m y complexión normal. Ha tenido alguna buena acción con balón.','RP',NULL),
  ('b7560863-7113-5486-930f-18fb10d41451','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2025-11-26 19:09:29','vs Porto','Morante: juega por derecha, a pierna cambiada. Tiene un perfil físico ideal para la posición. Es alto, bien compensado, con zancada, margen de crecimiento muscular. Tiene resistencia para repetir esfuerzos durante los 90 minutos. Jugador de ritmos altos, que se adapta a juego de transiciones pero también tiene ese punto de calma/pausa para tomar decisiones correctas. Es un jugador decisivo en último tercio gracias a su gran golpeo para pases y remates.','NB','Firmar'),
  ('8556d838-501b-512e-9e28-1c3a21c5d9c5','a2e7fd5a-c61c-5156-b844-f0b705c660ba','2025-11-26 19:15:50','vs Porto','González: extremo diestro por derecha. Perfil físico promedio: estatura cercana al 1.70 m, bastante fuerte de tren inferior. Es rápido y explosivo en primeros metros. Es vertical para buscar 1v1, creativo en el regate. Se nota evolución en toma de decisiones y finalización de jugadas, mejorando su golpeo de derecha. En defensa es pasivo, no destaca por ser trabajador. Es un chico irregular, que se desconecta y pasa fases largas de partido sin aparecer. Pero es cierto que últimamente está consiguiendo corregirlo.','NB','Seguir'),
  ('f288cb83-eb94-5d0b-901d-31bd88747aa6','93a33854-d3c6-5709-8a6e-747de7f13f8f','2025-11-26 19:19:10','vs Porto','Repito, se nota mejoría en Emmanuel. Aún teniendo desconexiones y errores claros en cuanto a timing y lectura de juego, tiene una superioridad física que le permite imponerse en duelos individuales y corregir. Además con balón es capaz de sumar jugando hacia adelante, sin destacar.','NB','Seguir'),
  ('a47e7f69-8e23-5e7a-abb3-ab1c3b63859f','6dd78885-4fa5-5394-82df-e9e749d3be94','2025-11-26 19:21:54','vs Porto','Mario: Lateral derecho de perfil físico medio (estatura promedio, musculatura poco desarrollada, buena velocidad y aceleración, con recorrido y capacidad para repetir esfuerzos). En defensa tiene rendimiento notable, ganando la mayoría de duelos individuales y mostrándose fuerte en situaciones de 1v1 en contra. Además, vigilando su espalda y no siendo superado. En ataque tiene criterio para llegar asociándose y recursos para generar desequilibrio individual.','NB','Firmar'),
  ('caae8018-ae8a-5643-8190-53ab26c9fa44','91b842b2-5662-5446-a89e-9fd00413118c','2025-11-27 00:43:54','vs Lugo','#8: Buen perfil físico. Estatura +1.80 o así parece. Con margen para ganar musculatura. Se asocia bien, juega hacia adelante, conduce. Ágil para giros, vertical. Juego asociativo bien, puede liderar. Creo que en defensa le falta mayor impacto.','NB','Seguir'),
  ('49c53e26-db3a-59d7-a4f0-47e5e03a9bfb','8ec10332-d52a-574f-ba7a-2dc6f921baa5','2025-11-27 00:44:45','vs Lugo','#7: buen físico. Estatura media-alta, bien compensado. Rápido. Usa bien el cuerpo. Gana metros en conducción. Muy bien a la contra. No usa izquierda. Buen centro raso. Irregular, con largos periodos en los que no aparece.','NB',NULL)
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('85ab47d8-c11e-5845-bea1-e361c86ea6aa','f0ff7585-3bac-5cc7-924b-57893652c83f','2025-11-27 00:45:44','vs Lugo','#9: Perfil físico muy bueno. Alto y fuerte. Muy grande. Primer control mejorable, le cuesta amortiguar. Buen giro y punto interesante de velocidad en primeros metros. Finaliza a primer toque en área.','NB','Seguir'),
  ('88ed789b-a577-57a7-a98c-32aabc786f5c','a7363496-50a0-5f49-bd8c-99d84b1e5c97','2025-11-27 00:46:31','vs Lugo','#10: Buen perfil físico. Estatura alta, fuerte, con buena arrancada. Juega hacia adelante, entre líneas. Intenso y agresivo. Busca tiro con frecuencia. Llega a área.','NB','Seguir'),
  ('f653dfde-7afb-5fea-913f-a7164938455f','641513de-0286-526b-8fe7-c3bdd7789883','2025-11-27 00:47:57','vs Lugo','#16: perfil físico medio. Estatura normal, delgado, con margen para ganar músculo. Bien en velocidad, sin dar sensación de tener explosividad top. Vertical para buscar situaciones de 1v1.','NB',NULL),
  ('660ac550-c0b7-5325-a35a-a6c394045007','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2025-11-27 14:12:13',NULL,'Centrocampista de buen biotipo físico: es alto, de piernas largas, con margen de crecimiento a nivel músculo, es ágil, tiene recorrido. Con balón va hacia adelante, vertical en sus acciones, gana metros en conducción, tiene buen pie. En defensa es ganador de duelos, intenso para afrontarlos e inteligente para posicionarse.','NB','Firmar'),
  ('8e14d884-7777-5ce2-84ad-9e0132aed259','30283bd4-f551-547e-acf9-3ffbb0dee053','2025-11-27 14:23:33','vs Sanluqueño','Extremo zurdo, por derecha. Buen prototipo físico en cuanto a estatura, fuerza, velocidad, agilidad. Es jugador con recorrido. Vertical en sus acciones, pisa área y genera ocasiones con frecuencia. Especialmente peligroso atacando el espacio y en conducción.','NB','Seguir'),
  ('b4b32997-b5f1-5d31-8925-2504d53e1cac','75534b8e-ae28-50e9-ab07-55eaa003ea3a','2025-11-27 15:09:10','vs Teruel','Como #8 - #10 tiene condiciones muy positivas. Perfil físico top: +1.80 m, compensado, fuerte, veloz, ágil. Es vertical para llegar a último tercio, pisa zona de finalización con frecuencia. En defensa es activo en presión y tiene recorrido.','NB','Firmar'),
  ('934b76cd-88e7-54ee-8de8-f64e3e7d505b','a84c149f-90cf-5f5b-9846-2071e38669cf','2025-11-27 17:11:39','vs Olot','Extremo diestro en izquierda. Físico promedio, sin destacar por tener gran biotipo en cuanto a estatura, fuerza…Es rápido, sin tener gran explosividad. Es extremo hábil, desequilibrante en el uno contra uno, con buen golpeo.','NB','Seguir'),
  ('6675bf05-5822-5629-878e-c53734f1232b','0b63d4a9-372d-53ed-a7a3-f0e03bfaa401','2025-11-27 17:13:47','vs Olot','Lateral derecho de buen perfil físico para la posición. Poco impacto en partido.','NB',NULL),
  ('1212dfdd-7777-519f-b9fa-c814f2ea5226','0cdebbd4-c496-5e12-b9cd-d08ac1f372c9','2025-11-27 17:17:11','vs Olot','Extremo de estatura cercana al 1.80 m, delgado, poco poderoso. Rápido en carrera, ágil. Tiene poco impacto en juego, se le ven debilidades técnicas y en toma de decisiones.','NB',NULL),
  ('19ecd6ef-ea23-5391-ace0-1a4d686fb707','a95b33ee-832e-567d-bade-531e8c222445','2025-11-28 12:16:01','Sámano - VALLADOLID B (18/10/2025)','Lateral izquierdo de una estatura algo inferior a 1''85 m y complexión delgada pero fuerte. Buen perfil técnico para aportar ventajas tanto en campo propio como rival. Muy dinámico en movimientos y explosivo para los primeros metros de carrera. Tiene bastante recorrido y en bueno en el 1vs1 defensivo. 

Por lo visto también es central, aunque no le veo cuerpo para ser top en la posición.','RP','Seguir'),
  ('6f8ecc77-b6d6-5303-8a1a-31a1c50a5500','62c5f84b-6935-5715-8b9c-0ed84cc94776','2025-11-28 12:20:56','Sámano - VALLADOLID B (18/10/2025)','Delantero centro diestro con un perfil físico interesante: estatura alrededor de 1''85 m y complexión fuerte. Muy dominante en duelos aéreos y duro en el choque. No está haciendo muy buenas cifras esta temporada pero tiene movimientos y acciones con balón interesantes.','RP','Seguir'),
  ('98e3c6d6-8ca6-534c-ae78-250aa4d95ee6','b48324ea-28c9-5df9-8266-86a257ae5b0c','2025-11-28 12:25:01','Sámano - VALLADOLID B (18/10/2025)','Central diestro con una estatura alrededor de 1''85 m y complexión fuerte. Duro en el duelo, pero me ha dejado dudas en algunas acciones defensivas y con balón.

Es titular con el filial y ha entrado en varias convocatorias del primer equipo en Segunda.','RP',NULL),
  ('d74fe73c-d9d6-5387-a254-313ceb6fb5b0','ea3cf696-7f16-54ff-a286-37174b4a5cac','2025-11-28 12:26:48','Sámano - VALLADOLID B (18/10/2025)','Extremo diestro con un perfil físico medio en cuanto a estatura y complexión. Tiene cierto desborde, pero no he visto nada muy especial en cuanto a técnica o velocidad.','RP',NULL),
  ('d35f83c2-7c0a-5cb7-995c-a97a1d99331a','f6d3092c-d3ae-5dec-aa0a-50acfff8d5d7','2025-11-28 12:28:51','Sámano - VALLADOLID B (18/10/2025)','Central zurdo con un perfil físico medio para la posición: estatura algo inferior a 1''85 m y complexión normal. Algunas buenas acciones defensivas y correcto con balón. Lleva 500 minutos con el filial en 2ª RFEF.','RP','Seguir'),
  ('6c87e3ec-46c6-5bc7-83fb-771076b77772','3d05e0cf-3610-5ede-951f-307358b825bd','2025-11-28 12:31:25','Sámano - VALLADOLID B (18/20/2025)','Central diestro con un perfil físico medio para la posición en cuanto a estatura y complexión. Es agresivo, pero no he visto acciones defensivas destacables. Con balón es correcto, sin aportar demasiado.','RP',NULL),
  ('6adc3427-6104-5dd2-82b3-fef04b7e506f','2c2a0cf9-f5dc-508f-8e9c-b77e76980709','2025-11-28 12:32:36','Sámano - VALLADOLID B (18/10/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Perfil físico interesante: estatura alrededor de 1''80 m y complexión delgada pero fuerte. Buen manejo de balón, gran ritmo de juego y bastante agresivo en la toma de decisión, buscando siempre progresar.','RP','Seguir'),
  ('bae738ab-9066-5d98-ac4d-691bb3391d17','c2c01031-911a-573b-a6a5-6b26dd17452b','2025-11-28 12:39:15','Sámano - VALLADOLID B (18/10/2025)','Delantero centro diestro de estatura cercana a 1''80 m y complexión más o menos fuerte. Ha entrado al partido desde el banquillo y no ha tenido tiempo de mostrar mucho. Está entrando habitualmente en el filial y ya ha debutado con el primer equipo del Valladolid en Segunda.','RP','Seguir'),
  ('e8986151-daf5-5954-bb6e-ce2058b0b874','a7d7fff4-88f9-5e9c-bc6a-f9297dcbcf57','2025-11-28 14:42:15','TUDELANO - Zaragoza B (18/10/2025)','Delantero centro diestro con un perfil físico interesante: estatura algo inferior a 1''85 m y complexión delgada. Tiene un juego de espaldas muy interesante y en carrera no parece lento. En el partido sale desde el banquillo y marca los dos goles de su equipo. Lleva cuatro en total.','RP','Seguir'),
  ('145cd125-88d6-5a97-a3e8-5382a7b8fe61','30633296-1284-531e-8095-6e6b16ada6cf','2025-11-28 14:46:56','Tudelano - ZARAGOZA B (18/10/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como mediapunta y cayendo a banda derecha. Perfil físico medio, pero muy ágil con el balón en los pies y con una arrancada interesante sin él. Técnicamente sobresaliente, tiene mucha facilidad para escapar de marca a través del regate y mejorar jugadas con conducción y pase. En el partido marca los dos goles de su equipo y es el jugador más peligroso.','RP','Firmar'),
  ('3a3c9ba6-2d8c-591d-9ea8-e25973c7f178','25503073-c24a-5325-9daa-e101e0ecaa39','2025-11-28 14:49:35','Tudelano - ZARAGOZA B (18/10/2025)','Central diestro con un buen perfil físico: estatura alrededor de 1''85 m y complexión atlética. Tiene algunos problemas de temporización, pero sus condiciones son muy buenas y es muy agresivo en la acción defensiva. Con balón me ha parecido correcto.','RP','Firmar'),
  ('7b6e1d9c-e9d2-55c9-becd-4f4020b9dddb','67a3adcb-e870-5b9a-b332-4ad6078aeb99','2025-11-28 14:51:30','Tudelano - ZARAGOZA B (18/10/2025)','Delantero centro diestro con un perfil físico interesante: estatura superior a 1''80 m y complexión fuerte. Es agresivo en el duelo y en el partido ha dejado alguna acción con balón de calidad. Todavía no ha marcado esta temporada en 2ª RFEF.','RP','Seguir'),
  ('15f16e64-3460-5038-bff2-1bf18b4b5779','444ab917-8d4b-5445-8230-8a063ee925d4','2025-11-28 14:55:07','Tudelano - ZARAGOZA B (18/10/2025)','Atacante diestro, en el partido actuando como extremo derecho. Perfil físico medio en cuanto a estatura y complexión, pero con una aceleración y velocidad punta muy interesantes. Jugador intenso en la acción y peligroso a campo abierto.','RP','Seguir'),
  ('ab6a3bc9-a800-585e-955c-af8287eb21c9','5a699f12-9c85-5a2d-9887-111d57a35bda','2025-11-28 16:43:55','OURENSE - Real Madrid B (19/10/2025)','Extremo diestro con un perfil físico muy interesante: estatura superior a 1''80 m y complexión fuerte. También es potente en carrera. Buena capacidad técnica para desbordar, sobre todo a través del cambio de ritmo. Puede jugar en ambos perfiles.','RP','Firmar'),
  ('d0dbeacf-d243-55be-be71-282f6534661f','08d69bc3-8b16-57d9-9825-58fa21b1b936','2025-11-28 16:48:09','OURENSE - Real Madrid B (19/10/2025)','Delantero centro diestro con un perfil físico muy interesante: estatura superior a 1''85 m y complexión delgada pero fuerte. Va muy bien en duelos, sobre todo aéreos, y usa bastante bien su cuerpo.','RP','Seguir'),
  ('226f8c38-051c-5d4a-9516-9e1c3894b6bb','b3f387c3-3c53-5205-8fc3-2781ce210c4b','2025-11-28 16:53:01','OURENSE - Real Madrid B (19/10/2025)','Extremo diestro con un perfil físico muy interesante: estatura superior a 1''80 m y complexión fuerte. Va muy bien al choque y en el partido gana varias acciones por agresividad y potencia. Con balón no he podido evaluar mucho, pero parece tener una técnica correcta.','RP','Seguir'),
  ('19f3fe7b-a6f9-5ff6-997d-3f5161ced9d5','aa0e4f48-67c7-59bd-a113-7f62c5376a14','2025-11-28 16:57:01','Ourense - REAL MADRID B (19/10/2025)','Central zurdo con un perfil físico interesante: estatura cercana a 1''85 m y complexión delgada pero atlética. Sobresaliente en la acción defensiva y en salida de balón, con capacidad para conducir y filtrar pases. Bien en duelos aéreos y mucha personalidad en todas las acciones.','RP','Firmar'),
  ('1523a7b0-3065-5838-9f54-b0ef96ef845d','cd8312ea-79bc-5921-8831-e1a9fd36221a','2025-11-28 16:59:20','Ourense - REAL MADRID B (19/10/2025)','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Perfil físico medio en cuanto a altura y complexión. Mucha calidad técnica, visión de juego y agresividad en la toma de decisión, con capacidad para hacer progresar al equipo a través del pase filtrado. Es un buen jugador, pero no le veo top ni física ni defensivamente para la posición.','RP','Seguir'),
  ('4350547f-b0f9-549c-9d50-69b8e03be6e3','bfd4566b-86ed-5e95-81eb-11df7ad84a11','2025-11-28 17:01:47','Ourense - REAL MADRID B (19/10/2025)','Central diestro con un perfil físico muy bueno: altura por encima de 1''85 m y piernas largas, con potencial para ganar en cuanto a potencia. Muy agresivo, le gusta defender hacia delante y anticipar a su atacante. Sobresaliente en el juego aéreo. Con balón es correcto.','RP','Firmar'),
  ('7f657298-8d45-509f-aaa1-59a838e9ed52','17770635-8b3b-5ffe-a168-56902549d24d','2025-11-28 17:04:31','Ourense - REAL AMDRID B (19/10/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando como mediocentro. Perfil físico más o menos interesante: estatura alrededor de 1''75 m pero aspecto muy fuerte. En el partido entra muy bien, roba algunos balones y aporta mucha seguridad con la posesión, con un ritmo de juego bastante alto.','RP','Seguir'),
  ('40309409-6f8b-5ecf-af87-fb05d668a9ad','17fe13b5-c239-5464-9293-7952d6c74e7e','2025-11-28 21:03:55','vs Cartagena','Extremo de estatura media-baja, poco poderoso en musculatura, buena velocidad. Jugador de intenciones verticales con balón, capacidad para ganar metros en conducción y progresar. Más allá de eso le falta más técnicamente para terminar jugadas.','NB',NULL),
  ('80d13da9-74cb-5497-b465-b42c2a5bd4dd','4db4bdc4-077f-5a3a-b6d4-7e1816c71c20','2025-11-28 21:07:00','Califas','Etame: Lateral derecho de buen prototipo físico. Es de estatura mediana, musculatura desarrollada, fuerte y potente. Con buen punto de velocidad y recorrido. Llega con criterio a zona de ataque, es capaz de generar en conducción, llegar a línea de fondo y centrar. Poco trabajo defensivo.','NB','Seguir'),
  ('ca41622f-4f83-5aae-bcaf-814f5509db3c','dac1482c-3609-5324-a7db-efb9d259bce7','2025-11-28 21:07:29','vs Califas','Derick: Extremo diestro por derecha. De estatura baja, tren inferior y superior desarrollado, muy potente y veloz. Genera desequilibrio individual, sobre todo en carrera y espacios largos.','NB','Seguir'),
  ('fdbf1c9a-0800-5f9b-9837-bd7c21315016','ee67da3a-ab30-5042-81ef-1988913886e6','2025-11-28 21:07:59','Califas','Tiago: Mediapunta de estatura +1.80, delgado, poco poderoso, da sensación de algo lento y que no puede soportar ritmos altos con frecuencia. Es jugador de nivel técnico alto, que se mueve bien entre líneas. Con recursos de desequilibrio y creación de ocasiones. Poco activo en fase defensiva.','NB',NULL),
  ('9aba0d13-b2d6-5df9-9363-eb41bc0558e3','c7a4890c-16b2-51b1-8b88-9f1ac74407c3','2025-11-28 21:08:28','Califas','Bermúdez: Extremo zurdo, en izquierda. De estatura baja, apariencia de tren inferior fuerte, veloz y ágil. Genera desequilibrio, tiene recursos en corto. Le falta mayor uso de pierna derecha. Físico limitante para niveles más altos.','NB',NULL),
  ('5cf62a76-cebd-55f5-a768-cc6082a18985','c2a8a5c2-d1b5-51d7-9bf9-24f64d102f79','2025-11-28 21:09:19','vs Sant Gabriel','Gerard Moreno: Lateral izquierdo de buen perfil físico. Alto, espigado, bien de velocidad. Con criterio en juego asociativo y capacidad para avanzar. Poco trabajo en defensa.','NB','Seguir'),
  ('864e7fb7-5f98-595c-a3d0-647441360ee4','df47cd80-2d2f-502b-b92a-d2ef189258d0','2025-04-04 09:48:27','vs Sant Gabriel','Marc Vara: #6 de perfil físico muy similar al de Javi Tena en cuanto a estatura, complexión, velocidad, ritmo. Me deja dudas su capacidad para subir ritmo y adaptarse a velocidades altas. No adaptable a 8.','NB','Seguir'),
  ('b7746bbc-c8ac-55a5-a65a-546ddd256034','4b752edf-e483-5adb-9940-1e8b4cdc6557','2025-11-28 21:11:49','vs Sant Gabriel','Aliouh: Extremo de poco impacto en juego. Perfil físico normal, estatura media, veloz y ágil, por hacer muscularmente.','NB',NULL),
  ('e946fef0-fdaf-5925-b860-e1b5e7cf8283','c8b306be-16e6-59bc-8bab-ca15e36d8fc9','2025-11-28 21:12:17','vs Sant Gabriel','Puig: Extremo de buen perfil físico, estatura +1.80 seguro. Me da sensación de que le falta punto de velocidad y aceleración para posición. No es un extremo de 1v1, más juego asociativo y llegada a área.','NB',NULL),
  ('55916cfb-743d-50e9-af09-1d07d28d67e6','b0a57561-e36d-52c3-a8f7-1e59c4f3a070','2025-12-01 07:54:44','vs Murcia','Extremo de condiciones físicas positivas para su posición: estatura media, delgado, con margen para ganar potencia. Muy rápido y explosivo. Encarador, con desequilibrio en 1v1, busca generar por sí solo. Es capaz de superar rivales. Algunos problemas en toma de decisiones y finalización, pero está mejorando notablemente.','NB','Seguir'),
  ('3d51eebb-e9e6-58e8-80e8-1c4b068f9585','7f059f9d-b74a-55f8-8329-e827904f8bf8','2025-12-01 07:56:14','vs Murcia','Segundo punta de estatura baja, bastante fuerte, rápido y dinámico. Se mueve entre líneas con fluidez, es inteligente para crear ocasiones y sobre todo encontrar situaciones de remate. Es un gran finalizador de jugadas.','NB',NULL),
  ('97c845db-c1c1-5a68-876a-7f1728e9c368','f6edb5fa-82cf-51c5-9d45-22cfc5c153c7','2025-12-01 13:42:37','RODA CAD. A -Primer Toque Cad. A (22/11/2025)','Lateral derecho con un perfil físico muy interesante: estatura algo por debajo de 1''80 m y complexión fuerte. Muy contundente en defensa y seguro con balón, consiguiendo incluso alguna ventaja a través del pase filtrado.','RP','Seguir'),
  ('5638d7d0-9f8a-5738-bf6d-f4e772384779','8772df7b-9d7a-5af5-b9af-22ce25998a6f','2025-12-01 13:45:10','RODA CAD. A - Primer Toque Cad. A (22/11/2025)','Central diestro con un buen perfil físico: estatura alrededor de 1''85 m, fino y largo. Es muy seguro en la acción defensiva y con balón. Transmite mucha jerarquía.','RP','Seguir'),
  ('d58bdb9b-334e-57b4-beb5-eb7a09c299f6','181872e0-7f04-5459-98a4-a2a9a698be4c','2025-12-01 13:49:55','RODA CAD. A - Primer Toquue Cad. A (22/11/2025)','Central zurdo con una estatura alrededor de 1''85 m, fino y largo. Correcto, pero algo desgarbado. Me deja alguna duda en cuanto a seguridad defensiva y con balón. Lento.','RP','Seguir'),
  ('142fb6a7-7f7e-5247-b851-2ef5c0960271','adfdf119-969f-547c-9706-cc783ce0262e','2025-12-01 13:54:46','RODA CAD. A - Primer Toque Cad. A (22/11/2025)','Lateral izquierdo con una estatura algo superior a 1''75 m y complexión delgada pero fuerte. Muy rápido en carrera. Tiene recorrido y es agresivo con balón, siempre busca progresar y desbordar cerca de área rival.','RP','Seguir'),
  ('6d70df7d-7348-5e81-90c5-f00ffabda6c4','c2263afc-5411-560a-87cd-159e982e0d47','2025-12-01 13:58:50','RODA CAD. A - Primer Toque Cad. A (22/11/2025)','Extremo diestro de estatura media. Explosivo y genera muchísimo al espacio, pero con balón en los pies le falta mucho.','RP',NULL),
  ('dcf2bcf0-9c2b-56ba-a847-0362ba2eb979','8772df7b-9d7a-5af5-b9af-22ce25998a6f','2025-12-01 15:10:32','RODA CAD. A - Algemesí Cad. A (29/11/2025)','Central diestro con un perfil físico muy bueno: estatura alrededor de 1''85 m con potencial 1''90 m y complexión delgada pero fuerte. Mucha jerarquía y calidad defensiva. Con balón tiene personalidad.','RP','Firmar'),
  ('853bba6c-f5b1-5aa3-acb3-f732c4554cb1','c2263afc-5411-560a-87cd-159e982e0d47','2025-12-01 15:13:50','RODA CAD. A - Algemesí Cad. A (29/11/2025)','Extremo diestro con un perfil físico medio: estatura menor a 1''75 m con potencial 1''77 m y complexión delgada pero atlética. Explosivo y rápido en carrera. Muy agresivo en movimientos sin balón, con desmarques constantes al espacio, y muy determinante en metros finales. Con balón le falta, pero al espacio es muy peligroso.','RP','Firmar'),
  ('6b2279b7-ef9b-59a2-993b-312155c55c94','3df7a485-5bb0-54b1-a837-aef467378d83','2025-12-01 15:17:13','RODA CAD. A - Algemesí Cad. A (29/11/2025)','Lateral izquierdo con recorrido. Perfil físico medio, estatura con potencial 1''80 m, y suficientemente fuerte para resistir duelos y con capacidad de zancada y de repetir esfuerzos. Calidad técnica para conducir y para el centro. Luego ha jugado de extremo izquierdo. Desplazamiento y golpeo top, también a balón parado.','RP','Seguir'),
  ('8322a10b-e6ab-5e66-a4a5-e1fd38d2a308','db45e113-b61d-5d57-8393-e706efd79d25','2025-12-01 15:19:44','RODA CAD. A - Algemesí Cad. A (29/11/2025)','Delantero centro diestro. Estatura potencial de 1''90 m y complexión delgada pero atlética, bastante ágil. Muy buen juego de espaldas, calidad con balón y capacidad para usar el cuerpo. Buenos movimientos y determinante en metros finales, buena toma de decisión.','RP','Seguir'),
  ('95f572fb-0677-50ed-bc4a-c40c8ddf53ac','181872e0-7f04-5459-98a4-a2a9a698be4c','2025-12-01 15:21:55','RODA CAD. A - Algemesí Cad. A (29/11/2025)','Central zurdo con una estatura potencial de más de 1''90 m, físico fuerte. Muy bien por arriba. Tiene calidad defensiva, pero le veo un punto por debajo de Izan Muñoz en liderazgo, carácter y velocidad.','RP','Seguir'),
  ('30d46cb0-cdaa-585c-bcc5-480d22ac67fc','5f402520-4031-5b23-b469-71edecb6ad62','2025-12-01 15:33:00','Roda Cad. A - ALGEMESÍ CAD. A (29/11/2025)','Extremo con perfil de mediapunta en banda. Físico ligero, con una estatura potencial de 1''75 m. Técnicamente muy bueno, sobre todo en espacios reducidos. En carrera parece que tiene velocidad punta. En la segunda parte juega de LTI.','RP','Seguir'),
  ('55eadad4-f95a-5bc6-9503-f8fba60ba578','22812024-5df3-500b-9dd9-cb1a5ca09534','2025-12-01 15:36:36','Roda Cad. A - ALGEMESÍ CAD. A (29/11/2025)','Delantero centro diestro con un perfil físico interesante: estatura potencial +1''90 m y aspecto delgado pero fuerte. Quizás algo lento. Bien en duelos, chocando y siendo capaz de jugar de espaldas.','RP','Seguir'),
  ('2f75b8bd-535c-530d-a012-08075bac3afc','157b01d4-593f-57fb-ba64-c006483f74ab','2025-12-01 15:40:39','Roda Cad. A - ALGEMESÍ CAD. A (29/11/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior. Estatura potencial 1''80 m, complexión delgada. Buena calidad técnica y visión de juego.','RP','Seguir'),
  ('f0296ed2-3362-5599-a182-2ea589a6df6e','7c9b4d1d-6fd0-59d6-a308-9d8e99455e28','2025-12-01 15:59:12','ELCHE B - Sanse (29/11/2025)','Delantero centro zurdo con un perfil físico interesante: estatura algo inferior a 1''85 m y complexión delgada pero fuerte. Calidad técnica para controles y descargas y bastante potente para proteger el balón y resistir choques.','RP','Seguir'),
  ('f4f3ab9d-b1ae-5382-ac46-0334541ed6ca','79d3f9f1-8d4b-54dc-88f1-3e04b4ad063d','2025-12-01 16:18:26','ELCHE B - Sanse (29/11/2025)','Central zurdo. Estatura alrededor de 1''85 m y complexión fuerte. Bastante correcto tanto en acciones defensivas como con balón, aunque sin mostrarse especialmente dominante. Rápido en carrera.','RP','Seguir'),
  ('1c5d68ae-5e78-5b5b-baad-354733edec3c','badf773d-29aa-5f21-a33c-d969f8db271b','2025-12-01 16:20:56','ELCHE B - Sanse (29/11/2025)','Centrocampista diestro de segunda/tercera altura estilo mediapunta, en el partido actuando en un doble pivote. Tiene mucha calidad, visión de juego y ritmo. Muy habilidoso para manejar el balón y escapar de marcas, pero me cuesta verlo por perfil físico y táctico.','RP','Seguir'),
  ('72092d66-81c1-56a8-a0e4-c9e03c4e0a1e','7f324ffc-c2a8-51ac-8dbe-095f0954b364','2025-12-01 16:24:40','Eldense - ANTEQUERA (29/11/2025)','Centrocampista zurdo box to box. Fuerte físicamente, con mucho recorrido y un grado de participación muy alto en muchas zonas del campo. Trato de balón sobresaliente, bueno defensivamente y con llegada. En el partido ha marcado dos goles jugando de pivote. Gran disparo desde la frontal.','RP','Seguir'),
  ('4a0834ef-d15e-5beb-ac52-927df3ef638d','5ee8a63e-d5b9-53d4-b349-9b25c76fcf56','2025-12-01 16:26:26','CASTELLÓN JUV. A - Elche Juv. A (30/11/2025)','Central zurdo. Físico interesante: 1''85 m de estatura y complexión fuerte, aunque con margen de mejora en cuanto a contundencia. Correcto en acciones defensivas y con balón, quizás le falta algo de activación','RP','Seguir'),
  ('245656f9-8021-57e2-9088-f4f76859acb7','fe26fc32-7830-56d4-8413-5f741d4ce9c6','2025-12-01 16:28:18','CASTELLÓN JUV. A - Elche Juv. A (30/11/2025)','Carrilero izquierdo con un perfil físico máso menos interesante: estatura algo inferior a 1''85 m y complexión delgada, pero fuerte para duelos. Aunque no parece muy rápido, es ágil y tiene capacidad de recorrido. Bien defensivamente y con balón. Atrevido para el 1vs1. Ha terminado de central izquierdo.','RP','Seguir'),
  ('e90bdeb4-35c5-544f-8756-ea642697f8a7','a5afff44-b856-525f-b12f-9232dd9f1827','2025-12-01 16:30:55','CASTELLÓN JUV. A - Elche Juv. A (30/11/2025)','Centrocampista diestro de primera/segunda altura. Estatura alrededor de 1''80 m, complexión fuerte. Mucha calidad técnica, bastante criterio y ritmo de juego alto. También tiene recorrido, siendo capaz de hacer progresar la jugada desde el primer pase hasta el último. Buen golpeo desde fuera del área, también a balón parado.','RP','Seguir'),
  ('7f4844e5-5f3a-5f10-9176-166d7ec3cc0e','31057f9e-7b4d-5d72-b3fb-9eb831bb98b3','2025-12-01 16:33:50','Castellón Juv. A - ELCHE JUV. A (30/11/2025)','Atacante diestro, en el partido actuando como delantero centro. Estatura algo superior a 1''70 m, pero físico fuerte capaz de resistir choques. Potente en carrera, explosivo para arrancar. Buena técnica y habilidoso para desbordar. Agresivo yendo al espacio.','RP','Seguir'),
  ('7c0305a1-4812-5d28-a216-e7cc0752b2a2','c317723e-a2b2-5739-bfca-baffe376e719','2025-12-01 16:39:32','Castellón Juv. A - ELCHE JUV. A (30/11/2025)','Central diestro de estatura superior a  1''85 m y físico fuerte. Dominante en el juego aéreo. Técnica correcta y un desplazamiento largo interesante.','RP','Seguir'),
  ('55dcf21b-0ead-5eb4-ab34-e35f12aa5bcf','9f4b0d38-32d0-54d6-bf80-5cdb6690c30d','2025-12-01 16:47:08','Castellón Juv. A - ELCHE JUV. A (30/11/2025)','Carrilero zurdo de estatura media y complexión delgada, pero ágil y con mucho recorrido. Calidad técnica y agresivo con balón en el último tercio, con capacidad de desbordar y de ir al espacio. Ha marcado un golazo con un disparo potente arriba. Está entrando en el Ilicitano.','RP','Seguir'),
  ('5fbda3c5-bfe9-54c9-8bab-12fada6625b6','93a33854-d3c6-5709-8a6e-747de7f13f8f','2025-12-01 19:19:06','vs Sevilla','Emmanuel: Central izquierdo de buen biotipo físico. Estatura cercana al 1.87 m, de complexión delgada aunque fuerte, es rápido y ágil en carrera, muy potente. En defensa es especialmente agresivo, va fuerte al duelo, proactivo para salir de zona. Se nota crecimiento en timing y elección en acciones defensivas. Con balón juega hacia adelante, busca superar líneas con pases y conducciones. Firmar.','NB','Firmar'),
  ('a2a4fa16-a88f-5310-a3f9-acb0b91cded9','210c5a49-0821-533e-b4f3-9f20e801d45e','2025-12-01 19:21:29','vs Sevilla','Miguel Romero: #6 de físico mediano en estatura, fuerza, velocidad…destacando por recorrido. Es un centrocampista con buen posicionamiento, capacidad de recuperación, ganador de duelos, difícil de superar en 1v1. Tiene buena técnica individual, capaz de liderar salida de balón y sumarse a ataque. Buen desplazamiento en largo y recursos para resolver en espacios cortos.','NB','Seguir'),
  ('cee72bc9-a852-56b4-9008-f55aa483a51b','28bf4078-9dd0-5241-b6a5-fb7fdd6444ba','2025-12-01 19:22:07','vs Sevilla','Iván Corralejo: Mediapunta de físico discreto (estatura baja, delgado, con margen de mejora en cuanto a potencia y musculatura, con bastante recorrido y capacidad para repetir esfuerzos). Nivel técnico alto, gran dominio de balón, hábil en espacios cortos. Puede ganar metros en conducción con facilidad y llegar a último tercio. Debe crecer notablemente en toma de decisiones, que lo llevan a ser menos productivo de lo que debería. En defensa es intenso y trabajador, aunque no consigue imponerse con regularidad debido a su físico.','NB',NULL),
  ('19b8be78-fdcf-581c-b333-31114160b7b8','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2025-12-01 19:22:49','vs Sevilla','José Morante: Extremo zurdo, juega por ambas bandas. Biotipo ideal para posición, con estatura +1.80, piernas largas, velocidad y agilidad. Complexión delgada, aunque con musculatura. Jugador con recursos para generar ocasiones tanto en espacios largos (diferencial en conducción y desmarques al espacio), como en corto (tiene buen repertorio para el regate). Gran golpeo de zurda para finalizar con remate y centros. Trabajador en fase defensiva. Jugador absolutamente diferencial, potencial de máximo nivel. Hacer esfuerzo especial por él. Firmar.','NB','Firmar'),
  ('528f41fe-9a1e-501f-84e5-0e4ce9b38d0a','24c4c209-23ba-575f-81b3-4b766b1182cc','2025-12-01 19:23:30','vs Sevilla','Rubén de Sá: Extremo, después delantero. En mi opinión mejor por dentro, como segundo punta o más atrasado incluso. Jugador de buen perfil físico (estatura media, delgado, fuerte, rápido, con recorrido). Tiene buen golpeo, es vertical en su juego, llegada al área con frecuencia, con buen nivel técnico. Sacrificado en fase defensiva.','NB','Seguir'),
  ('22e219ec-cf4e-5fd9-b2ee-dfa350070c8a','6dd78885-4fa5-5394-82df-e9e749d3be94','2025-12-01 19:24:02','vs Sevilla','Mario Navarro: Lateral derecho de perfil físico medio, destacando por velocidad y recorrido. Vocación ofensiva, con recursos para asociarse y también desequilibrar por su cuenta. Tiene criterio para elegir en último tercio, buen centrador. Es sólido en defensa, destacando por su buen trabajo en transiciones y en duelos 1v1. Firmar.','NB','Firmar'),
  ('09eeea7b-c6a6-5e91-80b3-1da8369815e5','23913533-4f13-5f12-ac06-3c4c9b9a4102','2025-12-01 19:24:44','vs Betis','Jesús Cruz: Centrocampista de buen perfil físico (+1.80, ágil, veloz de movimientos y en carrera, con recorrido). Antes era extremo, por lo que tiene nivel técnico alto para ganar metros en conducción y revolverse de forma individual. Menos asociativo, más vertical en acciones. Intenso aunque menos efectivo en fase defensiva, donde aún debe crecer.','NB','Seguir'),
  ('823458fe-db75-5c57-9bb8-fb7de5bd688c','43479982-bcdd-5184-b814-a84af3ab5dba','2025-12-01 19:26:50','vs Betis','Mario Díaz: como #6 no me convence tanto, ya que a campo abierto sufre porque no es un jugador especialmente veloz ni ágil. Tiene planta top, cercano al 1.90 m, coordinado. Con buena salida de balón y conceptos defensivos.','NB','Seguir'),
  ('4ef0d354-22d5-5392-9658-df778786019a','52708d44-ddc3-508d-933e-741094c91c42','2025-12-01 19:33:01','vs Tarazona','Tounkara: Centrocampista de buen perfil físico (estatura aprox 1.80 m, robusto, fuerte de tren inferior y superior, bien de agilidad y velocidad, también ritmo). Con balón es vertical, sorprende por su capacidad de llegada a último tercio. Tiene recursos en el 1v1, busca desequilibrar. Irregular a nivel técnico, falla controles, pases que no debería. Intenso en defensa, con recorrido, fuerte en presión y yendo al duelo.','NB','Firmar'),
  ('72374421-790b-57f3-a293-08182ef03e6c','2fefe7f2-8d94-5858-b4e5-ca26071d7dcf','2025-12-02 16:27:45',NULL,'Extremo diestro de buen perfil físico: estatura media-baja, musculatura desarrollada, robusto, rápido, con aceleración, explosivo en carrera. Jugador de gran capacidad para llegar a área rival y generar ocasiones, para él y sus compañeros. Es hábil para el regate, vertical para desequilibrio. Trabajador en fase defensiva, con recorrido y activo en presión.','NB','Firmar'),
  ('c4de234d-d4c6-5a7e-9c60-9cd5628f580a','5a699f12-9c85-5a2d-9887-111d57a35bda','2025-12-02 16:35:02',NULL,'Adrián Guerrero es extremo de gran biotipo: estatura +1.85 m, fuerte, veloz en carrera, aunque no explosivo. Jugador con recorrido y trabajo defensivo. Tiene capacidad para llegar a último tercio y centrar/asistir, es vertical en acciones. Le falta mayor creatividad en regate y desequilibrio individual. Es perfil con potencial primer equipo Deportivo la próxima temporada.','NB','Firmar'),
  ('22894027-d788-5d23-bc65-0fee6ee300e4','7ea1f858-0b8c-52ef-b4ed-0396cde2fe94','2025-12-02 16:42:26',NULL,'Centrocampista #8 de perfil físico promedio (estatura media, sin ser especialmente fuerte, con recorrido y capacidad para repetir esfuerzos). Jugador de nivel técnico alto, que destaca organizando juego y llegando a último tercio. Tiene recursos en 1v1 y superando líneas de presión en espacios reducidos. Es activo en presión e intenso para afrontar duelos individuales, sin ser tan ganador.','NB','Firmar'),
  ('a0a13363-e7ff-55f6-a1bc-c4f2c416fd4a','8d28c04f-5a27-5811-a090-c99579483f53','2025-12-02 17:05:56','vs Real Sociedad B','Carrilero de condiciones físicas muy positivas para posición: estatura media, muy potente, con musculatura desarrollada, veloz y ágil, con capacidad para repetir esfuerzos de alta intensidad. Es vertical en sus acciones, llega bien a línea de fondo para centrar. Aceptable a nivel técnico, sin destacar por ser jugador demasiado asociativo ni creativo en regate. Intenso en fase defensiva.','NB','Firmar'),
  ('6bedc7b5-cb48-52e9-b911-f9a79ba2336a','589cc61e-e55e-5a40-a4a6-d58e0bb60784','2025-12-02 17:19:53',NULL,'Centrocampista perfil #6 - #8 de físico medio en cuanto a estatura, potencia, ritmo. En mi opinión su mayor punto de mejora, y lo que va a condicionar su potencial. Jugador de nivel técnico alto para manejar juego asociativo de su equipo y desenvolverse en espacios reducidos, sin tanta llegada a último tercio. Activo en presión, con bastante recorrido, buen recuperador.','NB','Firmar'),
  ('ad723437-9d48-51ee-bc87-64c448d9fbac','e9899013-e914-59e9-8f4e-d5f820ffe8b7','2025-12-02 17:30:55','vs Leganés','Mediocentro de perfil físico medio: estatura media-baja, robusto, con recorrido. Poco impacto en juego en tiempo jugado.','NB',NULL),
  ('0463549e-caac-5923-ad69-5abb7ff9b79f','692f988b-e163-5ba1-9a67-a78b20f4c670','2025-12-02 17:40:29','vs Zaragoza','Debut en Segunda. Central izquierdo de buen biotipo físico (estatura media para posición, muy fuerte, veloz, ágil).  Poco preciso en entregas, aunque con intenciones de jugar hacia adelante y progresar. Con balón es agresivo para afrontar duelos y defender hacia adelante. Condiciones interesantes.','NB','Seguir'),
  ('24a42694-c790-5e7e-a9cd-d796645ca553','9b1cee6d-548f-5ec8-a654-0668502e1978','2025-12-02 18:00:25','vs Valladolid','Delantero centro de perfil físico ok: estatura cercana al 1.85 m, delgado, con apariencia de poco potente. Buena velocidad en carrera para explotar espacio. Destaca por capacidad de remate y movimientos en área. Fuera es activo en movimientos aún sin tener gran impacto en juego. Rendimiento normal en fase defensiva, sin destacar.','NB','Seguir'),
  ('a2c5d15d-ca29-5f62-adc2-9ca88daed1e6','d24eb8f3-cf61-5823-b1ca-dced3558ea4e','2025-12-02 21:20:05','vs Elche','Extremo diestro. Buena tipología física: estatura media-alta para posición, delgado, con piernas largas, aún por hacer en cuanto a musculatura. Es rápido, aunque no explosivo. Tiene buen golpeo de derecha, capacidad para generar ocasiones y terminarlas.','NB','Seguir'),
  ('dbbc4295-ce16-5ef7-a6e3-ae9e2ae6d9c9','c2910e39-576f-5d41-857f-bbb131c1e84c','2025-12-03 11:36:54','vs Real Madrid C','Delantero centro de buen prototipo físico: espigado, delgado, ágil. Juega fuera del área, va al choque, busca atacar espacios. Ver más.','NB','Seguir'),
  ('e1b5584d-b372-5c9a-8bc4-b5256e5061d0','64c162b1-75d3-5f34-9a00-1939664d085d','2025-12-03 11:39:34','vs Tenerife B','Delantero centro grande, fuerte, da sensación de algo tosco y poco veloz para atacar espacio. Juega de espaldas, sin tener gran capacidad asociativa. Destaca por juego cerca de área, donde tiene recusos para finalizar.','NB',NULL),
  ('8368fcdb-5f77-5664-b384-397fbd4dcc93','9c574cc8-96cf-5e6e-bf51-042c110fcc05','2025-12-03 11:41:32','vs Tenerife B','Se nota que al subir de nivel le falta mayor poderío/ritmo para marcar diferencias como lo hace en Juv DH.','NB',NULL),
  ('2d65af80-418d-5ecc-8c02-bc0beeafad03','b2d2d960-1d92-5431-abb6-7f3e1100dbfe','2025-12-03 11:52:57',NULL,'Centrocampista de prototipo físico normal (estatura ok, delgado, por hacer físicamente). Pocos minutos, estar atentos a si juega más.','NB','Seguir'),
  ('4598e350-f98c-589b-a84e-7d9e2339aa35','ef45a286-0b39-5765-9f54-fec8cd1b2637','2025-12-03 12:04:33','vs Estepona','Jugador al que estar atento por edad, ver si tiene más minutos. En principio no es interesante. Físico mejorable: estatura media, robusto, no da sensación de rápido. Se nota que tiene descaro y personalidad, activo en tiempo de juego.','NB',NULL),
  ('38a90a1c-35c5-5c67-a05e-eba4d694ceb2','385bd0c6-e2db-5f3e-a000-8d5ba4d12bec','2025-12-03 12:56:21','vs Olot','Entra desde banquillo. Extremo de buen perfil físico, encarador, desequilibrante en 1v1, con capacidad para marcar diferencias en espacios largos y cortos. Me sorprende su poca continuidad.','NB','Seguir'),
  ('6d81bdcf-f4a1-5d1c-8ba7-b583555475d6','49659dce-be7a-56c0-be43-2b716f5c1560','2025-12-03 13:19:19',NULL,'Extremo zurdo, de baja estatura. Poco impacto en partidos vistos.','NB',NULL),
  ('aef830ea-68ae-5426-855a-a15f1bebf437','0b38981f-afa3-5d14-b84a-f21ab09649dc','2025-12-03 13:41:23',NULL,'Extremo diestro de buen perfil físico: estatura media-alta, veloz, delgado. Es agresivo para buscar 1v1, con recursos para el regate. Encarador.','NB','Seguir'),
  ('53405ef6-edc3-5c67-838f-c2e2e3c62689','545a11e8-867a-58c9-b09a-744d73765daf','2025-12-03 22:58:19','vs Eldense','Extremo de perfil físico muy bueno para posición: alto, potente, veloz, con zancada larga y aceleración. Es jugador con recursos para desequilibrar en 1v1, sobre todo en espacios largos. Jugador diferencial.','NB','Firmar'),
  ('1097ff9c-6661-56c4-81f7-317f81831bf3','40a9d6d4-4c4f-5c53-b60f-aaa207cd88d2','2025-12-03 23:00:47','vs Almería','Extremo zurdo, de físico poco llamativo (bajo, no es potente, da sensación de poco estético, bien de velocidad sin ser explosivo). Genera desequilibrio en 1v1, capaz de crear ocasiones y de finalizar con éxito. Poco trabajador en fase defensiva, sin gran recorrido.','NB',NULL),
  ('b862e18b-249f-52c2-babf-b7ea193bd0db','cb45f736-b8f8-5958-a2b0-ef7281ea0e0d','2025-12-04 14:09:34','vs Marino de Luanco','Central diestro, juega por izquierda. Buen perfil físico, se le ve agresivo para afrontar duelos individuales, sin destacar en salida de balón. Ver más.','NB','Seguir'),
  ('20f4752d-fbdb-58ae-9f23-917cdb2027e4','87b3182f-c4ec-5424-a939-b1abbdb2be80','2025-12-04 14:22:32','vs Navalcarnero','Juega de lateral derecho, pese a ser zurdo. Es futbolista de físico medio: estatura media, complexión delgada, ágil, con recorrido, velocidad normal. Perfil ofensivo, hábil en el 1v1, con llegada área rival. Es agresivo para afrontar duelos y anticipar.','NB','Seguir'),
  ('0dfddd6c-0b00-50d0-b221-bface7a5b92e','055c217d-3353-5ddb-987d-da797beec0e5','2025-12-04 14:28:20',NULL,'Mal perfil físico para posición.','NB','Descartar'),
  ('7d93ef0f-1a8f-5d1a-b25b-c081b9b68f22','797878b8-bbd7-5a02-826d-1be038fa9978','2025-12-04 14:33:18','vs Olympiacos','Extremo por derecha. Perfil físico discreto, en cuanto a estatura, potencia, aceleración, recorrido. Su mayor virtud es la habilidad en 1v1, tiene recursos para superar en regate, sobre todo en corto. Le falta crecer en toma de decisiones y finalización. Siendo último año debería ser más determinante.','NB',NULL),
  ('f95c8203-e31e-5b40-9367-874ff7543cb4','8676ebcf-4bfd-5b76-b6a3-a3b736b98119','2025-12-04 17:34:52','vs Inter','Lateral derecho de biotipo físico medio: estatura mediana, robusto, de sensación de poco margen de crecimiento en este sentido. Es rápido, ágil, con aceleración y capacidad para repetir esfuerzos. Vocación ofensiva, con recursos para desequilibrar individualmente y criterio en último tercio. Es aplicado en fase defensiva, aunque puede mejorar.','NB','Firmar'),
  ('d4ac54c4-2e52-5cfd-bda0-127f1c22bda3','ee95d406-7197-509b-87da-be6b579a870d','2025-12-04 17:37:28','vs Inter','Central de biotipo físico ideal, con condiciones actuales y potencial de élite total.','NB','Firmar'),
  ('56cab0c4-c683-5a51-9818-2175107ae6f0','1a9b560f-ee3a-55bb-b7f4-8839d737ab88','2025-12-04 17:38:56','vs Inter','Lateral izquierdo que se nota que es central reconvertido. No destaca por perfil físico ni tampoco en resto de aspectos.','NB',NULL),
  ('add92ef2-d27f-5d6b-82aa-cee8b668e753','21653fd6-393c-502f-82be-2bd9c03c0e22','2025-12-04 17:39:47','vs Inter','Juega de #10. Estatura baja, perfil físico discreto. No lo veo generando impacto','NB',NULL),
  ('27653e4e-2750-581f-b256-cc0a1ee6cb89','54bb0d77-9628-5dae-b122-017a84d5da8d','2025-12-04 17:40:42','vs Inter','#6 de estatura aprox. 1.90, buena complexión física, bien construido y compensado. Delgado pero fuerte. Es lento y le cuesta aceleración en primeros metros. Jugador posicional, que en juego asociativo da continuidad y juega fácil, sin progresar con balón ni acercarse a área rival. Es inteligente para abarcar, recuperar y dar equilibrio, sin ser tan agresivo en duelos/choques.','NB','Seguir')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('b6a3b057-e519-5e31-b956-3cf1bfa66349','e17cc547-8e49-5175-b7e0-8a7cb266b528','2025-12-04 17:42:53','vs Inter','Jugador de estatura baja, delgado, poco poderoso, rápido, con aceleración. Perfil físico normal para posición, sin destaca. Genera desequilibrio en 1v1, y sobre todo tiene buena llegada a área para finalizar con remate propio.','NB','Seguir'),
  ('23f6ad40-59ae-5ee5-bf56-ab01842ed8f8','a8b7da47-5ec1-5310-917c-208b2f9fccde','2025-12-04 17:44:11',NULL,'Extremo de estatura baja, delgado, rápido y explosivo. Jugador ágil y dinámico, muy móvil. Tiene desequilibrio individual en 1v1, genera ocasiones por sí solo, llega con facilidad a área rival.','NB','Seguir'),
  ('a0ae6051-71b6-5657-a712-15205ecccc01','38dbdc1c-ce71-52f5-a959-100857cb5398','2025-12-05 12:10:53','vs Atlético','Lateral izquierdo de estatura baja, no poderoso, delgado, muy veloz y explosivo, con recorrido. Perfil Dani Muñoz. Llega con peligro a ataque, con recursos para asociarse y generar. Le falta más en defensa.','NB',NULL),
  ('e9d0a0b8-475e-5d56-8d3f-825e09ba3513','38bed638-5f1b-5460-9a41-a11070614fae','2025-12-05 12:12:51','vs Atlético','Central izquierdo de biotipo excelente para posición: estatura cercana a 1.85 m, de complexión robusta, fuerte de arriba y abajo, con buena velocidad/agilidad. Adaptable a lateral izquierdo. Sólido en acciones defensivas, agresivo para salir de zona y anticipar. Con buena salida de balón, capacidad para ganar metros en conducción y meter pases por dentro.','NB','Firmar'),
  ('d2aa113a-94dc-5c65-b5eb-358685ecabf3','7afa15e2-9645-5983-8c5e-8f77ec38438f','2025-12-05 12:14:43','vs Atlético','Central de biotipo físico top: incluso más alto que Fran Asier, con mayor margen de crecimiento en cuanto a musculatura, velocidad ok sin ser especialmente destacado. Se muestra sólido en acciones defensivas y juega hacia adelante.','NB','Seguir'),
  ('d3b0a8e2-4b56-5edf-af76-d78255a3fced','e7c82991-587b-5d87-bd8b-f58d14e9a2d5','2025-12-05 12:19:06','vs Atlético','Extremo de buen prototipo físico para la posición: estatura media-baja, delgado, con musculatura/potencia por hacer.  Es muy rápido y explosivo, con gran capacidad de aceleración. Jugador muy dinámico, agresivo, vertical para buscar situaciones de 1v1, con repertorio en regate y llegada a área.','NB','Firmar'),
  ('6f900356-f647-5155-97ba-fb71e63c166f','fb3317a6-b2cf-56ae-86a1-ad0b1ccb5be4','2025-12-05 12:21:58','vs Atlético','Delantero centro de buen perfil físico: estatura alta, delgado, con margen de crecimiento físico. Juega bien fuera del área, técnica correcta para asociarse. Menos presencia en área en este partido.','NB','Seguir'),
  ('e5c586e4-0a05-5125-8b09-ac1b4b122e55','e720e61f-c858-5e6c-8c72-bb6681991d72','2025-12-05 12:24:03','vs Real Madrid Cad A','Central diestro de buen perfil físico y nivel técnico positivo, agresivo en fase defensiva. Sensaciones positivas, me gustaría ver más.','NB','Seguir'),
  ('8c93c6b3-3126-5b02-99af-d56644fcdeeb','8bcc6303-af49-5a2a-a3f9-2aaee5875939','2025-12-05 12:27:05','vs Real Madrid Cad A','Central de físico top para posición: alto, delgado aunque fuerte, con margen de crecimiento en potencia. Tiene buen pie para sacar balón y romper líneas de pase, también ganar metros en conducción. Fuerte en fase defensiva, puede defender hacia atrás y hacia adelante. Potencial alto.','NB','Firmar'),
  ('6de10468-b76d-5ea8-86e6-9030760e255a','0a095877-e0df-5ece-81ed-0e6aa05af6ac','2025-12-05 12:28:38','vs Real Madrid Cad A','Extremo que genera poco impacto en partido. Se quedó físicamente, se nota porque cada vez marca menos diferencias.','NB',NULL),
  ('b3d19851-9fcc-53de-be53-d4d4091887ac','3d33d5f9-88a1-5da7-a047-bf7943d9691a','2025-12-05 12:30:40','vs Real Madrid Cad A','Delantero centro/segundo punta de buena estatura, con margen de crecimiento en cuanto a musculatura/potencia. Es jugador dinámico, de buen nivel técnico, presencia fuera del área jugando de espaldas y asociándose. Menos actividad en área.','NB','Seguir'),
  ('a9ec41af-908c-564b-b93a-926e8bdd376f','81a41bb7-02e4-5c9a-933c-0decedba6c05','2025-12-05 12:33:10','vs Atlético Cad A','Centrocampista #8 de físico top para posición: estatura cercana al 1.90 m, fuerte, de buen ritmo, igual algo lento en corto. Es buen recuperador, intenso en presión, con movilidad. Vertical con juego hacia adelante, muy potente en carrera, con llegada a último tercio.','NB','Firmar'),
  ('81aa861a-0503-5d02-a5ea-1865a3bc0d94','1b35dbe4-1e7a-5e19-a536-89f694f20083','2025-12-05 13:17:34','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Lateral derecho de estatura medio-baja. Buena técnica y bastante presencia en ataque, pero no he visto nada especial.','RP',NULL),
  ('be167ce0-b48c-5fab-9206-d2fef1449407','de72106d-f624-52ef-b0e4-dcab76c61597','2025-12-05 13:19:20','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Lateral izquierdo de estatura medio-baja. Muy buenas condiciones técnicas y muy participativo en ataque, sobre todo en el tercio final. Combina bien con los compañeros y es capaz de generar situaciones de peligro desde la banda.','RP',NULL),
  ('a3b5e817-13da-54a9-9cec-666d9c4da9bd','d0b0577d-baa1-5a77-b86b-e9127670c505','2025-12-05 13:22:49','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Central diestro de estatura alrededor a 1''85 m y complexión fuerte. Rápido, con buena capacidad de defender a campo abierto y un timing muy bueno para ir al suelo. También tiene buenas vigilancias en el área, con un alto nivel de activación y de velocidad de reacción. Con balón es correcto, en el partido no genera demasiadas ventajas.','RP','Firmar'),
  ('d07f8728-bcb9-539b-9fe1-884e43a4a4ea','1c4dc383-b594-5dab-98ef-97d420b7956c','2025-12-05 13:27:58','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Central zurdo de estatura cercana a 1''90 m y complexión fuerte. No tiene el mejor partido, pero tiene unas condiciones top, tanto defensivas como con balón.','RP','Firmar'),
  ('b9588086-d97f-5999-b396-731e99585b49','08f9ed00-d179-5da4-93c6-a334a0527252','2025-12-05 13:29:00','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Extremo diestro actuando en banda izquierda. Estatura baja, pero es duro para soportar cargas. Técnicamente es excelente, con un gran dominio de balón para conducir y buscar último pase. Muy agresivo en la toma de decisión en el último tercio. Me genera algo de dudas su físico.','RP','Seguir'),
  ('9d83ff58-30eb-5ed0-913e-256dc9636b77','0f9524f1-078a-5dea-b022-6c87ee4a7186','2025-12-05 13:30:52','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Centrocampista de segunda altura, aunque con capacidad de intervenir en todas las fases desde la construcción al último pase. Perfil físico medio-bajo en cuanto a estatura y complexión. Técnicamente notable y con una gran capacidad de giro. Ritmo de juego alto.','RP','Seguir'),
  ('88c3cb45-b088-5a32-a0ac-cd43be18ff29','6d230e2b-b0c7-57a2-8d2d-5ef2ab5a3aa3','2025-12-05 13:34:15','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Delantero centro con un perfil físico excelente: estatura cercana a 1''90 m, complexión atlética y buena zancada. Con balón ejecuta bien y tiene mucho instinto para moverse en el último tercio, sobre todo cuando su equipo ataca en carrera.','RP','Firmar'),
  ('67e4efba-d47c-5f6c-a1cd-4361a7d17c14','b0859051-f157-5bc5-bfa4-1e7375ea7ec4','2025-12-05 13:35:38','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Extremo zurdo, en el partido actuando en banda derecha. Perfil físico medio-bajo en cuanto a estatura y complexión. Gran dominio del balón y buena diagonal para buscar último pase o disparo, pero me cuesta verle siendo determinante en División de Honor.','RP',NULL),
  ('fd2adc43-72b5-5737-a849-5315c3a7dd52','5ac693e1-ede7-5532-846f-531665308edc','2025-12-05 13:37:26','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Centrocampista diestro de segunda/tercera altura para actuar como interior o mediapunta, acelerando jugadas. Perfil físico medio-alto en cuanto a estatura y complexión. Gran nivel técnico y buena llegada al área rival.','RP','Seguir'),
  ('0f9fd35d-cdc2-5b69-83c9-0755235094db','fc6cee27-b26e-5ee7-8272-8146ffb74520','2025-12-05 13:40:49','REAL MADRID JUV. B - Getafe Juv. B (29/11/2025)','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Perfil físico medio en cuanto a estatura, pero con una complexión fuerte y con potencial de mejora. Muy explosivo tanto para saltar a anticipar como para escapar de marcas con balón. Buen nivel técnico y criterio, bastante agresivo en la toma de decisión.','RP','Firmar'),
  ('a60905cc-6ae8-5c5d-9ecc-1f4f653c875e','d0c7a319-57d8-54e5-a7c8-7a155c2eda32','2025-12-05 13:46:08','Real Madrid Juv. B - GETAFE JUV. B (29/11/2025)','Central diestro con una estatura algo inferior a 1''85 m y complexión fuerte. Bueno en la defensa del área, con un nivel de activación bastante alto. Correcto con balón.','RP','Seguir'),
  ('022bc406-655d-55c3-bfc1-555ef8707cf4','5a61cb51-0c2b-56b9-8d0c-10551701c7fe','2025-12-05 13:52:04','Real Madrid Juv. B - GETAFE JUV. B (29/11/2025)','Central diestro con una estatura cercana a 1''90 m y complexión fuerte. Tiene buena zancada, gana bastante por arriba y en el partido deja algunas acciones de defensa de área de mucho nivel. Con balón no destaca.','RP','Seguir'),
  ('09dda040-893d-5cdd-bada-7bd1f75a7f2c','854840c7-6245-5f9b-8133-d9a29a0adef7','2025-12-05 13:53:37','Real Madrid Juv. B - GETAFE JUV. B (29/11/2025)','Delantero centro diestro con un perfil físico sobresaliente: estatura superior a 1''85 m, complexión fuerte y potente tanto en carrera como en duelos. En el partido tiene algunas buenas acciones de descarga con balón y se mueve bien pese a tener un partido complicado.','RP','Seguir'),
  ('b930c7d7-7c25-5bcb-90fc-f5855fa92688','a19737d0-2122-540f-b016-8b595505e959','2025-12-05 13:54:36','vs Damm Juv B','Lateral izquierdo de perfil físico discreto (estatura baja, delgado, poco poderoso, veloz en carrera aunque da sensación de que le cuesta arrancar. No destaca especialmente en nada.','NB',NULL),
  ('e34650a8-0692-5e7c-8989-88c4d2e3f002','84494212-3a7a-59c7-837f-8c1d83b414a6','2025-12-05 13:59:51','vs Damm Juv B','Extremo de físico ligero: estatura media, delgado, veloz, explosivo. Lo veo bastante hecho. Deja acciones interesantes en 1v1 y conducción. No le veo mucho más potencial de lo que es actualmente. Puede ir a cantera profesional pero no lo veo llegando.','NB',NULL),
  ('00c1b46d-6a96-54db-b090-35794c83d05f','73ba7f76-d8be-5bf3-9b8e-35c012e67aca','2025-12-05 14:04:14','vs Olot Juv B','delantero centro de perfil físico medio: estatura media-alta, fuerte, no es rápido en carrera ni tiene gran aceleración para atacar espacios. Es activo para jugar de espaldas y poco más.','NB',NULL),
  ('c776b609-1a49-5558-80b0-70260a24f895','c058cc00-b874-53d4-a2c0-2a7e250d78af','2025-12-05 15:14:51','vs Torremolinos','Es extremo de impacto reducido en cuanto a cantidad de acciones, pero que es capaz de generar ocasiones para él y sus compañeros gracias a su desequilibrio individual y buen golpeo. Me genera dudas su capacidad para adaptarse a niveles más altos por físico (debe dar paso adelante en este sentido).','NB','Seguir'),
  ('05d404a6-e723-5482-9bf3-23269dbad4d5','75534b8e-ae28-50e9-ab07-55eaa003ea3a','2025-12-05 15:16:53','vs Villarreal B','Me parece un perfil de #8 muy interesante por condiciones físicas, capacidad de presión adelantada, intensidad en su juego. Con balón supera líneas de presión en conducción, llega a último tercio con frecuencia.','NB','Firmar'),
  ('eb82004f-dddb-50cd-a74c-20ce391bfbfb','fe0497d4-3c16-56ca-bcf3-aa9b6ef1f322','2025-12-05 15:38:11',NULL,'Extremo de estatura baja, fuerte, de complexión robusta, rápido, con aceleración en carrera. Genera en conducción y llega al área. Ver más.','NB','Seguir'),
  ('78650332-fc0c-5ee6-984c-d5c37d5f65f4','f65ab97a-9d3a-5d08-a0af-01ce64f3d8d9','2025-12-05 15:48:02','vs Ponferradina','Jugador de zona interior, que se mueve bien, es hábil y tiene capacidad para crear ocasiones. Participa en los dos goles y genera expulsión. Perfil físico medio.','NB',NULL),
  ('b20e710b-eac7-5056-81a3-a1c77203fbe9','3d05e0cf-3610-5ede-951f-307358b825bd','2025-12-05 15:57:34','VALLADOLID B - Coruxo (30/11/2025)','Central diestro con un perfil físico medio para la posición. Transmite sensaciones de liderazgo en el equipo, pero no tiene nivel ni potencial top','RP','Descartar'),
  ('b2ea7bf5-eb79-588f-a15d-71c2fe55ab70','a95b33ee-832e-567d-bade-531e8c222445','2025-12-05 15:58:44','VALLADOLID B - Coruxo (30/11/2025)','Lateral izquierdo con una estatura algo superior a 1''80 my complexión fuerte. Tiene un partido horrible, pero por lo visto anteriormente creo que puede tener condiciones interesantes para la posición.','RP',NULL),
  ('4a66ef7d-2928-5ffc-8a5c-461e04935e0c','b48324ea-28c9-5df9-8266-86a257ae5b0c','2025-12-05 15:59:45','VALLADOLID B - Coruxo (30/11/2025)','Central diestro con un perfil físico medio para la posición. Poco nivel en general.','RP','Descartar'),
  ('1dfa5054-ba28-5056-8ec9-c7b7b372dc40','c2c01031-911a-573b-a6a5-6b26dd17452b','2025-12-05 16:01:00','VALLADOLID B - Coruxo (30/11/2025)','Delantero centro diestro con una estatura quizás algo superior a 1''80 m y complexión fuerte, aunque me deja algo de dudas en cuanto a peso. Tiene mucha personalidad y es inteligente para intentar generar ventajas a través de movimientos y duelos con los centrales, pero no he visto nada muy especial. Aún así, es un juvenil de primer año jugando habitualmente en 2ª RFEF.','RP','Seguir'),
  ('bb80600c-9b0f-5370-ae70-af9c704cb43a','2c2a0cf9-f5dc-508f-8e9c-b77e76980709','2025-12-05 16:02:44','VALLADOLID B - Coruxo (30/11/2025)','Centrocampista diestro de primera altura, en el partido actuando como mediocentro. Perfil físico medio en cuanto a estatura y complexión. Es agresivo y tiene un buen nivel técnico, pero no he visto nada muy especial.','RP',NULL),
  ('1764ece3-c724-5bce-9375-32e527af54ba','62c5f84b-6935-5715-8b9c-0ed84cc94776','2025-12-05 16:04:01','VALLADOLID B - Coruxo (30/11/2025)','Delantero centro diestro con un perfil físico interesante: estatura superior a 1''85 m y complexión fuerte, aunque parece algo pesado en carrera. No va mal al duelo. Destaca más por perfil que por nivel.','RP','Seguir'),
  ('b0367b5e-4498-5b93-a618-7357a8bfe636','ea3cf696-7f16-54ff-a286-37174b4a5cac','2025-12-05 16:05:11','VALLADOLID B - Coruxo (30/11/2025)','Extremo diestro con un perfil físico medio-bajo en cuanto a estatura y complexión. No tiene condiciones técnicas top ni es especialmente rápido. Termina muchas jugadas con centro precipitado por falta de recursos.','RP','Descartar'),
  ('2464565a-371c-5b8c-964a-c5a7e7b7ba7f','828d903c-17b3-5251-bc44-07d3510beece','2025-12-06 16:47:17','vs Celtic Elche','Nahuel Abadia: #6 de buen biotipo físico (estatura aprox 1.80 m, de piernas largas, delgado, potente, ágil y veloz). Utiliza bien las dos piernas, es vertical con balón, avanza en conducción y busca pases largos. Precisión irregular, da sensación de que le falta mayor sensibilidad técnica. Sorprende por recursos para superar rivales en corto. Es agresivo e intenso en fase defensiva, afrontando duelos con frecuencia y siendo ganador. Tiene recorrido y presencia en ambos campos.','NB','Seguir'),
  ('0d18ce13-ce02-5db0-afe1-540dd899fe19','77d754f5-9d95-5aef-acae-d757fd446e8e','2025-12-06 16:52:46','vs Celtic Elche','Lateral izquierdo de estatura baja, físico fuerte, potente, veloz. Juega hacia adelante, perfil ofensivo, intenso. Dudas sobre crecimiento físico.','NB','Seguir'),
  ('b63305ea-4550-5690-a154-ad1df75608c3','0dbafb17-841b-52d1-9dd1-0dae4c0290fa','2025-12-06 16:57:15','vs Patacona','#6 de perfil físico medio, agresivo en acciones, con buena salida de balón y recursos en juego asociativo. Parece que va a seguir creciendo, estar atentos.','NB',NULL),
  ('4f845d71-75d7-561b-9154-dd11d40569f6','4bb6f236-8e41-510f-865f-adaf0464749e','2025-12-06 18:47:21','VILLARREAL JUV. A - Murcia Promises Juv. A (6/12/2025)','Lateral derecho con un perfil físico medio-alto en cuanto a estatura y complexión para la posición. Bastante recorrido y juego interior. Bien técnicamente y bastante seguro en defensa.','RP','Firmar'),
  ('b705fe88-fbf0-55c8-ad8d-fdcbfd5bb2fb','5056e523-027d-5bff-b15d-a0a9f3fffca1','2025-12-06 23:10:43','vs Alboraya Juv B','Delantero centro/segundo punta de perfil físico mejorable: estatura media, sin llegar al 1.80 m, robusto, velocidad OK sin tener gran punta de aceleración. Jugador potente, de buen nivel técnico que es capaz de impactar fuera del área, jugar de espaldas y participar en juego asociativo.  Cerca del área tiene buenos movimientos y repertorio para finalizar.','NB','Seguir'),
  ('352b632a-5955-5b9d-a49e-dff4803bb4b7','7f324ffc-c2a8-51ac-8dbe-095f0954b364','2025-12-07 17:57:35','vs Betis B','Mediocentro de perfil físico medio en cuanto a estatura, complexión delgada, ágil, veloz y con recorrido. Jugador enérgico sin balón, que afronta duelos con frecuencia. Se mueve bien en espacios reducidos y llega al área rival.','NB','Seguir'),
  ('a9369ef5-17be-592e-be70-9221bab69995','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2025-12-07 17:59:04','vs Antequera','Primero extremo a pie natural, después por derecha donde crea mayor impacto. Jugador que por perfil físico, toma de decisiones y capacidad de finalización (remates y centros) está a otro nivel.','NB','Firmar'),
  ('e6ac49ba-c936-5f8c-99be-03e67038be99','41c80a9e-18c2-5397-a50c-946f063d558f','2025-12-07 18:01:09','vs Soneja','Lateral derecho de perfil físico ideal para posición, con ritmos altos y recursos defensivos/ofensivos de sobra. Jugador de máximo potencial.','NB','Firmar'),
  ('6b79f34f-8d31-584d-a396-9ba2c194df2c','0db04bac-6b60-5bb5-b5f7-de00dcf9402f','2025-12-07 18:14:39','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Lateral izquierdo de estatura medio-baja, pero rápido y muy dinámico. Buen perfil técnico y bastante atrevido con balón. Recorta bien hacia dentro y siempre trata de mejorar jugada, tanto en campo propio como en el último tercio. Tiene un centro bastante bueno.','RP','Seguir'),
  ('83d63ea1-3588-50ca-91ff-7e0ed96c8b2b','d66722d4-dcaf-536b-865f-2212df6f39fc','2025-12-07 20:15:21','vs Teruel','Mediapunta con potencial de Primera División. Físico mediano, estatura media, delgado, con margen de mejora en potencia/musculatura, bien de velocidad/agilidad sin ser explosivo. Como delantero centro le cuesta más.','NB','Firmar'),
  ('d644b022-d620-51ce-b59b-fe4d4c83140f','9b6de689-a352-5599-a6a0-a20c6dda6c40','2025-12-07 20:17:03','vs Teruel','Central con una suficiencia abismal para la categoría. Por nivel técnico y poderío físico, jugador de máximo nivel.','NB','Firmar'),
  ('b3cd4fe9-9695-54dc-a9ed-8e746af9b865','3880d6f2-55cf-57b7-b247-1b0e5e0761fb','2025-12-09 11:27:56','vs Eibar','Thiago Ojeda es un #6 de buen perfil físico para la posición (estatura cercana al 1.90 m, complexión delgada pero potente, velocidad/agilidad normales sin destacar, incluso da sensación de algo lento en primeros metros y giros, con menos, de recorrido ok). 

Es un #6 bastante posicional, pero que le está sumando mayor llegada a su juego. Con balón juega fácil, suele buscar opciones cercnas. Muestra cierta capacidad para avanzar en conducción, gracias a su potencia. Llega bien a último tercio, incluso con criterio para terminar jugadas con remates. 

En fase defensiva es jugador de buen nivel. Inteligente para posicionarse, saltar a presión, realizar coberturas, defensa de área. Es sólido en duelos aéreos, por arriba y por abajo. Tiene buena técnica de robo.','NB','Firmar'),
  ('d45d48eb-8c78-596e-96cc-fa0be8f327a1','8df73e8f-eb8f-5d2e-ba84-5bb1ebac4ab0','2025-12-09 11:36:15',NULL,'Perfil físico normal para posición (cercano al 1.80 m, delgado, no tan poderoso, de buena velocidad y datos de recorrido/intensidad mejores que los de la media). Fuerte en juego áereo, aunque le falta mayor consistencia en duelos a ras de suelo). Con balón no destaca por generar grandes ventajas en pases ni conducciones.','NB',NULL),
  ('12310927-6793-58af-b5b8-61437ae059af','680eaff8-fa0d-595a-a87e-c19b7514e7ac','2025-12-09 11:51:02',NULL,'Mediocentro muy poderoso físicamente, de estatura cercana al 1.90, fuerte. Capaz de soportar ritmos altos, aún sin tener gran punta de velocidad en carrera. En fase defensiva tiene recorrido, es buen recuperador, difícil de superar en duelos individuales. Con balón le falta mayor impacto, se nota que técnicamente no está pulido.','NB','Firmar'),
  ('b2472ab7-523d-57b8-97b9-45995f421bb0','0ee6ba40-3488-5286-b376-725a4d47a02a','2025-12-09 16:06:50','vs PSV','Sergio Esteban: lo veo con mismo rendimiento que últimas veces, consolidándose como el delantero centro de mayor potencial de su generación en España en mi opinión. Prototipo físico perfecto para posición: alto, fuerte, rápido, capaz de repetir esfuerzos. Presencia activa fuera del área, jugando de espaldas y atacando espacio. Con olfato para encontrar situaciones de remate y terminar jugadas por sí mismo. También puede generarse sus propias ocasiones.','NB','Firmar'),
  ('f19a2a50-5023-5513-826d-3e9fb1e0c089','4bf059d6-3d61-50a4-8835-1406de7e162e','2025-12-09 16:08:12','vs PSV','Gabriel Obama: delantero centro de gran perfil físico (estatura 1.87 m aprox, muy fuerte/potente, con velocidad aceptable para atacar espacio). En minutos de juego genera impacto en ataques de profundidad, ganando duelos individuales y teniendo ocasiones de remate. Perfil con claro margen de mejora y potencial.','NB','Firmar'),
  ('7857ee56-6c6b-5a26-882b-923f904876a8','e17cc547-8e49-5175-b7e0-8a7cb266b528','2025-12-09 16:09:27','vs PSV','Dudas sobre poderío físico. Le cuesta imponerse en carrera y en duelos. Tiene una capacidad muy buena para sacar remates, pero más allá de eso, le cuesta generar impacto en juego.','NB',NULL),
  ('bf554413-c5cc-59ec-9a28-13a4fd226763','ba2198f7-01f0-5710-a57c-559c9bef6827','2025-12-09 16:10:22','vs PSV','Lateral derecho de buen perfil físico (cercano al 1.80, complexión delgada pero bastante fuerte, velocidad normal sin ser explosivo, con recorrido). Poco impacto en ataque en este partido, y con problemas ante extremo habilidoso.','NB',NULL),
  ('412c6894-e072-594a-8fc9-75e3bc202620','83e6b76d-1f10-5efb-b88f-ade038f5b81e','2025-12-09 16:11:54','vs PSV','#6 de perfil físico OK para posición (buena estatura, agilidad). Sin tanto impacto en juego.','NB',NULL),
  ('84fb8ebf-b5e1-5e16-8139-b8744aed5dd9','cc7e3d37-0671-5974-95b6-daa354779d46','2025-12-09 16:52:39','vs PSV','Central que no me termina de convencer. En partidos de duelos físicos y mayor exigencia le cuesta imponerse.','NB',NULL),
  ('192f759c-d885-59b2-849b-86aae9b8a4a4','f3000518-2309-541b-bbe0-d15d6b942416','2025-12-09 17:55:42','vs Frankfurt','Central diestro jugando por izquierda. Buen biotipo (alto, de piernas largas, delgado, veloz, ágil, con potencia por hacer). Jugador vertical para romper líneas de presión y jugar hacia adelante con pases y conducciones. Es agresivo para afrontar duelos, aún irregular, con timing por mejorar.','NB','Firmar'),
  ('77a282f4-78d8-59c9-8a69-40f7bb1976f3','6978206f-1ef8-5d2d-9535-56b1d4c18bb6','2025-12-09 17:57:48','vs Frankfurt','Mediocentro #6-#8 de perfil físico medio, con nivel técnico alto y capacidad de llegada desde atrás. Buen constructor de juego y gestor de posesiones. Sin balón es intenso, aunque por físico tampoco demasiado imponente.','NB','Seguir'),
  ('ed2e0c5f-efe2-5f97-ae5a-d22760239d2c','b34f78a2-07f7-5c1e-864c-e17d14066b73','2025-12-09 18:02:57','vs Frankfurt','Jugador que puede desempeñar cualquier función en mediocampo y jugar como #6, #8 y #10. Seguramente #8 sea su puesto ideal. Perfil físico de estatura baja, fuerte, ágil, con recorrido. Gran nivel técnico, excelente para asociarse, con recursos en espacios reducidos y buen uno contra uno. Habilidad para llegar a área y finalizar.','NB','Firmar'),
  ('4e55ce86-f9a9-5f64-bdcc-717dd00ecd22','f242b686-83be-55c5-bbc7-9098daaabe6d','2025-12-09 18:09:04','vs Frankfurt','Extremo de estatura media, delgado pero bastante potente, rápido y explosivo. Con desequilibrio en 1v1 y conducción. Buena capacidad de finalización.','NB','Seguir'),
  ('c3b31da4-2af2-5576-b20a-9cdf91bee3d1','f455e623-550f-5ab1-b4cc-6e73f1585d54','2025-12-10 07:58:24',NULL,'Extremo diestro que suele jugar por derecha. Perfil físico medio (estatura mediana, complexión delgada, velocidad sin ser explosivo, bien de agilidad). Extremo de buen nivel técnico, vertical en sus acciones, más peligroso por llegada a línea de fondo y centro, y presencia en área, que por capacidad de generar en 1v1. Es buen perfil de extremo. No me parece top, sí que puede evolucionar en contexto Cádiz.','NB','Seguir'),
  ('05bb16dc-8f22-59a9-98e2-4c0866c8a383','cc785c2e-5f64-50a8-9cd8-f0c197c2a64b','2025-12-10 10:16:01','vs Villarreal','Poco impacto en juego, ya que entró en minuto 81. Buen perfil físico en primera impresión. Ver si tiene continuidad en primer equipo. Último año sub-23.','NB',NULL),
  ('f2a35112-e320-5f90-9670-0e06b524822d','77c9daec-cd0c-5a34-8a10-af13b1fbff4b','2025-12-10 10:23:49','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Centrocampista zurdo de segunda/tercera altura, para actuar como interior o mediapunta, aunque me gustaría verle en un doble pivote con mucha participación. Perfil físico medio-alto en cuanto a estatura y complexión teniendo en cuenta que es 2010. Nivel técnico muy elevado, con un dominio del balón extraordinario, y mucho criterio y personalidad para ser agresivo y tomar decisiones con balón.','RP','Firmar'),
  ('f390a01e-26a3-5fbd-b165-4cddae950a2d','fa85303a-3bd7-52d6-8444-e2c8991e6128','2025-12-10 10:30:03','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Central zurdo con una estatura alrededor de 1''85 m y complexión delgada, con potencial de crecimiento en este sentido. Notable con balón y muy seguro en todas las acciones defensivas: juego aéreo, anticipación, corrección etc.','RP','Decidir'),
  ('09b777f5-26e9-52ce-b186-4a51cbf0b514','70bc0460-fbc3-5e9f-ba03-c97d97e8fed9','2025-12-10 10:30:58','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Centrocampista zurdo de segunda/tercera altura. Estatura media, complexión ligera. Mucha calidad y buen nivel de participación, mejorando jugadas a menudo. Peligroso en el último pase. Técnica sobresaliente para el pase y para escapar de presiones, incluso de espaldas. También ha jugado de delantero centro y ha marcado un gol.','RP','Decidir'),
  ('b3318f89-e2b9-59c2-bcbe-fea8aeb5016a','bdbb33fb-f459-5b7a-b8e3-23c848dbf2f6','2025-12-10 10:32:33','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Lateral izquierdo con un perfil físico medio-alto en cuanto a estatura y complexión. Agresivo con y sin balón y buen nivel técnico para ejecutar. Buen recorrido y es bastante ofensivo, pero me genera dudas en retornos a partir de cierto minuto.','RP','Seguir'),
  ('8b4124fc-1df2-56ee-90a1-1afccc518533','24c00223-606d-5dc5-a82c-4af68b159afb','2025-12-10 10:33:42','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Mediocentro zurdo. Perfil físico alto. Tiene calidad en la distribución y el corte, pero en el partido ha estado algo más discreto que otras veces.','RP','Seguir'),
  ('3bea86cd-3ad6-58b8-90b9-53a7fc728ef6','2dfbb9ba-ba60-5e15-b652-c5fc24cbb2dd','2025-12-10 10:34:29','VILLARREAL JUV. B - Torre Levante Juv. A (5/12/2025)','Extremo diestro de estatura medio-baja y complexión ligera. Buen cambio de ritmo. Bastante calidad y personalidad con balón, pero no le veo muy especial.','RP','Seguir'),
  ('56cea63b-600b-5da3-a2c8-560664cf7ef1','fe695129-119b-50d0-a997-ca71af610a01','2025-12-10 10:35:06',NULL,'Delantero de estatura cercana al 1.80 m, delgado, veloz. Puede atacar espacio y está generando en área.','NB',NULL),
  ('14f632de-a462-57a0-8ab8-28b4878cae16','2e804b78-29db-5c09-a9f5-05bf4ccd1814','2025-12-10 10:38:25','Villarreal Cad. A - KELME CAD. A (6/12/2025)','Delantero centro diestro de estatura alta. No es rápido, pero tiene bastante calidad con balón y personalidad para hacer las acciones de ataque. Ha ganado varios duelos aéreos.','RP','Seguir'),
  ('af024d52-b4d6-5497-8b9c-5d18e44ec34d','95092cc1-bffb-5950-b9eb-c5783794d042','2025-12-10 10:45:16','Villarreal Juv. A - MURCIA PROMISES JUV. A (6/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura media y complexión delgada, con margen de mejora en este sentido. Nivel técnico correcto y muy intenso en la acción, sobre todo en defensa.','RP','Seguir'),
  ('c2695185-0414-58ca-92bd-4f956714d4f2','b77bcce3-529d-5afc-8a33-c4791eaaef2c','2025-12-10 10:47:16','Villarreal Juv. A - MURCIA PROMISES JUV. A (6/12/2025)','Centrocampista zurdo de primera/segunda altura. Perfil físico medio-alto en cuanto a estatura y complexión, aunque algo lento. Seguro con balón. Tiene recorrido y llegada, ha marcado un buen gol desde la frontal.','RP','Seguir'),
  ('944b9d42-db84-5109-b5c6-667cd7c1d196','ab1ce125-6708-5b2f-8b62-44490e90699f','2025-12-10 10:49:35','Villarreal Juv. A - MUCRIA PROMISES JUV. A (6/12/2025)','Extremo diestro, de perfil centrocampista en banda, de estatura baja y aspecto ligero, menos fuerte que Luismi, por ejemplo. Muy ágil y buena técnica para dominar el balón y desbordar. Hoy golazo y asistencia, está generando goles.','RP','Seguir'),
  ('5cf31cfb-4e36-5bb7-8cbd-5a1d5b0c9c9a','2f11ef02-aef0-5f04-bd94-4c56642f093b','2025-12-10 10:49:36','vs Girona B','Central de buen biotipo: alto (aprox. 1.88 m), espigado, delgado, con musculatura por construir, bien de velocidad y agilidad. En salida de balón muestra capacidad para jugar hacia adelante, supera línea de presión con pases y conducciones. En defensa es proactivo para anticipar, salir de zona y defender lejos del área. Da sensación de que debe ganar mayor fortaleza en duelos, sobre todo por arriba. Por perfil físico y características generales lo veo con potencial primer equipo claro.','NB','Firmar'),
  ('5596becf-42cf-53e9-bf92-384db9f4666c','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-12-10 10:52:26','RODA JUV. A - Jove Español Juv. A (6/12/2025)','Jugador zurdo de corte ofensivo, para actuar en banda o como interior/mediapunta. Perfil físico medio-alto, gran nivel técnico y mucha personalidad con balón. Muy peligroso en el último tercio.','RP','Firmar'),
  ('3456639a-a798-51f5-96d7-fde996b1c6d1','0d7a26e4-65fb-5aee-a24a-90783eac7e8f','2025-12-10 10:56:02','RODA JUV. A - Jove Español Juv. A (6/12/2025)','Centrocampista zurdo de segunda/tercera altura, en el partido actuando como interior. Físico medio, con aspecto ligero. Es perfil mediapunta por estilo de juego, pero también un gran gestor de balón. Nivel técnico muy elevado y gran criterio.','RP','Seguir'),
  ('5d687c46-759a-5843-b988-6a5d5d5fd97a','4693fc7a-2718-5142-9807-abeef8433e4f','2025-12-10 10:59:24','Villarreal B - TERUEL (7/12/2025)','Delantero centro con un perfil físico medio-alto en cuanto a estatura y complexión. Ha entrado en la segunda parte y ha tenido tres o cuatro descargas muy buenas, incluida una buena conducción superando un par de rivales.','RP','Seguir'),
  ('67e808ae-828a-5a8f-bc82-def3c2a155cc','f496dc51-cb91-592d-8b26-19672d9dc920','2025-12-10 14:19:36','MALLORCA JUV. A - Huesca Juv. A (7/12/2025)','Extremo diestro con un perfil físico sensacional: estatura superior a 1''85 m, piernas largas y aspecto delgado pero fuerte, con potencial de mejora. Jugador habilidoso para desbordar, en el partido a pierna cambiada. Genera acciones de centro con mucha facilidad y tiene una zancada muy poderosa.','RP','Firmar'),
  ('4d42e1cf-cb87-501c-855b-50c9530fbf9c','1a633f3b-0484-5887-82c4-a60cc6f7af51','2025-12-10 14:24:34','vs Copenhague','Mediocentro de perfil físico ideal para la posición: alto, espigado, delgado, con fuerza por ganar, rápido, ágil, con recorrido. Vertical en acciones, juega hacia adelante y se suelta en carrera. Le falta mayor impacto ya que suele desconectarse y debe ser más activo/agresivo en fase defensiva. Potencial top','NB','Firmar'),
  ('ddb58c63-fa36-569d-a734-cd4dd991d2d2','98f8a33f-ad30-552f-a337-8757c9646cfd','2025-12-10 14:26:44','vs Copenhague','Central izquierdo de buen biotipo: alto (1.90 m aprox), piernas largas, delgado, con físico por hacer,  velocidad normal. Defensa con carencias notables a nivel defensivo y con balón, seguir por cualidades físicas.','NB','Seguir'),
  ('3d1d5918-c544-5a82-895d-fe505124e087','f007ea82-e67b-5672-b631-b9de2c400bfc','2025-12-10 14:29:33','vs Copenhague','Extremo de estatura baja, potente, de musculatura desarrollada. Es rápido y explosivo. Tiene capacidad de 1v1, bien en espacios largos y con recursos en corto. Muestra habilidad para crear jugadas y finalizarlas. Bien en trabajo defensivo.','NB','Seguir'),
  ('c506ada3-7adf-5da8-9f7c-34ef23ff4fd7','6ada98ea-d903-5cf5-9ceb-367ec28151ff','2025-12-10 14:27:09','MALLORCA JUV. A - Huesca Juv. A (7/12/2025)','Delantero centro diestro con una estatura algo por encima de 1''80 m y un físico de aspecto fuerte. En el partido se muestra agresivo y deja bastantes movimientos interesantes sin balón.','RP','Seguir'),
  ('9a422a71-71f3-59fc-bc07-9f0d4b8ef884','1bb69ddd-744a-53fc-9b29-dc633daeb4b6','2025-12-10 14:31:23','vs Copenhague','No lo veo con nivel para evolucionar en clave Villarreal','NB','Descartar'),
  ('abb17fb6-08c0-58ff-85f5-90d20fda8bbf','e09543e0-cecd-54a4-b2cf-13bf3bdeb37d','2025-12-10 14:32:20','vs Copenhague','Mediocentro de físico promedio, sin destacar en nada. Estatura media, delgado, poco potente. Calidad, buen juego asociativo, juega fácil sin tener gran llegada a ataque. Tampoco es demasiado imponente en duelos.','NB',NULL),
  ('9952f112-1a00-571f-8f64-0795247583a6','db36d7c4-c805-54bd-808a-4f016915f064','2025-12-10 14:32:48','MALLORCA JUV. A - Huesca Juv. A (7/12/2025)','Segundo delantero zurdo con un físico más o menos interesante: estatura media pero aspecto atlético, con potencia en distancias cortas. No he podido evaluar velocidad en carrera. En el partido realiza alguna acción técnica interesante y se muestra agresivo con y sin balón.','RP','Seguir'),
  ('49a01932-d2e8-509a-b50a-c43665d8735b','4c0a0c63-8caa-53c0-91bb-0d9660c23d0b','2025-12-10 14:37:37','Mallorca Juv. A - HUESCA JUV. A (7/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando como mediocentro pero con un perfil más cercano al interior. Estatura medio-baja y complexión normal, estilo Rica. Gran manejo del balón y mucha personalidad para aguantarla y buscar la mejor solución. Un buen gestor de posesión que destaca acelerando jugadas. 

Lo está jugando prácticamente todo en DH siendo primer año y es un jugador de muy buen nivel, pero no encaja demasiado en nuestro perfil.','RP','Decidir'),
  ('98f86697-7267-5c77-be66-a1a5ac341867','cfd4fb0b-e191-5fc2-86d7-75559fdda9a1','2025-12-10 14:45:21','Mallorca Juv. A - HUESCA JUV. A (7/12/2025)','Segundo delantero/mediapunta diestro con un perfil físico medio en cuanto a estatura y complexión. No he visto nada destacable con balón. 

El jugador no me ha entusiasmado, pero es 2009 y está jugando todo en DH.','RP','Seguir'),
  ('45eca57b-950b-53d6-aa29-95104545dcd2','afa1d4aa-fee1-5972-843a-78da904cfe05','2025-12-10 14:47:44','Mallorca Juv. A - HUESCA JUV. A (7/12/2025)','Central diestro de perfil físico medio para la posición. En el partido ha entrado en los últimos minutos y ha resuelto bien un par de acciones con balón. No he visto nada destacable, pero es un 2009 que está teniendo minutos en el DH del Huesca.','RP','Seguir'),
  ('484dcbe0-c64c-573c-9720-da34fb021f1c','8f6f62e8-14e3-557f-a307-a95044bc030a','2025-12-10 14:50:18','Mallorca Juv. A - HUESCA JUV. A (7/12/2025)','Centrocampista zurdo de segunda altura, en el partido actuando en un doble pivote. Perfil físico medio-bajo en cuanto a estatura y complexión. Buen manejo de balón y último pase interesante.','RP','Seguir'),
  ('74827728-0214-59ff-9197-90e0a128821b','7161af4a-10e5-550f-911a-e439106db372','2025-12-10 14:52:41','Mallorca Juv. A - HUESCA JUV. A (7/12/2025)','Atacante diestro, en el partido actuando primero en banda derecha y después en una doble punta. Estatura media, pero físico más o menos potente. No es rápido en carrera, pero sí muy agresivo para presionar e ir al choque. No destaca especialmente con balón.','RP','Seguir'),
  ('722f79da-0b42-5949-9cf4-86ed15a1acfb','05ed1ceb-8ee5-539b-b72c-5b9d64a33b29','2025-12-10 15:39:46','vs Córdoba','Central diestro de biotipo excelente para posición: 1.90 m, fuerte, de velocidad aceptable, igual con algún problema en primeros metros y para giros. Es diestro. Defiende bien la profundidad, es agresivo para afrontar duelos individuales, es difícil de superar en el 1v1. Con balón, sin tener un gran pie, juega hacia adelante e intenta progresar.','NB','Firmar'),
  ('08259045-e010-5fec-ab4b-3f998b16e24e','05ed1ceb-8ee5-539b-b72c-5b9d64a33b29','2025-12-10 16:13:03','LEGANÉS - Córdoba (7/12/2025)','Central diestro con un perfil físico extraordinario: estatura cercana a 2 m y complexión muy fuerte; quizás algo lento, aunque con buena zancada. Muy agresivo en el duelo y bastante buena técnica defensiva para robar. Muy ganador en el juego aéreo. Con balón es correcto.','RP','Firmar'),
  ('0a6c91bd-c99d-547f-9e9f-e2e42bd1c3d2','692f988b-e163-5ba1-9a67-a78b20f4c670','2025-12-10 16:17:08','LEGANÉS - Córdoba (7/12/2025)','Central zurdo con un perfil físico muy bueno: estatura por encima de 1''85 m y complexión fuerte. En el partido tiene alguna buena acción defensiva, pero también comete un penalti por leer mal la jugada y reaccionar tarde.','RP','Seguir'),
  ('e3a53f0c-3e0e-5048-9e7b-82f7a645395f','23355bf5-c220-535e-a3fc-3b650b85b822','2025-12-10 16:21:57','LEGANÉS - Córdoba (7/12/2025)','Lateral derecho con un perfil físico medio para la posición: estatura alrededor de 1''75 m y complexión normal. Bastante agresivo en el duelo, buena actitud para defender. Tiene cierta velocidad de reacción y algo de recorrido, pero no he visto nada muy especial con balón.','RP','Seguir'),
  ('fdc24c37-8184-5c9a-a5fc-b5ece200e4db','12146f3b-1ff6-5cc4-aebc-06dcd9b238c0','2025-12-10 16:23:36','Leganés - CÓRDOBA (7/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando como mediocentro y como interior con recorrido en un 4-3-3. Perfil físico alto, sobre todo por estatura (+1''85 m). Buen manejo de balón y va bastante bien a duelos. Me ha faltado algo más de peso en el juego.','RP','Seguir'),
  ('a9872415-d2d0-587d-bf29-eadd3b09cfec','e1263955-d5b8-5908-81e1-a18069fd4e96','2025-12-10 16:25:47','Leganés - CÓRDOBA (7/12/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior con llegada. Perfil físico medio. Buen trato de balón y bastante intención en algún último pase. No es muy perfil.','RP','Seguir'),
  ('86bc7c71-80ec-5c21-9ef0-510d0ab59cba','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2025-12-10 18:30:15','vs Porto','Extremo zurdo de biotipo top, gran golpeo, recursos en 1v1, desequilibrio individual. Muy completo.','NB','Firmar')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('3650aa69-3269-5984-9a74-1d67a2fba52c','6dd78885-4fa5-5394-82df-e9e749d3be94','2025-12-10 18:32:16','vs Porto','Lateral derecho de buen perfil físico, sólido en fase defensiva, con llegada a ataque. Uno de los mejores en su posición en su generación.','NB','Firmar'),
  ('fd5166db-112a-56ab-ba4f-de58e3610afb','c6aeac05-d89c-51fe-b2a1-b54b54f617b5','2025-12-10 18:40:46','vs Girona B','Dudas sobre perfil físico. Le falta mayor poderío para imponerse en contextos más exigentes.','NB',NULL),
  ('c5d5c124-5004-510f-a474-0f1c03799e9c','5fcfa2a5-33ae-5664-bc07-8fb6dd6891fa','2025-12-11 09:43:33','vs Valencia B','Mediocentro de buen perfil físico a primera vista: grande y fuerte. Es lento, tosco, le cuestan los recorridos largos. No tiene buen impacto, de hecho me da la sensación de tener poco nivel.','NB','Descartar'),
  ('f8bedce8-e914-5f93-870e-180c93083d98','38857670-69b8-5457-852f-aef301ebe60b','2025-12-11 09:49:56','vs Valencia B','Delantero centro de perfil físico medio (estatura normal, rápido, ágil, delgado) con movilidad fuera del área, bueno yendo al espacio y cayendo a bandas. Poco impacto en el área en este partido.','NB','Seguir'),
  ('900bd306-65bc-5374-91dc-a50b57a4f5e0','989ecbc7-4f24-5e72-a750-6bcbd2a6c0f1','2025-12-11 09:56:42','vs Valencia B','Extremo interesante. Buen perfil físico para la posición (estatura media-baja, fuerte, rápido, explosivo, con cambio de ritmo). Genera desequilibrio en 1v1 y es capaz de crear alguna ocasión en poco tiempo.','NB','Seguir'),
  ('4687fe70-b611-5e4f-b1e8-8858a000e06c','cbb76c77-b30b-58dd-8cb8-2f23b1460a9c','2025-12-11 10:47:12',NULL,'Delantero centro de estatura algo superior a 1.80 m, muy fuerte y robusto. Buen juego de espaldas, rocoso, defiende bien su posesión. Le falta pie, se nota que le falta nivel técnico.','NB',NULL),
  ('d66c238b-3f84-523e-93f1-1121a765689e','4bf059d6-3d61-50a4-8835-1406de7e162e','2025-12-11 12:24:21','vs Getafe Juv A','Delantero centro de perfil físico top: grande, muy fuerte, buen velocidad. Juega de espaldas, se impone yendo al choque, peligroso atacando profundidad. Con pies no tiene gran calidad, pero sí es capaz de asociarse fácil y de conducir en corto. Tiene ocasiones con frecuencia. Perfil muy interesante.','NB','Firmar'),
  ('41cc3680-6189-51ec-9ebe-0f0caf1ae73a','54bb0d77-9628-5dae-b122-017a84d5da8d','2025-12-11 12:26:27','vs Getafe Juv A','#6 posicional de buen perfil físico, aunque lento en carrera y desplazamientos. Se muestra sólido en duelos, también por arriba, y recuperando. Con balón tiene criterio, suele jugar fácil con opciones cercanas aunque tiene buen pase largo. Es jugador de rendimiento fiable, pero al que le falta ganar más ritmo y recursos ofensivos.','NB','Seguir'),
  ('c3b2a7ca-3cea-5bb1-a84b-021463c745e3','ba2198f7-01f0-5710-a57c-559c9bef6827','2025-12-11 12:28:35','vs Getafe Juv A','Lateral derecho de buen perfil físico: fuerte, alto, veloz, con recorrido. Llegada a ataque, vertical en acciones, con presencia en último tercio. Se muestra sólido en fase defensiva. Por perfil y características es lateral derecho de potencial.','NB','Firmar'),
  ('824f31df-6b68-5414-8e57-15bfc58260cf','0ed4e7d6-c3ec-5488-907e-a4d7e3adf866','2025-12-11 12:31:48','vs Getafe Juv A','Juega de #8, ganando mayor capacidad para soltarse y llegar a ataque. Físico mediano, con recorrido, buen trato de balón, vertical. Trabajador en fase defensiva, agresivo para ganar duelos.','NB','Seguir'),
  ('add7dfb4-eb46-5042-89be-19170f2a372a','826e3259-52db-5f90-a7ca-0b41caa07468','2025-12-11 14:45:10','vs Racing','Extremo diestro por izquierda. Buen perfil físico para posición (estatura media, delgado, con musculatura por hacer, rápido, ágil). Perfil creativo, con recursos en 1v1, regateador, capaz de generar ocasiones por sí solo.','NB','Firmar'),
  ('74ada5f1-966b-54fd-a349-e4a9bdb8b6d4','b9403f72-9f8a-580f-86db-b3500febc285','2025-12-11 14:49:37','vs Racing','Extremo de físico normal, encarador, le falta explosividad. Está bien pero de menos potencial que Valeiro.','NB',NULL),
  ('f2230244-6279-5a22-a8cb-a5fc4cc04e09','3978a003-f74d-50bc-8ff0-e3bda51dc686','2025-12-11 14:54:16','vs Deportivo','Juega de #9. Perfil físico malo para posición. Fuerte, juega de espaldas, buen nivel técnico. Tampoco marca diferencias.','NB',NULL),
  ('45b795c8-fc53-54c0-80ad-0ba93a889a29','adb4404f-be83-58b5-9238-da8fa3b884c5','2025-12-11 14:56:41','vs Deportivo','#8 de buen perfil físico, dinámico, con recorrido. Por características similar a Sergio Martínez. Ver más.','NB','Seguir'),
  ('8bb12ffb-e33c-51ba-9419-5c8405298787','ab1ce125-6708-5b2f-8b62-44490e90699f','2025-12-11 16:55:51','vs Villarreal Juv A','Perfil de mediapunta de físico promedio (estatura media-baja, delgado, poco poderoso) de calidad, manejo de balón, buen juego asociativo. Genera con su golpeo. Le falta mayor poderío y ritmo, también más electricidad en 1v1 para ser extremo.','NB',NULL),
  ('b7b14110-85f4-51ee-b415-5c60cd4e5bb1','95092cc1-bffb-5950-b9eb-c5783794d042','2025-12-11 16:58:09','vs Villarreal','#6 de buen perfil físico (estatura cerca al 1.80 m, dinámico, ágil, fuerte). Buen manejo de balón, gana metros en conducción, intenso para afrontar duelos y en presión.','NB','Seguir'),
  ('af41e7ff-be94-5122-a135-b5fbdbbfbae7','f007ea82-e67b-5672-b631-b9de2c400bfc','2025-12-11 17:01:02','vs Murcia Promises','Extremo de estatura baja, muy potente, rápido, explosivo. Genera en 1v1, desequilibrante en carrera y yendo al espacio. Bien finalizando. Perfil que está creciendo notablemente.','NB','Seguir'),
  ('d2fe6561-4834-55ea-bbd1-cf5f1f532686','f14f7895-6ce7-5349-b885-a502e47da05a','2025-12-11 17:05:53','vs Espanyol','Rol de delantero centro referencia. Perfil físico top (+1.90, delgado aunque bastante potente, agilidad/velocidad normales). Es atacante que gana en juego aéreo, tiene recursos para jugar de espaldas y asociarse en corto, sin nivel técnico excelente. Mayor presencia en área que en partidos vistos anteriormente. Algo inconsistente aún, con condiciones para explotar.','NB','Seguir'),
  ('f6eb1d14-3da1-5467-8d90-48cd63d8f3f9','83eeb054-d58c-5b9f-a47f-601f86062ed7','2025-12-12 13:16:59','SEVILLA JUV. B - Zabal Juv. A (6/12/2025)','Lateral derecho de perfil físico medio. No he visto nada destacado.','RP',NULL),
  ('35f5d6e2-7db0-5f8c-a77d-599886b668dc','ae3cfa9f-a478-51b5-8125-f74540bf2874','2025-12-12 13:19:07','SEVILLA JUV. B - Zabal Juv. A (6/12/2025)','Lateral izquierdo de perfil físico medio. Nada destacable en lo que he visto.','RP',NULL),
  ('5202cff5-b406-53b3-9c81-888ea70aa150','bf5cd25d-7dfe-5f71-a3a2-01a6974d69ca','2025-12-12 13:21:49','SEVILLA JUV. B - Zabal Juv. A (6/12/2025)','Central diestro de perfil físico medio alto: estatura alrededor de 1''85 m y complexión fuerte. Muy bien defendiendo hacia delante, agresivo para cortar jugada y bastante dominante en el duelo aéreo. Es fuerte y tiene personalidad con balón para salir y aportar ventajas en construcción.','RP','Firmar'),
  ('8fa27066-c301-580f-8051-9bb52676c16f','d0d7f737-bfae-57c9-bf38-e8a7a28a6e73','2025-12-12 13:25:50','SEVILLA JUV. B - Zabal Juv. A (6/12/2025)','Extremo diestro con un perfil físico muy interesante: estatura alrededor de 1''85 m y complexión delgada, con piernas largas y margen de crecimiento en cuanto a fortaleza. Bien técnicamente, con cierta habilidad para desbordar y un buen cambio de ritmo y zancada. Agresivo en la toma de decisión, sobre todo en el último tercio, donde siempre busca área.','RP','Firmar'),
  ('389a6ad9-757d-560e-85be-a2268366f43f','617e8180-3992-5fe8-b7a6-041d7cffd539','2025-12-12 13:29:43','SEVILLA JUV. B - Zabal Juv. A (6/12/2025)','Extremo diestro con una estatura alrededor a 1''80 m y aspecto fuerte. Tiene buena técnica y habilidad para desbordar, aunque sin ser top. Potente en carrera y agresivo en la toma de decisión.

La temporada pasada jugó de delantero centro en el Castellón Cad. A, claramente es su posición. Fue el máximo goleador de su grupo en Cadete Autonómica.','RP','Seguir'),
  ('83b06267-c774-56b0-8ddb-f5fa5d60066e','3b5dc9c5-9c92-5083-80f8-0289e6a01243','2025-12-12 18:09:34','vs Moncadense','Central diestro, juega por izquierda. Biotipo bueno para posición: +-1.85 m, extremidades largas, delgado aunque potente, buena composición física. Buen ritmo aunque sin destacar por velocidad. Con balón da sensación de tener buen pie, aunque arriesga poco y suele buscar pases simples. Seguro en fase defensiva, sin gran trabajo en el partido.','NB','Seguir'),
  ('2601e02a-aec9-51eb-9cdb-bf7e24caf0f6','b49fc57f-0d10-539c-97e7-bd7b54db4857','2025-12-12 18:14:02','vs Moncadense','Jugador de buena técnica, recursos en 1v1, con buen golpeo de zurda. Creo que le falta mayor impacto en juego, tanto por trabajo defensivo como por incidencia real en posesión.','NB',NULL),
  ('d5672788-f34e-5ebc-acd7-1d520d56e1de','828d903c-17b3-5251-bc44-07d3510beece','2025-12-12 21:53:27','vs Valencia','Se nota mucho la diferencia física y técnica con respecto a los jugadores del Valencia.','NB','Descartar'),
  ('aeb9522f-6f15-522e-a10d-4e1d2e888a42','d798ec05-56a8-58d6-b29a-f7ccddd102d6','2025-12-12 22:36:48','vs Alcorcon','Extremo zurdo por derecha. Genera desequilibrio individual en 1v1, tanto en corto como en largo. Utiliza su potencia para imponerse. Acciones de calidad en centros, participa en ambos goles, trabajador en defensa.','NB','Firmar'),
  ('6c91a1ef-b6cd-54ff-b1df-f95da375b853','13a848f1-428b-5bcd-b641-49b608fc16ef','2025-12-13 14:03:02','vs Levante','Delantero centro de estatura cercana al 1.83 m, de gran musculatura, tren inferior muy potente, buen punto de agilidad y velocidad. Es jugador dinámico, activo fuera del área, capaz de generar por sí solo y que resolvió bastante bien dentro del área.','NB','Seguir'),
  ('82d0e541-fb90-54f7-9385-a4e218e8ce0a','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-12-13 14:06:26','vs Levante','#8 de gran perfil físico que genera en conducción por dentro, creando ocasiones de peligro. Intenso en fase defensiva.','NB','Firmar'),
  ('247a61e1-6e77-5da6-b337-f67b97773d24','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-12-13 14:11:06',NULL,'Corrector muy bueno gracias a velocidad y potencia. Es fuerte yendo al duelo, puede defender lejos de su área por velocidad. Le falta mejor lectura defensiva. Con balón progresa en conducción pero no tiene tanto pie. Buen central, bastante por debajo de Román','NB','Seguir'),
  ('7e8034dd-3e76-5976-b5d8-6c711fe2421c','b0a57561-e36d-52c3-a8f7-1e59c4f3a070','2025-12-13 14:13:13','vs Roda','Repito opinión. Es extremo que por perfil y características es muy interesante. Poco uso de pierna izquierda y toma de decisiones mejorable. Más allá de eso, muy rápido, explosivo y creador de ocasiones.','NB','Seguir'),
  ('dcd0a053-3210-56f5-885f-6e12f1096f04','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2025-12-14 10:51:44','vs Tavernes','Entra 20''. Jugador de buen perfil físico: es alto, fuerte, ya bastante hecho muscularmente, bien de ritmo y agilidad. Deja acciones interesantes en desequilibrio individual y asociándose hacia adelante. Bastante recorrido defensivo, sin tantos duelos. Quiero verlo de titular.','NB','Seguir'),
  ('adaa2434-06b0-5ff5-9667-1bf9006916d6','fa85303a-3bd7-52d6-8444-e2c8991e6128','2025-12-14 10:54:40','vs Tavernes','Central zurdo de buen biotipo: alto, de extremidades largas, delgado, con musculatura por hacer, OK de velocidad sin ser tan rápido como De Roa, por ejemplo. Calidad en salida de balón, donde tiene recursos para salir jugando, superar líneas y enviar pases largos. En defensa aún irregular, le falta punto de agresividad y mayor solidez en duelos.','NB','Seguir'),
  ('11af11f4-6cce-54b3-be03-7cb13324d698','70bc0460-fbc3-5e9f-ba03-c97d97e8fed9','2025-12-14 10:55:44','vs Tavernes','Jugador con calidad pero al que le falta ritmo y mayor incidencia en el juego. Le falta más consistencia y físico. Su carácter tampoco parece que sea positivo, en partidos cerrados participa menos.','NB',NULL),
  ('bfd08b82-4175-5aa2-9f49-9f3e0e0e1686','88d2d350-2a8b-5c7e-8c9a-32f2233e167e','2025-12-14 12:36:18','vs Sevilla','#6 de buen perfil físico (estatura ok, zancada, delgado, con musculatura por hacer), con dinamismo y recorrido sin balón.  Buen nivel técnico para asociarse y jugar hacia adelante. Sólido en duelos individuales. Perfil de 6-8.','NB','Firmar'),
  ('1ec1199f-4c51-51f5-a0f0-d9f91ff206e4','602698d7-57d1-5f3a-a279-2d0583ddfd4e','2025-12-14 12:41:53','vs Sevilla','Jugador de ataque, juega como extremo aunque en mi opinión es mejor por dentro ya que le falta punto de velocidad. Buen perfil físico a primera vista, dudas sobre si puede subir de ritmo y ganar esa explosividad. Tiene buen nivel técnico para asociarse y desequilibrar en 1v1, también para pisar área.','NB','Seguir'),
  ('af4d2b7e-3bca-5ab5-b3d4-ff2d9090c138','81960ae9-4519-5aff-bd49-b991748efd06','2025-12-14 12:46:19','vs Sevilla','Extremo diestro, que juega por izquierda. Buen manejo de ambos perfiles. Buen perfil físico, me gustaría ver en directo para medir mejor su velocidad en primeros metros. Jugador con buen manejo de balón, capaz de ganar metros en conducción y generar ocasiones. Buena finalización.','NB','Firmar'),
  ('df5f8338-f807-5838-8b17-3538752d1c6e','fbbd490a-6f4f-5bb1-9b8a-f1f13c50c4bf','2025-12-14 12:51:40','vs Betis','Delantero centro de buen perfil físico: grande, fuerte, muscularmente desarrollado, parece bastante ágil. Desde su entrada es el mejor jugador de su equipo, generando algunas ocasiones y participando en los dos goles.','NB','Seguir'),
  ('88fbe72d-63a2-57dd-a18c-cd400d40d4f8','5ee8a63e-d5b9-53d4-b349-9b25c76fcf56','2025-12-15 14:13:00','CASTELLÓN JUV. A - Patacona Juv. A (13/12/2025)','Central zurdo con una estatura superior a 1''85 m y complexión delgada. Con balón es bastante seguro e incluso aporta alguna ventaja en campo rival. Defensivamente le falta algo de contundencia.','RP','Seguir'),
  ('ed4889c4-64c3-52b3-9a05-108cb174e284','e7eb9a15-205a-5e70-9480-31de0c17dc6d','2025-12-15 14:14:06','CASTELLÓN JUV. A - Patacona Juv. A (13/12/2025)','Delantero centro diestro con un buen perfil fisico: estatura superior a 1''85 m y complexión fuerte. Va bien en duelos, ha dejado alguna acción con balón de calidad y ha marcado un gol en un rechace.','RP','Seguir'),
  ('669ccae7-082a-57e8-8cdf-36bbabbc2f66','f137f68e-faba-5fd4-afae-d1d06e0bd66b','2025-12-16 10:56:28',NULL,'Extremo zurdo, por derecha. Perfil físico promedio para posición: estatura media-baja, poco poderío, rápido, con aceleración, margen de crecimiento en fuerza y recorrido. Muestra cierta capacidad para desequilibrar en corto, con buen golpeo para sacar centros. Trabaja en fase defensiva pero le falta para imponerse en duelos.

Jugador que me recuerda a Pellistri por perfil. Con nivel para jugar en Primera RFEF o similares actualmente. Incluso en algún filial.','NB',NULL),
  ('7e1acc6a-e4a9-5873-955a-8de40f9af457','23355bf5-c220-535e-a3fc-3b650b85b822','2025-12-16 11:40:35','vs Racing','Lateral derecho de perfil físico  promedio: da sensación de +-1.75 m, complexión delgada, rápido y ágil. Con balón juega hacia adelante, es vertical en sus acciones, busca progresar en conducción y con pases. Debe crecer defensivamente, donde lo superan con facilidad en situaciones de 1v1.','NB',NULL),
  ('a2b3f547-6c69-5945-8c0e-30634d026b1f','a96a308e-4334-5155-9feb-29a735ebf46a','2025-12-16 12:11:48','vs Andorra','Mediapunta de estatura baja, tren inferior potente, rápido, con recorrido e intensidad. Jugador de buen nivel técnico, capaz de desequilibrar en 1v1, con gran golpeo de balón. Datos físicos por encima de la media de la competición.','NB','Firmar'),
  ('4c314b50-44c4-5fca-84a3-3e92346cce3c','12d6d728-f3fd-560e-b05d-e568b93e2657','2025-12-16 12:28:03','vs Andorra','Delantero centro de estatura alta, potente, de velocidad normal, dudas en aceleración en primeros metros. Postura algo encorvada, que ''afea'' un buen físico para posición. 

Juega fuera del área, alguna acción de espaldas e intentando conducir, sin mayor éxito. Tampoco dentro del área, donde no tuvo acciones.','NB','Seguir'),
  ('4808d2e1-cd2e-5d1b-a670-b1de1bd2a066','e5ababcd-cd27-520b-8f33-1dd5872c3831','2025-12-16 12:33:29','vs Valladolid','Extremo diestro por izquierda. Gran perfil físico para posición: estatura media, potente de tren inferior y superior, con fuerza para soportar choques, velocidad, aceleración y recorrido. Jugador de nivel técnico alto, desequilibrante en 1v1, capaz de generar ocasiones y finalizarlas.','NB','Firmar'),
  ('22373aac-5026-50be-abf5-6c127e29ae8a','25503073-c24a-5325-9daa-e101e0ecaa39','2025-12-16 17:50:40','vs Real Unión','Central diestro de buen prototipo físico: estatura de 1.85 m, de complexión fuerte, rápido, ágil, con potencial de salto. En salida de balón destaca por su capacidad para ganar metros en conducción y superar rivales en 1v1, le gusta tener presencia en campo rival. También buen pase largo. En acciones defensivas es agresivo, suele imponerse en duelos, puede defender hacia atrás y hacia adelante. Le falta mejor algún detalle, por ejemplo la defensa del atacante cuando está de espaldas, y crecer en timing…Pero es jugador de potencial alto.','NB','Firmar'),
  ('d4d1dfd7-0e98-515a-9f66-9128265f787f','5a451148-b24f-578a-ac88-fb2b3eacac50','2025-12-16 19:19:42','vs Solares','Extremo que se mueve bastante por zona interior. Perfil físico normal para posición: estatura media-baja, delgado, poco poderoso, sin ser especialmente rápido ni explosivo. Buen nivel técnico para asociarse. Le falta impacto.','NB',NULL),
  ('02f828b3-7f24-5ac6-a9f2-31d604c0036d','8bb372aa-26c5-5c1e-b32d-eb9d1e2657fe','2025-12-16 19:26:36','vs Solares','Delantero centro de estatura cercana al 1.80 m, de complexión fuerte, perfil físico parecido a Vinatea. Juega bien de espaldas, tiene recursos para proteger balón, sin ser capaz de generar ocasiones por sí solo con frecuencia. Buenos movimientos en área.','NB','Seguir'),
  ('fd21b903-f028-5e51-b87e-b75c7384d126','ceb7bffd-c4fc-5fc7-a43a-1088fcbc2a96','2025-12-17 09:25:54','vs Mosca','Juega de lateral derecho, fuera de posición habitual. Es rol que puede cumplir por poderío físico y comprensión del juego. Jugador que destaca por su potencial físico (es alto, fuerte, ágil). Tiene buen nivel técnico para avanzar con balón y jugar hacia adelante. Intenso en fase defensiva.','NB','Firmar'),
  ('3c0f3946-c2ea-5d37-a642-38a9bafa535f','23913533-4f13-5f12-ac06-3c4c9b9a4102','2025-12-17 09:32:39','vs Mosca','Mediocentro de buen perfil físico (+1.80 m, ágil, con recorrido). Da sensación de que le falta punto de intensidad y subir ritmo en ciertas acciones. Tiene técnica notable para  manejar balón, desequilibrar en espacios cortos y llegar a último tercio. Le falta más intensidad y orden en fase defensiva.','NB','Seguir'),
  ('25eea0e6-efbe-56f5-87d5-f26f0edf82ed','1048e894-8494-59c5-ab3b-509b0501cca7','2025-12-17 09:33:29','vs Mosca','Extremo zurdo por derecha. Perfil físico promedio para posición (estatura inferior a 1.75 n, delgado, con poco poderío, buena velocidad y aceleración). Tiene desequilibrio en 1v1 y sobre todo buen golpeo para terminar jugadas con tiros. Dudas sobre evolución física. Le falta.','NB','Seguir'),
  ('6a5f9f3d-a94c-57b6-9e11-51e2eccda54e','f455e623-550f-5ab1-b4cc-6e73f1585d54','2025-12-17 11:22:29','vs Sevilla C','Extremo de perfil físico medio (estatura media, delgado, no poderoso, buena velocidad aunque sin punto de explosividad). Extremo asociativo, con buen golpeo para pases y llegada al área. Le falta mayor poderío y más recursos en 1v1.','NB','Seguir'),
  ('8b84c1cb-a662-5cb7-8384-7b4df38c41ac','f80629a2-c942-5870-8d71-72dd46d6bf11','2025-12-17 11:24:45','vs Sevilla C','Lateral izquierdo de buen perfil físico (cercano al 1.80 m, de piernas largas, veloz sin ser explosivo, delgado, no poderoso). Juega hacia adelante, tiene buen nivel técnico sin ser excelente. Esforzado en ascciones defensivas.','NB','Firmar'),
  ('7b38be8e-ca5c-513c-9dae-a86d58bfe0cf','b569bf9a-8f39-5a81-b596-84b2e2db479f','2025-12-17 11:26:53','vs Cádiz B','Juega de extremo derecho. Por perfil físico e impacto en juego no me convence, creo que es tipo de jugador con tendencia a ir quedándose en el tiempo.','NB',NULL),
  ('da9a53a3-d78a-5755-8640-5db2d7469dbf','c09cf1a4-12ee-5527-9429-8e89ee694b25','2025-12-17 11:27:45','vs Cádiz B','#6 de estatura cercana al 1.80 m, complexión robusta, sensación de tener tendencia a eso. Es algo lento en desplazamientos largos. Le falta más pie en acciones de juego asociativo. Es agresivo en acciones individuales.','NB',NULL),
  ('b1f7a8e7-eea1-580a-8bb2-ddeed89fd7fd','86eefac0-5c60-5782-92bc-4b3ebb28eb1d','2025-12-17 12:42:34','vs Vilanova','Mediocentro de perfil físico medio: estatura de 1.80 m, fuerte, con recorrido, da sensación de algo lento en carrera y en gestos en general. Alguna acción positiva con balón, pero sin destacar por tener gran pie. En fase defensiva es intenso, agresivo para afrontar duelos. No me parece nada especial.','NB',NULL),
  ('5e899c3a-6127-531d-9372-37677011d2d1','ae08a545-77c6-5aaa-bf1b-0009c1d669e2','2025-12-17 12:45:00','vs Vilanova','#6 de estatura baja, potente sobre todo en tren interior, físico desarrollado, con recorrido. Normal, sin destacar.','NB',NULL),
  ('c8402343-66eb-5fb0-a9da-f63a4f326320','42e37ec9-1398-5113-adac-310d936c2f48','2025-12-17 12:46:10','vs Vilanova','Central de estatura cercana al 1.85 m, de complexión robusta, da sensación de algo pesado. Es agresivo para afrontar duelos individuales. Bien con balón, jugando hacia adelante. Sufre en alguna acción de cobertura de profundidad.','NB',NULL),
  ('5351a8b9-337b-591b-bddd-2054c1cde7ae','fde3e327-f6eb-5cf4-b8cc-108b58e5d2ad','2025-12-17 13:38:37','vs Castellón B','Extremo diestro, por izquierda. Buen perfil físico para posición: estatura media, biotipo delgado, bastante potente, muy rápido y explosivo. Generador de ocasiones, desequilibrante en 1v1, con recursos en corto y en largo. Llega al área con frecuencia. Muy diferencial en la categoría, con ritmo para fútbol profesional en corto plazo.','NB','Firmar'),
  ('a5fbe5a9-1a8c-5c15-892e-c6b92f0fd5fd','ca3f610e-0a3d-59fd-8fb7-79caa2f245ba','2025-12-17 13:43:25','vs Castellón B','Lateral derecho de buen perfil físico: estatura media-alta, de complexión delgada, fuerte, con recorrido, rápido sin ser explosivo. Destaca por sus cualidades con balón, tanto en juego asociativo como generando por sí solo. Llega con criterio a ataque. Explota espacios, tiene calidad para finalizar incluso. En fase defensiva se muestra serio, sin ser superado en el 1v1 ni en duelos individuales.','NB','Firmar'),
  ('68677212-aaa5-54b1-a77c-f81c49950426','42b4e2de-e909-57cc-9bd9-f72b4e9d1de5','2025-12-17 13:45:34','vs Castellón B','Perfil de #6-#8 de buen físico, dinámico, ágil, fuerte, con recorrido. Juega hacia adelante, supera bien presión rival, buena técnica individual. Intenso en duelos individuales, ganador, recupera, con recorrido. Es jugador para categoría superior.','NB','Firmar'),
  ('131effc3-122d-5bcb-914b-f1b90f8721ba','62fdd055-e4c2-5875-9052-62ab52b6cabe','2025-12-17 13:54:31','vs Girona','Central de mal físico, con poco potencial.','NB','Descartar'),
  ('daca1e25-83ce-5f55-96b0-f0d94cdf1ad7','385bd0c6-e2db-5f3e-a000-8d5ba4d12bec','2025-12-17 13:55:36','vs Girona B','Extremo de físico normal, le falta mayor poderío físico. Busca desequilibrar en 1v1, tiene regate, es creativo. Le falta punto de chispa en carrera. Está bien pero bastante diferencia con Hamony, por ejemplo, que es top de verdad.','NB',NULL),
  ('b9077ba4-c511-5fb0-8f9d-9b74b562ab8f','3d6f9d42-789a-5418-bd0c-050a335e3795','2025-12-17 13:59:40','LEVANTE JUV. B - Alzira Juv. A (16/12/2025)','Lateral diestro de estatura medio-baja, potencial 1''77, pero con un físico potente. Muy explosivo en primeros metros, tanto en ataque como en defensa, y fuerte para ganar duelos. Recorrido largo y físico para repetir esfuerzos. Técnicamente está bien y es atrevido con balón para asumir ciertos riesgos en campo propio y ofrecer soluciones diferentes en el último tercio.','RP','Firmar'),
  ('cf4fbe16-6e43-5faf-a2bb-b1ff2464a781','f164647d-f803-5042-95f8-3aedd0af0fb9','2025-12-17 14:06:39','LEVANTE JUV. B - Alzira Juv. A (16/12/2025)','Lateral izquierdo de estatura media, pero con un físico potencialmente bueno para la posición. Rápido para corregir e incorporarse al ataque, técnicamente muy bien y con mucha personalidad para jugar por dentro y acelerar jugadas por fuera. Siempre mira hacia delante y busca hacer progresar al equipo.','RP','Firmar'),
  ('d8ae4cf1-8970-5675-9a20-b29d6b435496','7ffb55c7-f547-5935-97d7-e102efdc42fe','2025-12-17 14:08:05',NULL,'Extremo de físico promedio para la posición: estatura baja, delgado, rápido. Su mayor virtud es la capacidad de conducción, tiene llegada a línea de fondo, suele buscar centros. No le veo mayor recorrido en fútbol profesional.','NB','Descartar'),
  ('8851f197-1102-5914-875e-79d1ab5b43f4','a266b3f3-3190-59d6-875d-9ec9264de6f1','2025-12-17 14:10:34','LEVANTE JUV. B - Alzira Juv. A (16/12/2025)','Extremo zurdo, bajito y con un perfil técnico muy bueno. Ha marcado un golazo de falta y es el que ofrece recursos más diferentes en el ataque del Levante. Me recuerda a Luismi, pero no lo veo tan determinante ni fuerte físicamente.','RP','Seguir'),
  ('66096a8a-50fd-5897-ac11-619ad61cf7d7','934a8b03-0d55-5c05-a684-b5988b52efbe','2025-12-17 14:22:01','Levante Juv. B - ALZIRA JUV. A (16/12/2025)','Central diestro con una estatura alrededor de 1''85 m y complexión fuerte. Bien en duelos y con un despeje potente.','RP','Seguir'),
  ('50d4f6a4-f655-5634-aec1-3cffc0ee38e9','8305bb0e-d392-5900-bba5-f229a2426893','2025-12-17 15:15:27','LEVANTE CAD. A - El Rumbo Cad. A (16/12/2025)','Central zurdo de algo más de 1''80 m de estatura, con potencial de 1''85 m, y complexión delgada pero fuerte. Notable con balón, con calidad y personalidad para asumir riesgos y batir línea. Bastante ganador en duelos y bueno en la acción defensiva, aunque con algún error de lectura.','RP','Seguir'),
  ('4f8268e7-3a0d-56c2-8ab4-5e88f80a1d64','33aab9a1-13fa-587d-84c0-07b3f64a1680','2025-12-17 15:18:55','LEVANTE CAD. A - El Rumbo Cad. A (16/12/2025)','Centrocampista diestro de segunda/tercera altura. Estatura alrededor de 1''75 m y físico muy fino. Técnicamente notable y muy plástico con el balón, tiene una muy buena capacidad para escapar de la presión y juega a ritmos muy altos. Acelerador de jugadas.','RP','Seguir'),
  ('51a9cc98-6de0-57ca-a32c-1faf9414b3de','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2025-12-17 15:52:00','vs Atlético B','Centrocampista que puede desempeñar función de #6 - #8. Buen perfil físico para la posición, con buena técnica, capacidad para soltarse en ataque y llegar a último tercio. Con recorrido defensivo, intenso en duelos, recuperador. Es jugador de potencial alto.','NB','Firmar'),
  ('e2691736-0e24-5081-88af-fca04ec44fab','46a6bf26-3ba7-5012-aefe-220de85ca247','2025-12-17 15:53:43','vs Atlético B','Juega de lateral derecho, da sensación de algo pesado para la posición. Defensa de 1.90 aprox, muy fuerte. Poco impacto.','NB',NULL),
  ('f6113347-db73-5160-b25b-1afa083280f7','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2025-12-17 15:54:50','vs Atlético B','Opinión similar a veces anteriores. Le falta punto de explosividad, es jugador algo pesado para la posición. Tiene buena técnica, es creador de ocasiones y tiene gran golpeo.','NB','Seguir'),
  ('ebf62ffb-6e3d-5ad8-a190-14b16c1a32b7','c6e3f413-7b7b-57bc-a75f-cac9750248ea','2025-12-17 15:55:52','vs Atlético B','Extremo de estatura baja, poco poderoso, rápido, con calidad. El físico lo condiciona','NB',NULL),
  ('66c47359-c25b-5a87-a8a7-417ac92148dc','c1d6f6b6-1b7f-5cdc-9d59-c1ba85a73a87','2025-12-18 07:32:43','vs Torrejón','Central derecho por izquierda. Buen perfil físico para posición: cercano al 1.90 m, de complexión fuerte, bien compensado muscularmente, bien de agilidad y velocidad. Tiene recursos en salida de balón, capaz de ganar metros en conducción y dar pases por dentro. Es fuerte para afrontar duelos individuales.','NB','Seguir'),
  ('569a34c4-9541-5476-a050-8733d1593f5f','09a1829b-dd76-5ff6-bf8f-fc4d4fd7a9d7','2025-12-18 07:35:57','vs Torrejón','#6 de buen perfil físico, buen nivel técnico y trabajo defensivo. Primero como #6 (su posición natural) y después central. Me gustaría verlo más.','NB','Seguir'),
  ('9b97e498-188b-5ffe-a1e2-467ba274707a','e52a963b-e596-5bc9-9c92-36f79b880ac6','2025-12-18 07:37:40','vs Torrejón','#8 de físico fuerte (estatura media, robusto, dinámico) con buen juego entre líneas, recursos para conducir, girar y terminar jugadas con remate o último pase. Intenso en fase defensiva, le puede faltar mayor recorrido.','NB','Seguir'),
  ('ccb1ccc3-6591-5a22-a05e-73c8d9d81b90','5ac693e1-ede7-5532-846f-531665308edc','2025-12-18 07:41:33','vs Torrejón','Juega de #10. Buen perfil físico (buena estatura, delgado, ágil, rápido para jugar por dentro). Muy creativo, con gran nivel técnico, recursos en 1v1, creador de ocasiones, llegador. Además, notable evolución sin balón con respecto a Málaga.','NB','Firmar'),
  ('90cdd6ab-f23e-51d5-a424-3b13aeb2108b','7bf8ef85-d24d-53d4-9bce-005f1e8aadb7','2025-12-18 07:43:31','vs Torrejón','Extremo derecho. Perfil físico normal para posición (bajito, sensación de potente, rápido, explosivo). Tiene 1v1, genera en regate, capacidad para centrar.','NB','Seguir'),
  ('3fe24d0e-32c4-5c62-b127-904a79afde51','1aca58d4-6e8b-580c-8ecd-cbc7cb862dd7','2025-12-18 07:46:07','vs Torrejón','Extremo de buen biotipo (es alto, fuerte, rápido) capaz de ganar metros en conducción y explotar espacios. Llega hasta línea de fondo y saca buenos centros de izquierda, jugando a perfil natural.','NB','Seguir'),
  ('c761f4f9-41ef-591e-b011-6835a4695def','af06e69a-152a-534f-8118-fad6d3713b69','2025-12-18 07:49:11','vs Torrejón','Centrocampista que puede jugar en las 3 alturas, seguramente ideal como #8. Gran perfil físico (es alto, fuerte, ágil), con buen nivel técnico para asociarse y generar por sí solo, sobre todo en conducción. Buen golpeo desde fuera del área.','NB','Firmar'),
  ('36677804-c9fc-5388-9e21-dc926bd047ab','2d368c13-58ad-5ffc-9a63-dfc64b4eb9bc','2025-12-18 07:51:20','vs Torrejón','Extremo de estatura baja, delgado, rápido y explosivo. Muy creativo en el regate, habilidoso en el 1v1. Le falta poderío y mejor toma de decisiones.','NB','Seguir'),
  ('e4e65b45-3d0e-5ff1-a035-ea98efce0762','0ced2d83-2178-5391-905e-7ac9f55837be','2025-12-18 09:59:43','vs Leganes Juv A','Perfil #8 - #10 de físico normal (estatura media-baja, delgado aunque fuerte, con recorrido, sin destacar especialmente por biotipo). Tiene gran nivel técnico y capacidad para llegar a área rival. Repertorio para finalizar.  Dudas sobre físico.','NB','Firmar'),
  ('ccbd0987-fdc5-54d4-8d5f-c5f55a81a608','d0b0577d-baa1-5a77-b86b-e9127670c505','2025-12-18 10:09:23','vs Leganés','Central de perfil físico top para posición, recursos para progresar con balón, sólido en duelos, fuerte por arriba. Potencial alto.','NB','Firmar'),
  ('bbfd2804-0edb-5844-ba78-3e8dd4a2dce6','f137f68e-faba-5fd4-afae-d1d06e0bd66b','2025-12-18 12:01:32',NULL,'Extremo zurdo bajito, pero con una complexión relativamente fuerte y un buen tren inferior, capaz de soportar choques, aunque tiene margen de mejora en esto. Con balón es técnico y tiene un buen cambio de ritmo para superar rivales y buscar centro, normalmente con bastante buena tensión y dirección. Por características encaja mejor a pierna cambiada, pero creo que podría rendir bien a pie natural. Es bastante agresivo en la toma de decisión. 

En defensa es trabajador y va fuerte al duelo, aunque le falta un punto en este aspecto. 

Está jugando muy poco, pero la temporada pasada generó dos goles (1G y 1A) en algo más de 180 minutos siendo su primer año senior. Potencial jugador de primera división si consigue buenos minutos en los próximos dos años.','RP','Decidir'),
  ('bf576be4-83e7-5bf8-8858-7389ee307119','626057b1-39f9-57ef-966c-4b10ea5c7006','2025-12-19 16:47:37','CORNELLÀ JUV. A - FC Barcelona Juv. A (13/12/2025)','Central diestro con una estatura algo superior a 1''80 m y complexión fuerte. Físicamente recuerda a Michael Romero. Es rápido y tiene una lectura y técnica defensiva bastante correctas. Buen desplazamiento en largo.','RP','Seguir'),
  ('c8161429-a904-5d68-9971-bc12f1b3e6fe','048e23bc-3b48-5e34-ba87-782765eb9592','2025-12-19 16:52:56','CORNELLÀ JUV. A - FC Barcelona Juv. A (13/12/2025)','Delantero centro diestro con una estatura alrededor de 1''80 m y complexión fuerte. Es rápido en carrera y muy agresivo en el duelo. Choca fuerte y protege bien la pelota. En el partido tiene algunas buenas acciones de conservación de balón y descarga. En la segunda parte pasa a la banda izquierda.','RP','Seguir'),
  ('6fd11c48-3d6a-5973-92a0-7c51fc2acaae','03c3667a-82eb-5c9f-92e8-67d3d79fca5b','2025-12-19 16:55:07','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Lateral derecho de perfil físico medio-bajo. Técnica correcta y cierto recorrido, pero nada especial.','RP',NULL),
  ('c92f08f7-b174-555d-a00a-49f008c07d4f','cf3a8e8a-a043-5a3e-8037-9e2154369985','2025-12-19 16:56:16','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Central zurdo con una estatura algo superior a 1''80 m y complexión delgada pero fuerte, con margen de crecimiento en este sentido. Es rápido, corrige muy bien la posición y es bastante contundente en duelos, con un buen timing y una buena intensidad. Con balón es notable, siendo capaz de mejorar jugadas y batir líneas a través de la conducción y el pase.','RP','Firmar'),
  ('9d436cf8-1b24-52c8-bb55-207c280a061e','98e20e08-0a75-5df1-9d66-2679a6a6a4dd','2025-12-19 16:59:19','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Lateral izquierdo de perfil físico medio en cuanto a estatura y complexión, pero bastante rápido y con un gran dominio del juego aéreo. Muy bien técnicamente, tiene bastante recorrido y es agresivo en la toma de decisión con balón y en los movimientos en ataque sin él.','RP','Firmar'),
  ('d1986ff4-8a99-5837-a82e-5aa52faa4718','15c931ac-6a62-54e8-838d-f6302eccd15d','2025-12-19 17:01:37','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior. Perfil físico medio en cuanto a estatura y complexión. Bien técnicamente y bastante acertado en la circulación, aunque le falta un punto de peso en el último tercio.','RP','Seguir'),
  ('7c87d4b1-3257-533c-8089-8634969566ee','be7d6b5d-248c-5984-a652-3dafc7472d3d','2025-12-19 17:04:14','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Delantero centro diestro con una estatura alrededor de 1''80 m y complexión fuerte. Es rápido en carrera y va bien a duelos, chocando fuerte y protegiendo bien el balón. En el partido deja algunas buenas acciones de descarga.','RP','Seguir'),
  ('a7fc2ac4-86b0-5055-b819-1dec698bf92f','d2477de6-05aa-5464-baad-c6829e0d4d5d','2025-12-19 17:06:14','Cornellà Juv. A - FC BARCELONA JUV. A (13/12/2025)','Centrocampista de segunda tercera altura, en el partido actuando como interior con llegada. Perfil físico medio. Buena técnica para conducir, pasar y desbordar en ciertos contextos.','RP',NULL),
  ('479f3df6-f64c-521a-99e9-3be473d4a88c','13a848f1-428b-5bcd-b641-49b608fc16ef','2025-12-20 23:23:19','vs Valencia','Delantero centro de buen biotipo físico: estatura de 1.83 m aproximadamente, de complexión robusta, gran musculatura de arriba y abajo, es rápido, con aceleración en primeros metros. Tiene recursos para el juego de espaldas, donde es capaz de girar, generar faltas y darle "oxígeno" a su equipo, también combinar fácil. Es veloz para ir al espacio, debe crecer en finalización aún.','NB','Seguir'),
  ('f6aba7e8-f4ab-5a87-ae7f-baffa4e5ce86','a2c52aae-d8d1-5621-9d82-96ad09e4f379','2025-12-20 23:26:16','vs Valencia','Romero: Central diestro de gran perfil físico (estatura aprox. 1''88 m, gran musculatura, con buena velocidad punta y agilidad). Es agresivo para afrontar duelos, buen corrector, defiende la profundidad con eficacia. Le falta mejorar conceptos (timing, defensa de área…). Con balón no destaca, juega hacia adelante pero sin crear grandes ventajas.','NB','Seguir'),
  ('cdd9b71f-4ad4-5608-96e0-65abf107eecd','ae1103cb-1258-5669-8b41-8e67a9cdb7b7','2025-12-20 23:27:40','vs Valencia','Lateral izquierdo de estatura cercana al 1.80 m, complexión robusta, rápido, no explosivo, con recorrido. Vertical en acciones con balón, juega hacia adelante, capaz de generar en conducción. En fase defensiva le falta mayor solidez en 1v1.','NB',NULL),
  ('d89b0be9-a2b8-59d6-af37-4e4ae9da5736','61bacbb6-8b01-5917-8d00-f7c34cd49000','2025-12-20 23:31:44','vs Valencia','Barella: Extremo de estatura baja, complexión delgada, rápido, explosivo. Zurdo por izquierda. Poco uso de derecha. Jugador vertiginoso, desequilibrante, con 1v1. Capaz de generar ocasiones de forma individual. Le falta punto de toma de decisiones y capacidad de finalización.','NB','Seguir'),
  ('e9ef8dd1-f264-5d00-9624-b86617478b89','2bc000e3-d8ac-5533-989e-5ad48da97d8b','2025-12-20 23:34:26','vs Valencia','Carrasco: perfil de #8 de gran físico (alto, fuerte, ágil, con recorrido). Aún con margen para crecer. Vertical en acciones, juega hacia adelante, genera en conducción, llega a último tercio. Es esforzado en fase defensiva, afronta duelos con agresividad, bien en presión y hacia atrás.','NB','Firmar'),
  ('ef17cba5-0a8b-52ba-a5aa-a5b2d9e835e7','aeb8cbbd-3d9c-5a3f-ace7-0cc1a7163b2a','2025-12-20 23:36:32','vs Roda','Central derecho. Con problemas en defensa de profundidad y leyendo pases cruzados, le generaron bastante peligro pese a que el contexto era cómodo para ellos. Es fuerte pero lento y poco ágil de movimientos.','NB',NULL),
  ('fb839e03-71de-5012-99a7-038692764313','07db410c-c4db-5120-9f0d-11e24b5d75a3','2025-12-20 23:37:16','vs Roda','Central zurdo de gran capacidad en juego asociativo. Recursos para generar ventajas en salida, con pases y conducciones. Cada vez con mejores decisiones. En defensa irregular en duelos, aunque con clara evolución en cuanto a agresividad y fortaleza.','NB','Firmar')
ON CONFLICT (id) DO NOTHING;

INSERT INTO scouting_reports (id, player_id, fecha, titulo, texto, persona, conclusion) VALUES
  ('66235d6e-de2d-5c34-a9d5-4e92e17e3465','b8b8aa80-d41b-58e1-939d-33d8eeeed79d','2025-12-20 23:40:06','vs Roda','Juega de extremo izquierdo, metiéndose mucho por zonas interiores.  Gran nivel técnico, capacidad asociativa y movilidad. No es extremo puro, no tiene esa chispa necesaria para ser de banda total. Aún así es jugador diferencial. Trabajador en defensa, aunque no parezca.','NB','Firmar'),
  ('254e1fab-87ed-56d9-aa87-448c4d5895b2','83ebd693-dff5-55ee-8331-5753ec2fe001','2025-12-20 23:44:44','vs Castellón','Mauro Roca: extremo de condiciones físicas muy buenas (1.80 m aprox, muy rápido, de complexión delgada pero fuerte, con recorrido). Jugador "robótico", de buena técnica aunque con recursos limitados en 1v1 como tal. Peligroso yendo al espacio, con buena capacidad de finalización. Buen trabajo defensivo.

Lo veo con posibilidades de ser profesional aunque en posiciones más atrasadas.','NB','Seguir'),
  ('464eff2d-9de2-5b86-9b68-a1b57633ed0d','1a633f3b-0484-5887-82c4-a60cc6f7af51','2025-12-20 23:46:43','vs Castellon','Mediocentro perfil #8 de físico ideal, también adaptable a otras posiciones (en banda, incluso segundo punta). Jugador de gran perfil físico, destaca por su zancada. Llega a área rival con frecuencia. Intenso en fase defensiva. Es completo y de potencial alto.','NB','Firmar'),
  ('19577e5d-43ea-58a0-b705-65760190ff34','bad86b19-1215-59c8-9e23-f100919fda68','2025-12-21 09:33:20','vs Japon','Lateral izquierdo de buen perfil físico para posición: estatura media-alta, complexión delgada, fuerte, rápido, con recorrido. Con recursos técnicos notables para asociarse, progresar y llegar a ataque. Es aplicado en defensa, ganador de duelos, buen recuperador.

Firmó con Niagara el 21/02/2024','NB','Firmar'),
  ('7ce2accf-fb20-53e3-a774-a2fb9d1805d6','c77695e6-b66f-50c1-9545-8cef3d7230c8','2025-12-21 09:35:44','vs Japón','Mario Rivas: central de buen perfil físico, sin ser excelente para posición. Sensación de estar en 1.85 máximo. Complexión delgada, aunque fuerte. Es rápido y ágil. Puede defender lejos de su área con solvencia, es agresivo en duelos. Con balón progresa en conducción y con pases entre líneas. Tiene gran pase largo.','NB','Firmar'),
  ('0bdbbd16-e4bc-5513-8c1b-2fa5be46f31c','d7f29410-9a41-5ee0-980a-f9a9b8037b73','2025-12-21 09:37:03','vs Japón','Lateral derecho de perfil físico ok, jugador asociativo, con recursos para participar en circulación, superar presión y sumarse a ataque. No tiene gran rendimiento defensivo.','NB',NULL),
  ('f05efbe6-c2f1-5a31-9308-10ea8b44ce8b','4927782b-b372-5985-870c-e0265752ebaa','2025-12-21 09:39:55','vs Japón','Yáñez: Atacante zurdo, primero de mediapunta y después de extremo derecho. Perfil físico medio para posición (estatura baja, poco poderío, aunque rápido y explosivo). Es jugador de gran nivel técnico, desequilibrante en 1v1, con recursos para generar ocasiones y finalizar. Productivo en último tercio.','NB','Firmar'),
  ('67bb2932-da9d-556c-97a5-3a67f99d1717','f1af55bb-1d78-5613-aa60-f94f30644482','2025-12-21 09:45:58','vs Japón','Extremo diestro de buen perfil físico (estatura 1.80 m aprox, complexión fuerte, potente, de buena velocidad aunque sin ser explosivo. Da sensación de que le falta punto de chispa). Atacante agresivo para buscar el 1v1, con recursos para desequilibrar, de nivel técnico adecuado para realizar pases, controles…Peligroso yendo al espacio. Su mayor punto de mejora es la toma de decisiones y la capacidad de finalización. Por condiciones físicas lo veo con bastantes posibilidades de ser profesional.','NB','Firmar'),
  ('c3674f79-1522-55c5-abfe-a1d21163ceee','c058cc00-b874-53d4-a2c0-2a7e250d78af','2025-12-21 09:48:48','vs Japón','Extremo de perfil físico medio para posición (estatura baja, delgado, poco poderoso, rápido y explosivo). Con buen nivel técnico para controles, pases, tiros…Y agresivo para  afrontar 1v1, creativo en el regate. Buena llegada al área. La duda es el físico pero aún así creo que es futbolista con potencial primer equipo.','NB','Firmar'),
  ('8292726b-c19f-5f99-b656-3838337d2f3e','b0a57561-e36d-52c3-a8f7-1e59c4f3a070','2025-12-21 18:17:13','vs Elche','Aldi: Extremo diestro por izquierda. Perfil físico positivo para posición: estatura media, muy rápido y explosivo, con recorrido, complexión delgada aunque con musculatura y potente. Es jugador desequilibrante en conducción gracias a su velocidad, también en 1v1. Además ha crecido notablemente en finalización.','NB','Firmar'),
  ('54a6c351-b79e-5a64-a938-fe8d01116d26','976ae02f-ae62-5a8e-b573-ba60c990b08d','2025-12-21 21:45:07','vs Betis','Extremo de físico potente, entra desde el banquillo. Poco impacto en minutos jugados, no pudiendo superar a De Roa en el 1v1. Ver más, supuestamente fichado por el Betis.','NB',NULL),
  ('bc4b9641-d942-5199-9194-3b0985306a85','b0a57561-e36d-52c3-a8f7-1e59c4f3a070','2025-12-21 22:46:40','General','Jugador muy rápido y desequilibrante en 1v1, no tiene un perfil físico muy poderoso pero es vertical en acciones de duelo y buena toma de decisiones post regate.','PP','Seguir'),
  ('be5719ff-e71a-515b-b7d7-08984f9cd74e','4c0a0c63-8caa-53c0-91bb-0d9660c23d0b','2025-12-22 10:02:05','vs Racing Zaragoza','Buen perfil, tecnico. Y jugador con una excelente trato de balon, con dudas para ganar duelos y a nivel fisico.','AV','Seguir'),
  ('b7f2a8bd-9a2b-5e3f-b1bf-f5a4632feef9','6f05c97a-1fc2-52f9-b757-802419cfee54','2025-12-22 10:55:38','ELCHE CAD. A - Primer Toque Cad. A (20/12/2025)','Centrocampista zurdo de segunda altura, en el partido actuando como interior con recorrido. Estatura algo inferior a 1''80 m, con potencial para llegar a 1''83 m, y complexión delgada pero fuerte. Nivel técnico muy elevado y gran criterio y personalidad con balón para aguantarla, escapar de presiones y encontrar soluciones para mejorar la jugada. Buen timing. Va bien al duelo.','RP','Seguir'),
  ('cedcf54e-7193-5ec3-ba22-b1b9f65e028e','f581e29e-f903-5191-8d39-dd5ae4bd5931','2025-12-22 15:29:31','ELCHE CAD. A - Primer Toque Cad. A (20/12/2025)','Central diestro de estatura algo inferior a 1''85 m, con potencial de 1''87, y complexión más o menos fuerte. Tiene buenas condiciones, transmite seguridad y mucha confianza en las acciones con y sin balón.','RP','Seguir'),
  ('a2ab1954-86bb-5abe-836b-d508cec6ebb1','3f92ad96-76dd-5776-87e8-71480cebffad','2025-12-22 15:38:28','ELCHE CAD. A - Primer Toque Cad. A (20/12/2025)','Delantero centro zurdo con un perfil físico espectacular: estatura superior a 1''85 m y complexión muy fuerte, pesado de movimientos pero rápido en carrera. Es agresivo y tiene cierta calidad y criterio para aguantar la pelota de espaldas y descargar. En área le falta instinto para los movimientos.','RP','Seguir'),
  ('14634fc6-be15-5e27-a74c-2a9121547238','26bad713-122f-5f1e-899f-a048c4e9fcd5','2025-12-22 15:40:32','CASTELLÓN CAD. A - Don Bosco Cad. A (21/12/2025)','Centrocampista diestro de segunda/tercera altura, en el partido actuando como interior/enganche con bastante recorrido. Perfil físico interesante: estatura alrededor de 1''80 m, con potencial 1''85 m, y complexión delgada pero fuerte. Buen trato de balón, participa a varias alturas y es muy agresivo en el duelo.','RP','Seguir'),
  ('055a6425-228f-5063-943f-deb3410082e8','dd9401aa-de34-52ee-ba27-81900b71c7d7','2025-12-22 15:44:06','CASTELLÓN CAD. A - Don Bosco Cad. A (21/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Perfil físico medio-bajo: estatura inferior a 1''70 m y complexión muy ligera. Trato de balón sobresaliente y mucho criterio para la distribución. Tiene mucha calidad para escapar de presiones y bastante peso en el juego.','RP','Seguir'),
  ('04885d61-f822-5ec0-b7d5-70a1fc0024eb','56bd0455-c4b6-5a47-93fb-bf0fa60c78ae','2025-12-22 15:52:17','El Rumbo Juv. A - VILLARREAL JUV. B (21/12/2025)','Centrocampista diestro con capacidad de influir en las tres alturas del centro del campo desde una posición de interior o en doble pivote. Estatura cercana a 1''90 m, complexión fuerte. Ganador de duelos y buen trato de balón, tomando buenas decisiones y con un buen nivel técnico para dar continuidad al juego y ayudar al equipo a ganar metros. Ha dejado algunas conducciones espectaculares, dejando hasta tres rivales detrás.','RP','Firmar'),
  ('68d1861e-3ac5-5795-b91d-73f73b215dfd','70bc0460-fbc3-5e9f-ba03-c97d97e8fed9','2025-12-22 15:54:10','El Rumbo Juv. A - VILLARREAL JUV. B (21/12/2025)','Centrocampista zurdo de segunda/tercera altura, estilo interior con llegada o mediapunta. Estatura algo por debajo de 1''80 m, complexión delgada pero fuerte. Técnicamente sobresaliente y con mucha creatividad y criterio con balón para mejorar jugadas constantemente. Muy peligroso en la frontal del área desde el último pase y el disparo.','RP','Firmar'),
  ('9fc08c9e-fb9e-58f6-b33c-cdcf523ffe96','24c00223-606d-5dc5-a82c-4af68b159afb','2025-12-22 15:55:44','El Rumbo Juv. A - VILLARREAL JUV. B (21/12/2025)','Centrocampista zurdo de primera/segunda altura, para actuar como mediocentro o en doble pivote. Estatura cercana a 1''90 m y complexión fuerte. Jugador de una enorme jerarquía, sobre todo con balón, con un dominio y un criterio notables. Bien en duelos, aunque no destaca por ello.','RP','Firmar'),
  ('20a8e1d9-5eb7-57f3-8923-98dfa8f9a770','0db04bac-6b60-5bb5-b5f7-de00dcf9402f','2025-12-22 15:56:24','El Rumbo Juv. A - VILLARREAL JUV. B (21/12/2025)','Lateral izquierdo de estatura alrededor de 1''75 m y físico ligero. Ágil y muy bueno técnicamente, con personalidad para tratar de mejorar jugadas desde la base y en todas las alturas del campo. Mucho recorrido, buen físico para repetir esfuerzos. Lo que no me convence es que tenga a Pilili por delante en la estructura del Villarreal.','RP','Seguir'),
  ('2e40b8e9-8e88-56ae-93d7-70dbbd340ca1','ceb7bffd-c4fc-5fc7-a43a-1088fcbc2a96','2025-12-22 17:19:47','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Lateral derecho con una estatura alrededor de 1''80 m y complexión delgada. Muy seguro con balón, participa con acierto en la salida de balón y en la construcción del juego. En campo rival, sin ser demasiado insistente en el desdoblamiento, sí sabe cuándo ocupar posiciones adelantadas y tiene recursos para mejorar jugadas, desbordar a su par y meter centro. En defensa tiene un nivel de activación muy bueno y explosividad para ser fiable en el 1vs1. 

Lateral de buen rendimiento que con un correcto desarrollo puede terminar siendo muy importante.','RP','Firmar'),
  ('3a17c65c-23a8-50e3-ae3c-6db8e39838e8','7526f789-dbdb-5603-852d-c4845096ab38','2025-12-22 17:23:43','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Centrocampista de primera/segunda altura, para actuar en doble pivote o como interior. Perfil físico medio. Buen manejo de balón y criterio para distribuir.','RP',NULL),
  ('7706e3ce-c092-5466-a3cf-1e57ca913108','7bbf912f-80a7-58f0-906d-1b654fb6018a','2025-12-22 17:24:57','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Centrocampista de segunda/tercera altura, para actuar como interior con cierto recorrido. Buen manejo de balón, sabe sumar intervenciones con acierto en campo rival, pero sin demasiado peso.','RP',NULL),
  ('7327fad5-3500-52a8-8e6b-d1b28c775a92','af5127f4-7f26-5a9d-adb6-623f12694c8c','2025-12-22 17:26:27','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Extremo diestro, en el partido actuando a pierna cambiada. Estatura inferior a 1''70 m y físico más o menos preparado para resistir choques, pero sin destacar. Tiene calidad técnica, llegada y agresividad con y sin balón. No parece excesivamente rápido.','RP','Seguir'),
  ('ce45d0ad-487a-5526-beaa-b5a4e79d9ee5','43479982-bcdd-5184-b814-a84af3ab5dba','2025-12-22 17:27:56','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Central diestro con una estatura cercana a 1''90 m y complexión fuerte. Contundente en el duelo y muy seguro tanto en la acción defensiva como con balón. Mucha presencia.','RP','Firmar'),
  ('56af392a-f13b-54c5-8711-d852396f930e','98a9b155-2038-52c0-b0da-1055c9b14033','2025-12-22 17:29:21','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Delantero centro diestro con una estatura superior a 1''85 m y complexión fuerte. No he tenido tiempo de evaluar demasiado en los minutos que ha tenido, pero el perfil llama la atención.','RP',NULL),
  ('35e8f964-9465-5d0f-8904-085d2a041cc7','1048e894-8494-59c5-ab3b-509b0501cca7','2025-12-22 17:31:23','SEVILLA JUV. A - Vázquez Cultural Juv. A (21/12/2025)','Extremo zurdo, en el partido actuando a pierna cambiada. Estatura alrededor de 1''70 m y complexión delgada. Nivel técnico muy elevado para conducir con la pelota pegada al pie y para realizar pases de mucha calidad en el último tercio. Agresivo en la toma de decisión. Quizás le falta un punto de velocidad/explosividad.','RP','Seguir'),
  ('1c15d3ff-3d3c-58eb-aa54-b5c769430626','4f29aa3c-9e99-508a-9f86-146d39c20900','2025-12-23 13:20:36',NULL,'Delantero centro de buen perfil físico (estatura superior al 1.80 m, muy fuerte, de complexión robusta, buen punto de velocidad). Juega bien de espaldas, sin tener nivel técnico top es capaz de generar en 1v1 y conducción. Tiene buenos movimientos y repertorio dentro del área.

Es delantero que por características y perfil físico tiene posibilidades de asentarse en primer equipo.','NB','Firmar'),
  ('c177ddf6-3ce0-5eaa-9834-124512f0ed45','3cfaf681-48d0-53e4-b400-e3b8e91be3a1','2025-12-23 13:45:24','vs Ourense','Delantero centro de perfil físico top (1.92 m, grande, fuerte, velocidad normal) que hace doblete, con buena presencia en área y superioridad en duelos. Por perfil es muy interesante.','NB','Firmar'),
  ('29a014ea-467e-5585-93c9-62c81e72bb80','00767957-9359-5a69-a4d9-49f8ab98cfa8','2025-12-23 13:51:38',NULL,'DEBUT EN SEGUNDA RFEF','NB',NULL),
  ('bfb0ab0f-1edc-5807-b861-78cd2b772253','dbd33a94-f4da-5c1e-a800-1f5f161a7ff4','2025-12-23 15:05:31','vs Mancha Real','Delantero centro de perfil físico top para posición. Sin tener tanta participación (juega segunda parte) deja acciones interesantes de espaldas, atacando profundidad y generando por sí solo.','NB','Firmar'),
  ('7517b428-8c9c-50f1-ab60-ad44e8e48a3f','3e396cdd-7cfd-5984-b4ac-23433caf2d6f','2025-12-23 15:07:17','vs Mancha','Entra en 60'', primero por derecha, después por izquierda. Poco impacto en juego. Buen perfil físico, aunque le falta punto de explosividad. Buen nivel técnico, vertical, juega hacia adelante, tiene 1v1, busca finalizar.','NB','Seguir'),
  ('dce9f08b-2b16-5b25-97c2-5efbd2bff518','c6fa1037-44ec-5e3e-aaef-7b3246aa2b76','2025-12-23 15:09:39','vs Mancha','Central izquierdo de biotipo top para posición: es alto, de piernas largas, complexión delgada, musculatura por hacer, rápido, con aceleración. 

Deja sensaciones positivas en duelos individuales, mostrándose más seguro que en partidos anteriores. Es proactivo para salir de zona y anticipar. 

Con balón suele buscar progresar, intentando pases largos con precisión irregular hasta ahora. Me parece perfil de potencial primer equipo.','NB','Firmar'),
  ('76e792ee-2f40-5d56-9559-6b762a80bca0','1b5e18ea-2c3c-5906-83b6-8549c5bc83d8','2025-12-23 15:13:06','vs Mancha','Perfil físico mejorable, estatura baja, poco poderoso. No genera impacto significativo.','NB',NULL),
  ('437e8642-7ef5-5352-a151-0d90daa37048','3e396cdd-7cfd-5984-b4ac-23433caf2d6f','2025-12-23 15:46:57','Huétor Vega - GRANADA B (15/10/2025)','Extremo diestro, en el partido actuando a pie natural. Estatura algo inferior a 1''80 m y complexión normal. Tiene cierta potencia en carrera, pero no destaca por el físico. Nivel técnico correcto y agresivo en la toma de decisión, aunque le faltan recursos para desbordar y resolver acciones en espacios reducidos. Intenso en la presión y en el duelo.','RP','Seguir'),
  ('7c7cb7fd-ac3d-5836-9694-97de6c071dcb','c2e49b61-aef3-57a8-a899-007eeeb90577','2025-12-23 15:49:42','vs Baleares','Mediocentro #8 de perfil físico medio, con bastante despliegue y recorrido. Gran nivel técnico, manejo de dos piernas, capaz de liderar juego asociativo, con buena llegada a último tercio y golpeo de balón. Intenso y trabajador en fase defensiva, con buena lectura para saltar a presión, e interceptar.','NB','Firmar'),
  ('0e0552d5-f2f7-51e9-9169-e6c0df5fb78a','31c26b78-9265-5cd1-b7bb-a2de31d5e63b','2025-12-23 16:03:10','vs Baleares','Perfil de mediapunta similar a Corralejo, para lo bueno y lo malo. Poco poderío físico, aunque bastante intenso sin balón. Es trabajador en fase defensiva aunque le falta para imponerse en duelos. Con balón tiene excelente nivel técnico, capaz de manejar ambas piernas, asociarse, superar rivales y llegar a zona de finalización.

Es jugador que por perfil en Barça puede ir hacia arriba. Le veo encaje en equipos asociativos.','NB','Seguir'),
  ('b258560d-c085-5c71-8afc-fd75ef756d08','854840c7-6245-5f9b-8133-d9a29a0adef7','2025-12-23 17:27:57','vs Rayo','Delantero centro de físico top pero aún verde. Con poco impacto en juego, irregular técnicamente, con defectos de compresión del juego.','NB','Seguir'),
  ('0cec9623-d78f-5097-92a2-1bfbc41627d2','aa5c075a-9ba7-5ca6-beab-929e3ad3d7ca','2025-12-24 01:25:34','OVIEDO B - Segoviana (21/12/2025)','Central zurdo con una estatura alrededor de 1''90 m y complexión fuerte. Hace un partido prácticamente perfecto, ganando todos los duelos tanto aéreos como en suelo y mostrando un timing y una técnica defensiva sobresaliente. Con balón está correcto y aporta algunas ventajas a través de pases que baten línea.','RP','Seguir'),
  ('fa57b953-1341-5ce9-a63e-d8f508cbaf87','7456d332-3990-5c95-b533-7bd329b31ab8','2025-12-24 01:29:50','OVIEDO B - Segoviana (21/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura cercana a 1''80 m, complexión normal. En el partido no tiene acciones destacables para bien ni para mal pero está correcto, lo cual está muy bien para un 2008 en 2ª RFEF.','RP','Seguir'),
  ('b650bd1a-0a76-57ed-89ad-65e8494b5ebe','eda4b624-4ff5-5fc5-8f84-aa02598cb7cd','2025-12-24 01:35:56','OVIEDO B - Segoviana (21/12/2025)','Jugador diestro adaptable a las cuatro posiciones del ataque: extremo por ambas bandas, mediapunta y delantero. Estatura cercana a 1''80 m, complexión normal. No parece especialmente rápido, pero tiene una carrera potente, capaz de superar rivales. Buen nivel técnico, agresivo en la toma de decisión y con llegada. Le falta mejorar cifras de goles y asistencias.','RP','Seguir'),
  ('52db8c10-10c8-5288-9dd8-1de7582b220e','daaa9208-b19b-5a10-a066-fe56749e5bf9','2025-12-24 01:43:04','Oviedo B - SEGOVIANA (21/12/2025)','Central diestro con una estatura alrededor de 1''85 m y complexión fuerte. En el partido entra en la segunda parte y está correcto. Tiene buen perfil pero no parece top.','RP',NULL),
  ('2b858827-4df6-503a-8fce-b67819cd268a','f496dc51-cb91-592d-8b26-19672d9dc920','2025-12-24 02:39:46','MALLORCA JUV. A - Damm Juv. A (21/12/2025)','Extremo diestro, en el partido actuando a pierna natural. Estatura cercana a 1''90 m y complexión delgada pero fuerte, con extremidades largas. Muy potente en la arrancada y en carrera, donde destaca por su facilidad para esquivar rivales con cambios de ritmo y dirección. Pragmático en la toma de decisión, suele terminar la jugada en centro desde línea de fondo.','RP','Firmar'),
  ('0075c7bc-ba82-5966-9c20-fdca807474a2','16bd0b39-5c0d-5cc9-be3c-dd932c7e6a3a','2025-12-24 02:41:55','MALLORCA JUV. A - Damm Juv. A (21/12/2025)','Delantero centro diestro con una estatura cercana a 1''85 m y complexión fuerte. En el partido apenas tiene intervenciones y solamente lleva un gol esta temporada, pero el perfil está bien.','RP','Seguir'),
  ('2c530554-3f69-5c23-b9d9-21b55bf0f396','7e562b9f-5987-5058-89f7-d6fab312a2de','2025-12-24 02:47:46','MALLORCA JUV. A - Damm Juv. A (21/12/2025)','Lateral derecho con una estatura cercana a 1''80 m y complexión fuerte. Gran velocidad de reacción, nivel de concentración muy elevado y muy agresivo en el duelo. Es rápido y tiene mucho recorrido. Buen nivel técnico y de criterio con balón para ejecutar jugadas que ayuden al equipo a diferentes alturas.','RP','Seguir'),
  ('3237dd3c-d827-5093-855c-d8bfa5c36dda','be2c2ff0-592f-545c-8b83-2cfba08b81a0','2025-12-24 02:50:28','Mallorca Juv. A - DAMM JUV. A (21/12/2025)','Centrocampista diestro de primera altura, también actúa como central en la primera parte. Estatura cercana a 1''80 m y complexión fuerte. Muy buen recuperador y con balón tiene calidad, criterio y personalidad.','RP','Seguir'),
  ('9326e42f-a26e-5b7f-af27-2354aa629aa4','010de466-02ef-59bc-a285-6fef9a903600','2025-12-24 02:53:18','Mallorca Juv. A - DAMM JUV. A (21/12/2025)','Delantero centro diestro con una estatura superior a 1''90 m y complexión delgada pero fuerte. En el partido gana todos los duelos, protege muy bien el balón de espaldas y aporta ventajas constantes a través de descargas en un contexto desfavorable para el equipo. Lleva 7 goles en 14 partidos en DH esta temporada y la temporada pasada marcó 12 en Liga Nacional. Perfil muy interesante.','RP','Seguir'),
  ('3513855c-0994-5fb3-a251-3728d2661db8','8e80a690-488c-5a22-8a4b-42acddc9f8bd','2025-12-25 12:50:33','Alexis Ciria VS Atletico Sanluqueño','Es un jugador, con un excelente perfil tecnico, y unas muy buenas condiciones para manejar el balon, en carrera y a altas  velocidades, sin embargo, pese a tener calidad y potencial para llevar el balón a situaciones mas peligrosas del juego, es un jugador al que le falta clarividencia y parece que evite los duelos para ser vertical, la mayoria de sus acciones con balon terminan yendo hacia detras. A nivel defensivo tiene mucho trabajo y es consistente.','AV','Seguir'),
  ('fe823a25-0e6b-572b-9ab1-64d59356f28c','657e7fdb-9b93-5ee4-bbe5-a2ad666eb656','2025-12-25 13:27:50','Nicolas Guillen vs Atletico Sanluqueño','Jugador de 1ª division, mucha solvencia en espacios reducidos, y capacidad fisica para repetir esfuerzos y estar en todas partes en todas las fases del partido, sin duda un jugador que estara en futbol profesional muchos años.','AV','Firmar'),
  ('1d3aa041-0d6b-5ddc-83e0-80072f4780ae','52708d44-ddc3-508d-933e-741094c91c42','2025-12-25 13:31:25','Ntji Tounkara vs Sevilla Atletico','Jugador con un gran potencial fisico, de elite probablemente en cuanto a fisico, al que no se le aprecian muchas cualidades con el balon, pero necesario para cualquier equipo a nivel defensivo. Muy parecido al perfil de Jannyck Mboula del Numancia.','AV','Seguir'),
  ('71df77f7-6b0e-5b94-bbd9-2ac2bae1a4d7','c93fece2-a8f8-5ae1-a1fd-f351db87e5ac','2025-12-25 13:34:38','Miguel Sierra vs Atletico Sanluqueño','Jugador mas destacado de lejos del partido, jugando de extremo derecho a pierna cambiada, cada vez que ha encarado se ha ido, siendo un jugador vertical y teniendo muy en cuenta que tenia siempre inferioridad numerica, generador de todas las ocasiones de peligro de su equipo, esta a nivel de ser jugador de 1ª division.','AV','Firmar'),
  ('d3cff3b7-052c-5cdc-ad3b-462dbf45a9d7','34ab4c58-b2c0-5fa1-89b5-20cd2cb8af47','2025-12-25 13:37:22','Ibrahim Sow','Jugador muy fuerte y rapido, con capacidad para el remate y que debe crecer en el equipo, creo que este final de temporada puede hacerse muy fuerte en su equipo. Y terminar siendo muy importante, marca un gol decisivo y gana un duelo importantisimo para dar la asistencia, en 3 años puede estar generando traspasos importantes.','AV','Seguir'),
  ('ea8e5d3e-b3f5-5bd6-a356-fd535f37b997','65c1637e-71b9-594f-b082-035491232d43','2025-12-25 13:40:16','Boubacar Bonfing vs Sevilla Atletico','Jugador con un perfil fisico interesante, y un muy buen desplazamiento, ganador de todos los duelos jugados en el partido. Tiene un gran potencial para establecerse en el futbol profesional en los proximos 2 años.','AV','Seguir'),
  ('193f4dd6-df05-5e99-b303-4d8be1ef844d','9c87d677-cc5b-5c4c-be3f-3522ec0994e9','2025-12-25 17:45:06','DIPANDA VS REAL AVILA','Delantero centro, con unas condiciones de elite absolutas, durante el portido fue imposible quitarle el balon, si no era mediante una falta muy clara. 

En velocidad y aceleracion muy dificil de parar, constantemente se fue de su par ( que no parecia flojo en este aspecto). 

Con el balon, muy buenas sensaciones en espacios reduicidos y en conduccion se nota mayor descontrol, pero es normal con la velocidad y lo mejor de todo corregible. 

Perfil muy muy parecido a Etta Eyong en el Cadiz hace dos años, le intuyo una progresion muy parecida a este jugador.','AV','Firmar'),
  ('c8734f7c-80bd-57ac-8258-2ea411c2d0ad','5e0f8326-6c73-5b49-b1f1-0fe8855d0235','2025-12-25 17:50:45','Noe Carrillo vs Real Avila','Mediocentro, con un perfil de pie muy alto, que lleva siempre el balon pegado a los pies y que tiene intenciones muy interesantes con el. En el partido siempre llevo las acciones hacia adelante, y aunque no sea un perfil interesante desde el plano fisico, creo que es un jugador que puede llegar a instalarse en el futbol profesional debido a que su futbol con los pies y velocidad de procesamiento es superior y se nota.','AV','Seguir'),
  ('679c4da2-71f9-5acf-affb-9e597e3b8ee8','8e385692-c861-538f-95fd-5441c0b74edb','2025-12-25 17:56:40','Mario Hermo vs Real Avila','Lateral derecho con unas condicieones propicias para la elite, tiene verticalidad y juega hacia adelante, ademas es un jugador que tiene facilidad para ganar duelos, tiende a desconcentrarse y cometer errores en los retornos pero eso es facilmente corregible.','AV','Seguir'),
  ('c586025e-9289-5b6a-a0f3-88d6ebe775b0','81f93149-11f6-5362-99b1-467098ae820d','2025-12-25 18:01:05','David Dominguez vs Real Avila','Jugador con un aspecto a primera vista feo, mediapunta, con mucha capacidad para ser vertical, y aunque no lo parezca fuerza para progresar y acelerar superando rivales. Realiza un gran partido siendo muy participativo y teniendo mucho que ver en la mayoria de las acciones ofensivas de su equipo.','AV','Seguir'),
  ('880a8282-fb64-5216-b04a-8e1749ac4e68','44fc5b90-2872-5962-b3d4-957c46d35dec','2025-12-25 18:04:45','Quique Teijo','Jugador debil en duelos y con pocos recursos ofensivos .','AV','Descartar'),
  ('e32a01a6-9f40-5b91-af79-54c1c15edeaa','c6aeac05-d89c-51fe-b2a1-b54b54f617b5','2025-12-26 13:33:29','vs Olot','Extremo con buena capacidad para generar ocasiones, tanto para él como para sus compañeros. Por condiciones creo que es jugador para jugar en categoría superior seguro, pero me deja dudas a nivel físico para primer equipo de Valencia.','NB','Seguir'),
  ('0670ec20-9f55-5e52-805e-c9037da4b08b','70b245a8-07a4-5a82-b89f-808bbf019cbf','2025-12-26 13:40:03','vs Olot','Extremo de buenas cualidades físicas, destacando por velocidad y recorrido. Complexión delgada aunque bastante fuerte, sin chispa en primeros metros. No destaca por tener gran repertorio en 1v1, pero sí es capaz de ganar en conducción. Su mayor virtud es la llegada al área, donde finaliza bien.','NB','Seguir'),
  ('34bcee35-0697-5892-b752-a9e86dbedd31','ee95d406-7197-509b-87da-be6b579a870d','2025-12-26 12:45:14','Derbi','Jorge Domínguez: central de potencial para ser uno de los mejores de su posición en la élite. Defensor completo, lo tiene todo (físico, técnica, agresividad, velocidad). Está capacitado para defender a cualquier tipo de delantero. FIRMAR.','NB','Firmar'),
  ('22bc0fb0-8f6a-578b-aa55-712c7a241f6e','ba2198f7-01f0-5710-a57c-559c9bef6827','2025-12-26 12:45:53','Derbi','Adrian Martínez: Juega por izquierda, normalmente lateral derecho. Perfil físico top para posición (es alto, grande, rápido, con recorrido). Tiene llegada a ataque, nivel técnico para asociarse y generar desequilibrio. Aplicado en fase defensiva. FIRMAR.','NB','Firmar'),
  ('10df256e-084e-50f5-9fc0-21d976634c25','54bb0d77-9628-5dae-b122-017a84d5da8d','2025-12-26 12:46:37','Derbi','Tena: #6 de buen físico (aunque lento) que suele jugar fácil, no pierde balones y da continuidad al juego. Le falta mayor capacidad de recorrido en ataque en mi opinión. Sólido en acciones defensivas, aplicado tácticamente. Tiene condiciones para ir hacia arriba.','NB','Seguir'),
  ('d67b3252-8e84-52b8-bf01-0891b5be555e','a8b7da47-5ec1-5310-917c-208b2f9fccde','2025-12-26 12:47:18','Derbi','Rubén Gómez: extremo de estatura baja, muy rápido y explosivo. Irregular en impacto, capaz de crear ocasiones en 1v1 aunque sin tanto acierto en este partido. SEGUIR.','NB','Seguir'),
  ('9bcca541-219b-5fcd-987b-adc479b37e3c','4bf059d6-3d61-50a4-8835-1406de7e162e','2025-12-26 12:47:46','Derbi','Obama: perfil físico ideal para posición. Cerca del 1.90 m, muy fuerte, complexión espectacular, buen punto de velocidad. Es agresivo para buscar ataques al espacio y área en general. Le falta mayor sensibilidad a nivel técnico, en controles y demás. SEGUIR.','NB','Seguir'),
  ('2aed8e28-55f5-5733-ae94-315f34a62a9c','0ced2d83-2178-5391-905e-7ac9f55837be','2025-12-26 12:48:15','Derbi','Carlos Díez: mediapunta que destaca por ser un llegador desde segunda línea, con recursos para finalizar. No tiene tanto impacto en el juego a simple vista pero es un jugador con gran presencia en último tercio. Físico normal, sin destacar. SEGUIR.','NB','Seguir'),
  ('62846318-cc2e-54c3-8f34-5e7d91135a3b','7ce76b8d-10a5-57f7-b111-a085dbf680f6','2025-12-26 12:48:40','Derbi','Ariel: Central por izquierda. Estatura baja para posición parece, más normal verlo de lateral. Rápido, buen corrector, va hacia atrás, es agresivo en duelos, ok con balón. Perfil parecido a Ale Gomes. SEGUIR.','NB','Seguir'),
  ('4248c195-0e97-50f3-a651-58e013a9a1c4','3b76ec9b-0609-5acc-bdd5-416fb7feb213','2025-12-26 12:49:09','Derbi','Adrián: Extremo zurdo por derecha, donde no se siente cómodo por poco uso de pierna mala. Es vertical para buscar acciones de 1v1, desequilibrante, sin tanto éxito en este partido. Le falta más físico y mayor trabajo defensivo además. SEGUIR.','NB','Seguir'),
  ('8275edfd-7a3d-50ac-906e-33b4f45c9067','dbb01d53-b005-5bfa-970a-a20204e42e01','2025-12-26 12:49:44','Derbi','Lezcano: juega de lateral izquierdo, creo que esa va a ser su posición por físico. Es un jugador de buen nivel técnico-táctico, que suele resolver bien circunstancias del juego tanto en ataque como en defensa. Sin embargo no me parece brillante, con menos potencial que Valde y Aguado. SEGUIR.','NB','Seguir'),
  ('2541e2ed-01ca-580a-93f2-e0806d6c84db','c94a40fd-89af-5e85-a982-6c4e7432d455','2025-12-26 12:50:15','Derbi','Bailón: Lateral derecho de perfil físico medio, sin destacar especialmente es rápido y con recorrido. Menos potencial que Fortea pero jugador con posibilidades fuera Del Real Madrid. Tiene recursos en ataque y en defensa es bastante serio. SEGUIR.','NB','Seguir'),
  ('e9962b26-2ed8-5492-bd09-e467e75a23be','27cad8ba-b61e-5866-97f7-b046c0bea039','2025-12-26 12:50:40','Derbi','Ferran: me recuerda a Oreiro tanto en aptitudes como en potencial. Centrales de nivel parecido, me cuesta verlo crecer en clave Real Madrid aunque sí tendrá espacio en otros clubes. No me parece central de primer nivel.','NB',NULL),
  ('71942ead-8929-59f5-9d17-f08b9a48936c','4c0a0c63-8caa-53c0-91bb-0d9660c23d0b','2025-12-26 15:08:33','vs Manresa','Mediocentro perfil #8 de físico normal (estatura media, delgado, sin destacar por potencia, ágil) de buen nivel técnico para manejar balón, asociarse, llevar peso del juego en salida. Sin tantas acciones de llegada a último tercio ni despliegue en ataque. No destaca en fase defensiva, donde le falta mayor poderío para imponerse.','NB',NULL),
  ('5c4e94a1-929b-51ad-8a52-70bef5880b57','b7d204d7-568e-5a4f-bd43-cadb3b873e17','2025-12-26 15:16:27','vs Huesca','Buen perfil físico pero poco destacable en juego, lo veo lento y poco ágil, con problemas técnicos','NB',NULL),
  ('2df00ffc-cc1a-5d9a-867c-123668373a2a','0829f6af-8a5a-5ff5-8bca-3ed32d61e08c','2025-12-27 20:13:06','vs Águilas','Extremo de físico promedio (estatura media baja, delgado, con poco poderío, buen punto de velocidad sin ser excesivamente explosivo. Físicamente le falta bastante, le cuesta imponerse. Me recuerda a Vini. Vertical para buscar 1v1 sin ser ganador, es irregular a nivel técnico. No lo veo preparado para jugar en cantera de nuestra zona.','NB',NULL),
  ('7133bed6-db56-58ed-857a-b89554e7289a','e1263955-d5b8-5908-81e1-a18069fd4e96','2025-12-29 13:56:02',NULL,'Centrocampista perfil #8 de condiciones físicas normales (estatura media, delgado, no destaca por potencia ni por nada especialmente en este sentido). Jugador de buen nivel técnico, con recursos en juego asociativo, habilidad para superar presión y jugar hacia adelante. Es intenso en fase defensiva, activo en presión, aunque le falta más poderío para imponerse en duelos.

Creo que podría tener más minutos en Segunda, aunque físicamente le puede costar.','NB',NULL),
  ('37f0c587-f12c-51c0-bac2-643a0f30b584','9c87d677-cc5b-5c4c-be3f-3522ec0994e9','2025-12-29 17:25:16','vs Numancia','Delantero centro de buenas condiciones físicas (estatura de 1.80 m aprox, muy fuerte y rápido, explosivo, ágil). 

Cuenta con buen nivel técnico para realizar controles, giros, ganar metros en conducción y progresar. Activo fuera del área, atacando espacios, retrocediendo para entrar en juego. Capaz de generar sus propias ocasiones. Agresivo para sacar tiros. Potencial interesante, lo veo más de delantero que de extremo.','NB','Firmar'),
  ('7331a9dd-3be2-5d4c-960f-eca6a081dd39','d73a8091-6159-5ce6-8a97-836dcd5a1927','2025-12-30 11:22:19',NULL,'Jugador activo en fase defensiva, con buenos datos de recuperación, agresivo para afrontar duelos y proactivo para salir a interceptar. Va bien en juego aéreo pese a su físico, que no destaca.','NB',NULL),
  ('c191c257-258c-5257-ab4a-8143e0dbd7e4','8990848a-32d3-5b66-ba89-f75dad3b517b','2025-12-30 12:26:01','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Lateral derecho con una estatura alrededor de 1''75 m y complexión normal. Jugador muy dinámico y con una técnica notable para escapar de las presiones. Tiene mucha personalidad con balón y siempre encuentra la forma de darle continuidad a la jugada y hacer progresar al equipo desde la banda. Mucho recorrido, buena velocidad de reacción y gestual.','RP','Firmar'),
  ('ac090ae4-8bb6-5fc5-a80c-ca16781f0315','4f9c2b27-9205-588f-9bc6-c9a90ab30478','2025-12-30 12:32:44','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Lateral izquierdo con una estatura algo inferior a 1''85 m y complexión delgada pero fuerte. Gran capacidad técnica para escapar de presiones y hacer progresar al equipo a través del pase, incluso en largo con cambios de orientación a extremo contrario. Bien defensivamente, fuerte en el duelo y con una buena capacidad física para el 1vs1.','RP','Seguir'),
  ('24060087-9cdf-5088-ab1c-81bdf7e0a359','b169714e-1bf5-5828-8a3a-c1984e17eb4d','2025-12-30 12:35:44','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Central zurdo con una estatura cercana a 1''90 my y complexión fuerte. Muy ganador por arriba y con una buena lectura y timing para realizar la acción defensiva. Bien con balón.','RP','Seguir'),
  ('7620ea69-49b2-5155-88b4-643fa1bf2fb5','68f3033a-f761-5029-86ae-dc07cfd0c485','2025-12-30 12:38:37','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Extremo diestro con una estatura algo inferior a 1''80 m y complexión normal. No parece destacar por potencia o velocidad, pero tiene una gran capacidad de desborde a través de acciones técnicas.','RP','Seguir'),
  ('6b5b0bc0-202e-53f4-b548-eddd0484748a','e9602a91-2142-5d52-b3c5-f8cfc86e447e','2025-12-30 12:40:54','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Delantero centro diestro con una estatura algo inferior a 1''90 m y complexión delgada pero fuerte. Duro en el choque y en el salto, tiene poco peso en los partidos pero es capaz de ganar duelos y aportar ventajas al equipo desde ahí.','RP','Seguir'),
  ('b2f1ab3b-a671-54a0-9070-f78064ab45a1','4f527eea-f439-50b7-b063-c73481eabfa8','2025-12-30 12:44:15','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Extremo diestro, estilo mediapunta en banda, de estatura media y complexión normal, pero con bastante potencia para chocar. Es agresivo con y sin balón y tiene un manejo de pelota excelente. Poco peso en el partido.','RP','Seguir'),
  ('6c5ccd95-9cb2-53d0-87c6-72ed1b34de09','f6a01600-ab90-590b-893b-202f68f66dea','2025-12-30 12:46:38','ESPANYOL JUV. A - Cornellà Juv. A (21/12/2025)','Extremo zurdo con un perfil físico medio. No me ha llamado la atención por calidad técnica ni velocidad.','RP',NULL),
  ('e1e855fa-01f2-510e-a227-70725c0fae95','9704cede-5d46-5073-9e22-c267fe350348','2025-12-30 12:48:01','Espanyol Juv. A - CORNELLÀ JUV. A (21/12/2025)','Lateral derecho de perfil físico medio. Es 2008 y está jugando mucho, pero no me ha llamado la atención por nada.','RP',NULL),
  ('832d100a-c685-5788-b6fb-97454777b55f','626057b1-39f9-57ef-966c-4b10ea5c7006','2025-12-30 12:49:25','Espanyol Juv. A - CORNELLÀ JUV. A (21/12/2025)','Central diestro con una estatura algo superior a 1''80 m y complexión fuerte. Buena lectura y calidad defensiva, muy duro en duelos y bastante ganador en acciones en suelo y aéreas. Con balón tiene calidad para aportar ventajas en salida de balón.','RP','Seguir'),
  ('16db2cdb-dc49-5e4b-8228-3f9fd61317d2','048e23bc-3b48-5e34-ba87-782765eb9592','2025-12-30 12:51:08','Espanyol Juv. A - CORNELLÀ JUV. A (21/12/2025)','Atacante diestro, en el partido actuando primero como extremo derecho y después como delantero centro. Estatura alrededor de 1''75 m y complexión normal, pero es muy fuerte en los duelos. Jugador agresivo capaz de ganar balones a los centrales y generar peligro en el último tercio.','RP','Seguir'),
  ('90fa3c3a-13d6-549d-914a-56b2e4a2579e','be2c2ff0-592f-545c-8b83-2cfba08b81a0','2025-12-30 14:28:42','DAMM JUV. A - San Francisco Juv. A (13/12/2025)','Centrocampista diestro de primera altura, de corte y distribución. Estatura alrededor de 1''80 m y complexión delgada pero fuerte. Muy buen manejo de balón y criterio para distribuir desde atrás hacia delante.','RP','Seguir'),
  ('c67b924e-6b07-5f9b-837c-e1e19f953bc0','111a84a3-31d2-5b37-8fce-f8d0b4862b76','2025-12-30 14:32:16','DAMM JUV. A - San Francisco Juv. A (13/12/2025)','Extremo diestro con una estatura algo superior a 1''80 m y físico fuerte. Tiene una aceleración extraordinaria y bastante calidad técnica para desbordar. Lleva 9 goles en 13 partidos esta temporada en DH.','RP','Seguir'),
  ('df343134-98d5-575f-bb5b-90cd23b76c15','f19c5e79-14d8-5b90-855b-80e304f4bd01','2025-12-30 14:35:19','DAMM JUV. A - San Francisco Juv. A (13/12/2025)','Extremo diestro de estatura algo inferior a 1''80 m y aspecto fuerte. No parece muy rápido en carrera, pero tiene una buena técnica y llegada.','RP','Seguir'),
  ('5c3b82a0-65da-58bd-83bf-ad5c4c088b5d','aa6b6a58-ebb5-5547-9bc5-27f2dd16c8cc','2025-12-30 14:39:07','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Lateral derecho con una estatura algo superior a 1''75 m y complexión normal. Muy agresivo defensivamente, difícil de superar en el 1vs1. En ataque es correcto y se suelta de vez en cuando en campo rival.','RP','Seguir'),
  ('164efe62-5a4c-5aaf-ab0f-fe80004fece6','aa6b6a58-ebb5-5547-9bc5-27f2dd16c8cc','2025-12-30 14:39:07','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Lateral derecho con una estatura algo superior a 1''75 m y complexión normal. Muy agresivo defensivamente y difícil de superar en el 1vs1. En ataque es correcto y se suelta de vez en cuando en campo rival.','RP','Seguir'),
  ('643eb44f-11ab-56f9-819d-17f12dd33cca','a79553bf-2a37-52a0-b7f9-1e1423bd5637','2025-12-30 14:44:28','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Lateral izquierdo de perfil físico medio-bajo. Bastante flojo.','RP','Descartar'),
  ('9bee8d11-68f9-5449-93e2-0935225e410c','0f4544e8-0e74-5196-a0c8-f1b950304d0a','2025-12-30 14:48:58','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Central diestro con una estatura alrededor de 1''85 m y complexión fuerte. Bastante ganador de duelos, aunque algo pesado de movimientos. Con balón es correcto.','RP','Seguir'),
  ('e7c5d9b1-e8af-5829-97b8-741262cd67e6','5e741405-1458-57b2-bb29-e4650e5b32e8','2025-12-30 14:51:15','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Extremo diestro con un perfil físico medio bajo. Nada destacable.','RP',NULL),
  ('96cd35db-977f-5a00-8ab0-487678b4ea59','e904407d-ce8b-5c70-bf35-e7947b84a97f','2025-12-30 14:52:27','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Centrocampista diestro de primera/segunda altura, en el partido actuando en doble pivote. Estatura algo inferior a 1''80 m, complexión normal. Nada destacable.','RP',NULL),
  ('89457d10-182e-5d89-95f4-7d685b7fb12b','bbf1f6cb-0241-5531-8faf-ea4ed0106de5','2025-12-30 14:54:23','Damm Juv. A - SAN FRANCISCO JUV. A (13/12/2025)','Delantero centro diestro con una estatura algo inferior a 1''85 m y complexión fuerte. Potente en carrera y buenos movimientos cerca del área. Lleva 8 goles en 14 partidos en DH esta temporada.','RP','Seguir'),
